(function() {
var mat_ch_1_Verses = [
  {num:1,words:[["O le tusi i le gafa o Iesu Keriso,", "The book of the generation of Jesus Christ,"], ["o le atalii o Tavita,", "the son of David,"], ["o le atalii ia o Aperaamo.", "the son of Abraham."]]},
  {num:2,words:[["Na fanaua e Aperaamo o Isaako;", "Abraham begat Isaac;"], ["na fanaua foi e Isaako o Iakopo;", "and Isaac begat Jacob;"], ["na fanaua e Iakopo o Iuta ma ona uso;", "and Jacob begat Judas and his brethren;"]]},
  {num:3,words:[["na fanaua e Iuta o Faresa ma Sera mai ia Tamara;", "And Judas begat Phares and Zara of Thamar;"], ["na fanaua e Faresa o Esaroma;", "and Phares begat Esrom;"], ["na fanaua e Esaroma o Arama;", "and Esrom begat Aram;"]]},
  {num:4,words:[["na fanaua e Arama o Aminatapu;", "And Aram begat Aminadab;"], ["na fanaua e Aminatapu o Naasona;", "and Aminadab begat Naasson;"], ["na fanaua e Naasona o Salemona;", "and Naasson begat Salmon;"]]},
  {num:5,words:[["na fanaua e Salemona o Poasa mai ia Raava;", "And Salmon begat Booz of Rachab;"], ["na fanaua e Poasa o Opeta mai ia Ruta;", "and Booz begat Obed of Ruth;"], ["na fanaua e Opeta o Iese;", "and Obed begat Jesse;"]]},
  {num:6,words:[["na fanaua e Iese o le tupu o Tavita;", "And Jesse begat David the king;"], ["na fanaua e le tupu o Tavita o Solomona mai le avā a Uria;", "and David the king begat Solomon of her that had been the wife of Urias;"]]},
  {num:7,words:[["na fanaua e Solomona o Reopoamo;", "And Solomon begat Roboam; and Roboam begat Abia;"], ["na fanaua e Reopoamo o Avia;", "and Abia begat Asa;"]]},
  {num:8,words:[["na fanaua e Avia o Asa;", "And Asa begat Josaphat;"], ["na fanaua e Asa o Iosefatu; na fanaua e Iosefatu o Iorama;", "and Josaphat begat Joram;"], ["na fanaua e Iorama o Usia;", "and Joram begat Ozias;"]]},
  {num:9,words:[["na fanaua e Usia o Iotama;", "And Ozias begat Joatham;"], ["na fanaua e Iotama o Aasa;", "and Joatham begat Achaz;"], ["na fanaua e Aasa o Esekia;", "and Achaz begat Ezekias;"]]},
  {num:10,words:[["na fanaua e Esekia o Manase;", "And Ezekias begat Manasses;"], ["na fanaua e Manase o Amone;", "and Manasses begat Amon;"], ["na fanaua e Amone o Iosia;", "and Amon begat Josias;"]]},
  {num:11,words:[["na fanaua e iosia o Iekonia ma ona uso,", "And Josias begat Jechonias and his brethren,"], ["ina a tāfea i Papelonia.", "about the time they were carried away to Babylon:"]]},
  {num:12,words:[["Ua oo le tafeaga i Papelonia,", "And after they were brought to Babylon,"], ["ona fanaua ai lea e Iekonia o Salatielu;", "Jechonias begat Salathiel;"], ["na fanaua e Salatielu o Serupapelu;", "and Salathiel begat Zorobabel;"]]},
  {num:13,words:[["na fanaua e Serupapelu o Apiuta;", "And Zorobabel begat Abiud;"], ["na fanaua e Apiuta o Eliakimo;", "and Abiud begat Eliakim;"], ["na fanaua e Eliakimo o Asora;", "and Eliakim begat Azor;"]]},
  {num:14,words:[["na fanaua e Asora o Satoka;", "And Azor begat Sadoc;"], ["na fanaua e Satoka o Akeimo;", "and Sadoc begat Achim;"], ["na fanaua e Akeimo o Eliuta;", "and Achim begat Eliud;"]]},
  {num:15,words:[["na fanaua e Eliuta o Eleasaro;", "And Eliud begat Eleazar;"], ["na fanaua e Eleasaro o Matano;", "and Eleazar begat Matthan;"], ["na fanaua e Matano o Iakopo;", "and Matthan begat Jacob;"]]},
  {num:16,words:[["na fanaua e Iakopo o Iosefa le tane a Maria,", "And Jacob begat Joseph the husband of Mary,"], ["na fanaua ai Iesu ,", "of whom was born Jesus,"], ["o le ua igoa ia Keriso.", "who is called Christ."]]},
  {num:17,words:[["O lenei, o tupulaga uma e afua mai ia Aperaamo e oo ia Tavita,", "So all the generations from Abraham to David are fourteen generations;"], ["e sefulu ma le fa ia tupulaga; e afua foi ia Tavita e oo i le tafeaga i Papelonia, e sefulu ma le fa ia tupulaga;", "and from David until the carrying away into Babylon are fourteen generations;"], ["e afua foi i le tafeaga i Papelonia e oo i le Keriso, e sefulu ma le fa ia tupulaga.", "and from the carrying away into Babylon unto Christ are fourteen generations."]]},
  {num:18,words:[["Sa faapea ona fanau mai o Iesu Keriso. Sa fāufautane lona tinā o Maria ia Iosefa,", "Now the birth of Jesus Christ was on this wise:"], ["ua iloa ua to o ia i le Agaga Paia,", "When as his mother Mary was espoused to Joseph, before they came together,"], ["a o lei faatasi i laua.", "she was found with child of the Holy Ghost."]]},
  {num:19,words:[["O Iosefa foi lana tane o le tagata amiotonu ia,", "Then Joseph her husband,"], ["e lei loto foi o ia ina faamasiasi ia te ia i luma o tagata,", "being a just man, and not willing to make her a publick example,"], ["ua ia manatu e faatea lemu ia te ia.", "was minded to put her away privily."]]},
  {num:20,words:[["A o manatunatu o ia i na mea,", "But while he thought on these things,"], ["faauta,", "behold,"], ["ua faaali mai ia te ia le agelu a le Alii i le miti,", "the angel of the Lord appeared unto him in a dream,"], ["ua faapea mai,", "saying,"], ["Iosefa e,", "Joseph,"], ["le atalii o Tavita,", "thou son of David,"], ["aua e te fefe ina au mai ia te oe o Maria lau avā;", "fear not to take unto thee Mary thy wife:"], ["auā o lana to mai le Agaga Paia lea.", "for that which is conceived in her is of the Holy Ghost."]]},
  {num:21,words:[["E fanau mai e ia le tama tane,", "And she shall bring forth a son,"], ["e te faaigoa foi ia te ia o Iesu;", "and thou shalt call his name JESUS:"], ["auā e faaola e ia lona nuu ai a latou agasala.", "for he shall save his people from their sins."]]},
  {num:22,words:[["Ua oo nei mea uma ina ia taunuu ai le afioga a le Alii i le perofeta,", "Now all this was done, that it might be fulfilled which was spoken of the Lord by the prophet,"], ["ua faapea mai,", "saying,"]]},
  {num:23,words:[["Faauta,", "Behold,"], ["e to le taupou,", "a virgin shall be with child,"], ["ma fanau mai le tama tane,", "and shall bring forth a son,"], ["latou te faaigoa foi ia te ia o Emanuelu;", "and they shall call his name Emmanuel,"], ["o lona uiga pe a faamatalaina,", "which being interpreted is,"], ["Ua ia te i tatou le Atua.", "God with us."]]},
  {num:24,words:[["Ua ala Iosefa, sa moe,", "Then Joseph being raised from sleep did as the angel of the Lord had bidden him,"], ["ona faia lea e ia e pei ona fai mai ai ia te ia o le agelu a le Alii; ua na au mai lana avā.", "and took unto him his wife:"]]},
  {num:25,words:[["A e la te lei feiloai ua oo ina fanau mai e ia o lana tama tane ulumatua;", "And knew her not till she had brought forth her firstborn son:"], ["ua ia faaigoa foi ia te ia o Iesu .", "and he called his name JESUS."]]},
];
renderVerseSet(mat_ch_1_Verses, 'mat-ch1-verses');

var mat_ch_2_Verses = [
  {num:1,words:[["Ua fanau Iesu i Peteleema i Iutaia i ona po o Herota le tupu,", "Now when Jesus was born in Bethlehem of Judaea in the days of Herod the king,"], ["faauta, ua oo mai ai makoi mai sasae i Ierusalema,", "behold,"], ["ua faapea mai,", "there came wise men from the east to Jerusalem,"]]},
  {num:2,words:[["Po o fea o i ai le ua fanau mai o le tupu o tagata Iutaia? Auā ua matou vaaia lona fetu i sasae,", "Saying, Where is he that is born King of the Jews? for we have seen his star in the east,"], ["ua matou o mai ai e ifo atu ia te ia.", "and are come to worship him."]]},
  {num:3,words:[["Ua faalogo i ai Herota le tupu,", "When Herod the king had heard these things, he was troubled,"], ["ona atuatuvale ai lea o ia atoa foi ma Ierusalema uma.", "and all Jerusalem with him."]]},
  {num:4,words:[["Ona ia faapotopotoina ai lea o le au faitaulaga sili uma ma le au tusiupu o le nuu, ua fesili atu ia te i latou,", "And when he had gathered all the chief priests and scribes of the people together,"], ["po o fea e fanau ai le Keriso.", "he demanded of them where Christ should be born."]]},
  {num:5,words:[["Ona latou fai mai ai lea ia te ia,", "And they said unto him,"], ["O Peteleema i Iutaia;", "In Bethlehem of Judaea:"], ["auā ua faapea ona tusia e le perofeta,", "for thus it is written by the prophet,"]]},
  {num:6,words:[["O oe foi Peteleema i le nuu o Iuta,", "And thou Bethlehem,"], ["e te le topito ona faatauvaa i alii o Iuta;", "in the land of Juda,"], ["auā e tupu mai ia te oe le faipule,", "art not the least among the princes of Juda: for out of thee shall come a Governor,"], ["o le na te pule i lo'u nuu o Isaraelu.", "that shall rule my people Israel."]]},
  {num:7,words:[["Ua aami lemu ane e Herota o makoi,", "Then Herod, when he had privily called the wise men,"], ["ona matuā suesue ai lea ia te i latou i ona po na iloa ai le fetu.", "enquired of them diligently what time the star appeared."]]},
  {num:8,words:[["Ona ia aauina atu ai lea o i latou i Peteleema,", "And he sent them to Bethlehem,"], ["ua faapea atu,", "and said,"], ["O atu ia outou, ina matuā saili ia i le tama itiiti;", "Go and search diligently for the young child;"], ["pe a outou iloa,", "and when ye have found him,"], ["ia outou faailoa mai ia te au,", "bring me word again,"], ["o a'u foi ou te alu atu ai e ifo atu ia te ia.", "that I may come and worship him also."]]},
  {num:9,words:[["Ua latou faalogo atu i le tupu,", "When they had heard the king,"], ["ona latou o ai lea,", "they departed; and,"], ["faauta foi,", "lo,"], ["o le fetu na iloa e i latou i sasae,", "the star,"], ["ua muamua atu ia te i latou,", "which they saw in the east, went before them,"], ["ua oo ina tu mai i luga o le mea ua i ai le tama itiiti.", "till it came and stood over where the young child was."]]},
  {num:10,words:[["Ua latou iloa le fetu,", "When they saw the star,"], ["ona matuā tele ai lea o lo latou fiafia.", "they rejoiced with exceeding great joy."]]},
  {num:11,words:[["Ua latou ulufale atu i le fale,", "And when they were come into the house,"], ["ua latou iloa ai le tama itiiti ma Maria lona tinā,", "they saw the young child with Mary his mother,"], ["ona latou faapauu ai lea,", "and fell down,"], ["ma ifo atu ia te ia;", "and worshipped him:"], ["ua talai foi o latou oloa,", "and when they had opened their treasures,"], ["ona latou avatu ai lea ia te ia o mea alofa,", "they presented unto him gifts;"], ["o le auro,", "gold,"], ["ma le pulu lipano,", "and frankincense,"], ["ma le pulu muro.", "and myrrh."]]},
  {num:12,words:[["Ua faailoa ia te i latou i le miti, aua ne'i foi atu ia Herota,", "And being warned of God in a dream that they should not return to Herod,"], ["ona latou o atu ai lea i lo latou nuu i le tasi ala.", "they departed into their own country another way."]]},
  {num:13,words:[["Ua o i latou,", "And when they were departed,"], ["faauta,", "behold,"], ["o le agelu a le Alii ua faaali mai ia Iosefa i le miti,", "the angel of the Lord appeareth to Joseph in a dream,"], ["ua faapea mai,", "saying,"], ["Tulai ia,", "Arise,"], ["ina ave le tama itiiti ma lona tinā,", "and take the young child and his mother,"], ["ma sosola i Aikupito,", "and flee into Egypt,"], ["ma nonofo ai seia ou fai atu ia te oe;", "and be thou there until I bring thee word:"], ["auā o le a saili Herota i le tama itiiti ina ia fasioti ia te ia.", "for Herod will seek the young child to destroy him."]]},
  {num:14,words:[["Ua tulai ia,", "When he arose,"], ["ua ave le tama itiiti ma lona tinā i le po,", "he took the young child and his mother by night,"], ["ona o atu lea i Aikupito.", "and departed into Egypt:"]]},
  {num:15,words:[["Sa i ai foi o ia ua oo ina oti o Herota;", "And was there until the death of Herod:"], ["ina ia taunuu ai le afioga a le Alii i le perofeta,", "that it might be fulfilled which was spoken of the Lord by the prophet,"], ["ua faapea mai,", "saying,"], ["Na ou valaauina lo'u atalii ai Aikupito.", "Out of Egypt have I called my son."]]},
  {num:16,words:[["Ua iloa e Herota ua olegia o ia e makoi,", "Then Herod, when he saw that he was mocked of the wise men,"], ["ona tele ai lea o lona ita,", "was exceeding wroth,"], ["ua aauina atu e ia nisi e fasioti i tama tane uma i Peteleema e oo i ona tuaoi uma,", "and sent forth, and slew all the children that were in Bethlehem,"], ["e afua i e ua lua o latou tausaga atoa ma e ua pito ane i ai,", "and in all the coasts thereof,"], ["e faatatau i ona po na na matuā sueina atu ai i makoi.", "from two years old and under, according to the time which he had diligently enquired of the wise men."]]},
  {num:17,words:[["Ona taunuu lea o le upu a le perofeta o Ieremia,", "Then was fulfilled that which was spoken by Jeremy the prophet,"], ["ua faapea mai,", "saying,"]]},
  {num:18,words:[["Ua lagona le leo i Rama,", "In Rama was there a voice heard,"], ["o le auega,", "lamentation,"], ["o le fetagisi,", "and weeping,"], ["ma le tagitu'i tele;", "and great mourning,"], ["ua tagiaue Rasela i lana fanau,", "Rachel weeping for her children,"], ["e le mafai foi ona faanaina o ia,", "and would not be comforted,"], ["ona o i latou ua leai.", "because they are not."]]},
  {num:19,words:[["Ua oti Herota,", "But when Herod was dead,"], ["faauta, o le agelu a le Alii ua faaali mai ia Iosefa i le miti i Aikupito,", "behold,"], ["ua faapea mai,", "an angel of the Lord appeareth in a dream to Joseph in Egypt,"]]},
  {num:20,words:[["Tulai ia,", "Saying,"], ["ina ave le tama itiiti ma lona tinā,", "Arise,"], ["ina o atu ia i le nuu o Isaraelu;", "and take the young child and his mother, and go into the land of Israel:"], ["auā ua oti e na sailia le tama itiiti e fasioti.", "for they are dead which sought the young child's life."]]},
  {num:21,words:[["Ona tulai ai lea o ia,", "And he arose,"], ["ua ave le tama itiiti ma lona tinā,", "and took the young child and his mother,"], ["ona o ai lea i le nuu o Isaraelu.", "and came into the land of Israel."]]},
  {num:22,words:[["A ua faalogo o ia ua fai ma tupu i Iutaia o Arekilao o le sui o Herota lona tamā,", "But when he heard that Archelaus did reign in Judaea in the room of his father Herod, he was afraid to go thither:"], ["ona fefe ai lea i alu i ai. A e peitai ua faailoa ia te ia i le miti,", "notwithstanding,"], ["ona alu ai lea o ia i le nuu o Kalilaia.", "being warned of God in a dream, he turned aside into the parts of Galilee:"]]},
  {num:23,words:[["Ua oo foi i le tasi aai e igoa ia Nasareta,", "And he came and dwelt in a city called Nazareth:"], ["ua nofo ai; ina ia taunuu ai o le upu a le au perofeta,", "that it might be fulfilled which was spoken by the prophets,"], ["E igoa o ia o le Nasareta.", "He shall be called a Nazarene."]]},
];
renderVerseSet(mat_ch_2_Verses, 'mat-ch2-verses');

var mat_ch_3_Verses = [
  {num:1,words:[["O ona po ia na sau ai Ioane le papatiso, ua tala'i atu i le vao o Iutaia,", "In those days came John the Baptist,"], ["ua faapea atu,", "preaching in the wilderness of Judaea,"]]},
  {num:2,words:[["Ina salamo ia outou;", "And saying, Repent ye:"], ["auā ua latalata mai le malo o le lagi.", "for the kingdom of heaven is at hand."]]},
  {num:3,words:[["Auā o ia lava lenei na fai mai ai le perofeta o Isaia,", "For this is he that was spoken of by the prophet Esaias,"], ["ua faapea mai,", "saying,"], ["O le leo o le ua alaga i le vao,", "The voice of one crying in the wilderness,"], ["Ina teuteu ia outou le ala o le Alii,", "Prepare ye the way of the Lord,"], ["ia faalaulelei ona ala.", "make his paths straight."]]},
  {num:4,words:[["A o Ioane ia, sa ofu i le fulufulu kamela,", "And the same John had his raiment of camel's hair,"], ["ma le fusi pa'u i lona sulugātiti;", "and a leathern girdle about his loins;"], ["a o ana mea e 'ai, o sē akerise ma le meli vao ia.", "and his meat was locusts and wild honey."]]},
  {num:5,words:[["Ona o atu ai lea ia te ia o Ierusalema,", "Then went out to him Jerusalem,"], ["ma Iutaia uma,", "and all Judaea,"], ["atoa ma le itu uma o Ioritana;", "and all the region round about Jordan,"]]},
  {num:6,words:[["ua papatisoina foi i latou i Ioritana e ia,", "And were baptized of him in Jordan,"], ["ua faaali atu e i latou a latou agasala.", "confessing their sins."]]},
  {num:7,words:[["Ua na iloa atu le au faresaio ma le au satukaio e toatele ua o mai i lana papatisoga,", "But when he saw many of the Pharisees and Sadducees come to his baptism,"], ["ona ia faapea atu ai lea ia te i latou,", "he said unto them,"], ["Fanau a gata feai e,", "O generation of vipers,"], ["o ai ea ua na faaali atu ia te outou ia sosola ese i le toasa atali?", "who hath warned you to flee from the wrath to come?"]]},
  {num:8,words:[["Ia outou fua mai ni fua e tatau ma le salamo;", "Bring forth therefore fruits meet for repentance:"]]},
  {num:9,words:[["aua foi ne'i outou manatu e faapea ifo i o outou loto,", "And think not to say within yourselves,"], ["O Aperaamo,", "We have Abraham to our father:"], ["o ia o lo matou tamā; auā ou te fai atu ia te outou,", "for I say unto you,"], ["e mafaia lava e le Atua ona faatupuina mai i nei maa ni fanau mā Aperaamo.", "that God is able of these stones to raise up children unto Abraham."]]},
  {num:10,words:[["O loo tuu nei foi le mătau i tafu'e o laau;", "And now also the axe is laid unto the root of the trees:"], ["o laau uma foi e le fua mai i fua lelei,", "therefore every tree which bringeth not forth good fruit is hewn down,"], ["e taia ma lafoina i le afi.", "and cast into the fire."]]},
  {num:11,words:[["O a'u nei,", "I indeed baptize you with water unto repentance:"], ["ou te papatiso atu ia te outou i le vai ina ia salamo;", "but he that cometh after me is mightier than I,"], ["a e peitai o lē mulimuli mai e silisili o ia ia te au,", "whose shoes I am not worthy to bear:"], ["e le aoga a'u ona tauave i ona see vae;", "he shall baptize you with the Holy Ghost,"], ["o ia lea na te papatisoina atu ia te outou i le Agaga Paia ma le afi.", "and with fire:"]]},
  {num:12,words:[["O i lona aao lana asu,", "Whose fan is in his hand,"], ["na te faamamāina ai lana faaputugāsaito;", "and he will throughly purge his floor,"], ["na te faapotopotoina foi ana saito i le fale saito,", "and gather his wheat into the garner;"], ["a e susunuina le otaota o saito i le afi e le matineia.", "but he will burn up the chaff with unquenchable fire."]]},
  {num:13,words:[["Ona maliu atu ai lea o Iesu mai Kalilaia i Ioritana ia Ioane,", "Then cometh Jesus from Galilee to Jordan unto John,"], ["ia papatisoina ai e ia.", "to be baptized of him."]]},
  {num:14,words:[["A ua vavao e Ioane ia te ia,", "But John forbad him,"], ["ua faapea mai,", "saying,"], ["E ao ona e papatisoina mai o a'u,", "I have need to be baptized of thee,"], ["a ē maliu mai ea oe ia te au?", "and comest thou to me?"]]},
  {num:15,words:[["A ua tali atu Iesu,", "And Jesus answering said unto him,"], ["ua faapea atu ia te ia, Tuu mai nei pea ia;", "Suffer it to be so now:"], ["auā e faapea ona tatau ia te i tatou ona faataunuuina o mea tonu uma.", "for thus it becometh us to fulfil all righteousness."], ["Ona tuu mai lea ia te ia.", "Then he suffered him."]]},
  {num:16,words:[["Ua papatisoina Iesu,", "And Jesus,"], ["ona maliu ae loa lea o ia nai le vai,", "when he was baptized, went up straightway out of the water:"], ["faauta foi,", "and,"], ["ua faaavanoaina le lagi ia te ia,", "lo,"], ["ua ia iloa atu foi le Agaga o le Atua ua afio ifo e peiseai se lupe,", "the heavens were opened unto him, and he saw the Spirit of God descending like a dove,"], ["ua oo i ona luga.", "and lighting upon him:"]]},
  {num:17,words:[["Faauta foi,", "And lo a voice from heaven,"], ["o le siufofoga mai le lagi,", "saying,"], ["ua faapea mai, O lo'u atalii pele lenā,", "This is my beloved Son,"], ["ua ou fiafia lava ia te ia.", "in whom I am well pleased."]]},
];
renderVerseSet(mat_ch_3_Verses, 'mat-ch3-verses');

var mat_ch_4_Verses = [
  {num:1,words:[["Ona aveina ae lea o Iesu i le vao e le Agaga, ina ia faaosoosoina e le tiapolo.", "Then was Jesus led up of the Spirit into the wilderness to be tempted of the devil."]]},
  {num:2,words:[["Ua faalaina ia i po e fagafulu ma ao e fagafulu,", "And when he had fasted forty days and forty nights,"], ["mulimuli ane ona fia taumafa ai lea o ia.", "he was afterward an hungred."]]},
  {num:3,words:[["Ona alu ane lea ia te ia o lē faaosooso,", "And when the tempter came to him,"], ["ua faapea mai,", "he said,"], ["Afai o oe le Alo o le Atua,", "If thou be the Son of God,"], ["ina fetalai atu ia ia liu areto nei maa.", "command that these stones be made bread."]]},
  {num:4,words:[["Ona tali atu ai lea o ia,", "But he answered and said,"], ["ua faapea atu,", "It is written,"], ["Ua tusia, E le na o mea e 'ai e ola ai le tagata,", "Man shall not live by bread alone,"], ["a o afioga uma e tūlei mai i le fofoga o le Atua.", "but by every word that proceedeth out of the mouth of God."]]},
  {num:5,words:[["Ona ave ai lea o ia e le tiapolo i le aai paia,", "Then the devil taketh him up into the holy city,"], ["ua ia faatuina foi ia te ia i le tumutumu o le malumalu,", "and setteth him on a pinnacle of the temple,"]]},
  {num:6,words:[["ona fai mai lea o ia ia te ia,", "And saith unto him,"], ["Afai o oe le Alo o le Atua,", "If thou be the Son of God,"], ["oso ia oe i lalō;", "cast thyself down:"], ["auā ua tusia,", "for it is written,"], ["E poloai o ia i ana agelu ia te oe,", "He shall give his angels charge concerning thee:"], ["latou te ave ia te oe i o latou lima,", "and in their hands they shall bear thee up,"], ["ne'i tū'ia lou vae i se maa.", "lest at any time thou dash thy foot against a stone."]]},
  {num:7,words:[["Ua fetalai atu Iesu ia te ia,", "Jesus said unto him,"], ["Ua tusia foi,", "It is written again,"], ["Aua e te tofotofo i le Alii lou Atua.", "Thou shalt not tempt the Lord thy God."]]},
  {num:8,words:[["Ona toe ave lea o ia e le tiapolo i le mauga matuā maualuga,", "Again, the devil taketh him up into an exceeding high mountain,"], ["ua ia faaali foi ia te ia malo uma o le lalolagi ma o latou matagofie;", "and sheweth him all the kingdoms of the world, and the glory of them;"]]},
  {num:9,words:[["ona fai mai lea o ia ia te ia,", "And saith unto him,"], ["Ou te avatua nei mea uma ia te oe,", "All these things will I give thee,"], ["pe afai e te faapaū ma ifo mai ia te au.", "if thou wilt fall down and worship me."]]},
  {num:10,words:[["Ona fetalai atu lea o Iesu ia te ia,", "Then saith Jesus unto him,"], ["Ina alu ese ia oe Satani;", "Get thee hence,"], ["auā ua tusia,", "Satan: for it is written,"], ["E te ifo atu i le Alii lou Atua,", "Thou shalt worship the Lord thy God,"], ["ua na o ia lava e te auauna i ai.", "and him only shalt thou serve."]]},
  {num:11,words:[["Ona tuua ai lea o ia e le tiapolo,", "Then the devil leaveth him,"], ["faauta foi,", "and, behold,"], ["ua o mai agelu ma auauna mai ia te ia.", "angels came and ministered unto him."]]},
  {num:12,words:[["Ua faafofoga Iesu ua tuuina atu Ioane i le fale puipui ,", "Now when Jesus had heard that John was cast into prison,"], ["ona maliu atu ai lea o ia i Kalilaia;", "he departed into Galilee;"]]},
  {num:13,words:[["ua tuua e ia o Nasareta,", "And leaving Nazareth,"], ["ua maliu atu o ia ma nofo i Kapanaumi ua tu matafaga,", "he came and dwelt in Capernaum, which is upon the sea coast,"], ["i le tuaoi o Sepulona ma Nafatali;", "in the borders of Zabulon and Nephthalim:"]]},
  {num:14,words:[["ina ia taunuu ai le upu a le perofeta o Isaia,", "That it might be fulfilled which was spoken by Esaias the prophet,"], ["ua faapea mai,", "saying,"]]},
  {num:15,words:[["O le nuu o Sepulona,", "The land of Zabulon,"], ["ma le nuu o Nafatali,", "and the land of Nephthalim,"], ["o le ala i le vai i tala ane o Ioritana,", "by the way of the sea, beyond Jordan,"], ["o Kalilaia o nuu ese,", "Galilee of the Gentiles;"]]},
  {num:16,words:[["o le nuu sa nofo i le pouliuli, ua latou iloa le malamalama tele;", "The people which sat in darkness saw great light;"], ["o i latou foi sa nonofo i le nuu ma le ata o le oti ua alu ae le malamalama ia te i latou.", "and to them which sat in the region and shadow of death light is sprung up."]]},
  {num:17,words:[["Talu mai ai na afua ona tala'i atu e Iesu,", "From that time Jesus began to preach,"], ["ua faapea atu,", "and to say,"], ["Ina salamo ia outou;", "Repent:"], ["auā ua latalata mai le malo o le lagi.", "for the kingdom of heaven is at hand."]]},
  {num:18,words:[["Ua savali ane Iesu e latalata ane i le vai o Kalilaia,", "And Jesus,"], ["ona silafia lea e ia o le uso e toalua,", "walking by the sea of Galilee,"], ["o Simona ua igoa ia Peteru,", "saw two brethren, Simon called Peter,"], ["ma Aneterea lona uso,", "and Andrew his brother,"], ["ua la lafo le upega i le vai,", "casting a net into the sea:"], ["aua o tagata fai faiva i laua.", "for they were fishers."]]},
  {num:19,words:[["Ona fetalai atu lea o ia ia te i laua,", "And he saith unto them,"], ["Ina mulimuli mai ia ia te au,", "Follow me,"], ["ou te faia oulua ma fai faiva i tagata.", "and I will make you fishers of men."]]},
  {num:20,words:[["Ona la tuua loa lea o laua upega,", "And they straightway left their nets,"], ["a e mulimuli atu ia te ia.", "and followed him."]]},
  {num:21,words:[["Ua tuanai foi e ia lea mea,", "And going on from thence,"], ["ona silafia lea e ia o le isi uso e toalua,", "he saw other two brethren,"], ["o Iakopo le atalii o Sepetaio,", "James the son of Zebedee,"], ["ma Ioane lona uso,", "and John his brother,"], ["ua i le vaa ma lo la tamā o Sepetaio,", "in a ship with Zebedee their father,"], ["ua latou fai masae o latou upega;", "mending their nets;"], ["ua ia valaauina atu foi ia te i laua.", "and he called them."]]},
  {num:22,words:[["Ona la tuua loa lea o le vaa ma lo la tamā,", "And they immediately left the ship and their father,"], ["a e mulimuli atu ia te ia.", "and followed him."]]},
  {num:23,words:[["Ua faataamilo Iesu i Kalilaia uma,", "And Jesus went about all Galilee,"], ["ua ia a'oa'o i o latou sunako,", "teaching in their synagogues,"], ["ua ia tala'i atu foi le tala lelei o le malo,", "and preaching the gospel of the kingdom,"], ["ma faamalolo e ia o ma'i uma ma ma'i tiga uma o le nuu.", "and healing all manner of sickness and all manner of disease among the people."]]},
  {num:24,words:[["Ua oo atu ai lona logo i Suria uma,", "And his fame went throughout all Syria:"], ["ona latou au mai ai lea ia te ia o e ua mamai atoa uma, o e ua i ai ma'i eseese,", "and they brought unto him all sick people that were taken with divers diseases and torments,"], ["ma e ua puapuagatia,", "and those which were possessed with devils,"], ["ma e ua uluitinoina e temoni,", "and those which were lunatick,"], ["ma e ua ma'i māliu, atoa ma e ua mamai i le supa;", "and those that had the palsy;"], ["ona faamaloloina lea o i latou e ia.", "and he healed them."]]},
  {num:25,words:[["Ona mulimuli atu lea ia te ia o le motu o tagata e toatele mai Kalilaia,", "And there followed him great multitudes of people from Galilee,"], ["ma Tekapoli,", "and from Decapolis,"], ["ma Ierusalema,", "and from Jerusalem,"], ["ma Iutaia,", "and from Judaea,"], ["ma ona tala atu o Ioritana.", "and from beyond Jordan."]]},
];
renderVerseSet(mat_ch_4_Verses, 'mat-ch4-verses');

var mat_ch_5_Verses = [
  {num:1,words:[["Ua silasila atu ia i le motu o tagata,", "And seeing the multitudes,"], ["ona maliu ae lea o ia i le mauga;", "he went up into a mountain:"], ["ua nofo ai i lalo,", "and when he was set,"], ["ona o mai ai lea o ona soo ia te ia;", "his disciples came unto him:"]]},
  {num:2,words:[["ua ia fetalai atu,", "And he opened his mouth,"], ["ma a'oa'o ia te i latou,", "and taught them,"], ["ua faapea atu,", "saying,"]]},
  {num:3,words:[["Amuia ē loto maulalo;", "Blessed are the poor in spirit:"], ["auā e o latou le malo o le lagi.", "for their's is the kingdom of heaven."]]},
  {num:4,words:[["Amuia ē faanoanoa;", "Blessed are they that mourn:"], ["auā e faamafanafanaina i latou.", "for they shall be comforted."]]},
  {num:5,words:[["Amuia ē agamalu;", "Blessed are the meek:"], ["auā e fai mo latou tofi le nuu.", "for they shall inherit the earth."]]},
  {num:6,words:[["Amuia ē fia aai ma fia inu i le amiotonu;", "Blessed are they which do hunger and thirst after righteousness:"], ["auā e maoona i latou.", "for they shall be filled."]]},
  {num:7,words:[["Amuia ē alolofa atu;", "Blessed are the merciful:"], ["auā e alofaina mai i latou.", "for they shall obtain mercy."]]},
  {num:8,words:[["Amuia ē loto mamā;", "Blessed are the pure in heart:"], ["auā latou te iloa atu le Atua.", "for they shall see God."]]},
  {num:9,words:[["Amuia ē faatupuina le filemu;", "Blessed are the peacemakers:"], ["auā e ta'ua i latou o atalii o le Atua.", "for they shall be called the children of God."]]},
  {num:10,words:[["Amuia ē sauaina ona o le amiotonu;", "Blessed are they which are persecuted for righteousness' sake:"], ["auā e o latou le malo o le lagi.", "for their's is the kingdom of heaven."]]},
  {num:11,words:[["Amuia outou pe a latou upu leaga,", "Blessed are ye, when men shall revile you,"], ["ma faasaua ia te outou,", "and persecute you,"], ["ma latou tuuaiina pepelo outou i mea leaga uma ona o a'u.", "and shall say all manner of evil against you falsely, for my sake."]]},
  {num:12,words:[["Ia outou olioli ma fiafia lava;", "Rejoice,"], ["auā o i le lagi lo outou taui e tele;", "and be exceeding glad: for great is your reward in heaven:"], ["auā na faapea ona latou faasaua i perofeta e na muamua ia te outou.", "for so persecuted they the prophets which were before you."]]},
  {num:13,words:[["O outou,", "Ye are the salt of the earth:"], ["o le masima o le lalolagi outou;", "but if the salt have lost his savour,"], ["a e afai e magalo le masima, pe se a se mea e faamāi a'i? E leai se mea e toe aoga ai,", "wherewith shall it be salted? it is thenceforth good for nothing,"], ["na ona lafoaiina i fafo,", "but to be cast out,"], ["ma solia e tagata.", "and to be trodden under foot of men."]]},
  {num:14,words:[["O outou, o le malamalama o le lalolagi outou.", "Ye are the light of the world."], ["E le mafai ona lilo le aai ua tu i luga o le mauga.", "A city that is set on an hill cannot be hid."]]},
  {num:15,words:[["Latou te le tŭtŭina foi le lamepa i le tuu ai i lalo o le mea e fua a'i saito,", "Neither do men light a candle, and put it under a bushel,"], ["a e tuu i luga lava o le tuugālamepa ia pupula atu ai i e o i le fale uma.", "but on a candlestick; and it giveth light unto all that are in the house."]]},
  {num:16,words:[["Ia faapea ona pupula atu lo outou malamalama i luma o tagata,", "Let your light so shine before men,"], ["ina ia latou iloa la outou amio lelei,", "that they may see your good works,"], ["latou te vivii atu ai i lo outou Tamā o i le lagi.", "and glorify your Father which is in heaven."]]},
  {num:17,words:[["Aua ne'i outou manatu ua ou sau e tatalaina le tulafono po o le au perofeta;", "Think not that I am come to destroy the law,"], ["ou te lei sau e tatalaina,", "or the prophets: I am not come to destroy,"], ["a ia faataunuuina.", "but to fulfil."]]},
  {num:18,words:[["Auā e moni,", "For verily I say unto you,"], ["ou te fai atu ia te outou,", "Till heaven and earth pass,"], ["e mavae atu le lagi ma le lalolagi, a e le mavae atu lava se iota po o sina fāsi mataitusi o le tulafono,", "one jot or one tittle shall in no wise pass from the law,"], ["seia taunuu mea uma.", "till all be fulfilled."]]},
  {num:19,words:[["O lenei,", "Whosoever therefore shall break one of these least commandments,"], ["o se na te tatalaina se poloaiga e tasi e aupito itiiti o nei poloaiga,", "and shall teach men so,"], ["ma faapea ona a'oa'o i tagata, e ta'ua ia e aupito itiiti i le malo o le lagi;", "he shall be called the least in the kingdom of heaven:"], ["a o se anaana ma a'oa'o ai,", "but whosoever shall do and teach them,"], ["e ta'ua ia e sili i le malo o le lagi.", "the same shall be called great in the kingdom of heaven."]]},
  {num:20,words:[["Auā ou te fai atu ia te outou,", "For I say unto you,"], ["a le sili la outou amiotonu i la le au tusiupu ma le au faresaio,", "That except your righteousness shall exceed the righteousness of the scribes and Pharisees,"], ["e le sao atu lava outou i le malo o le lagi.", "ye shall in no case enter into the kingdom of heaven."]]},
  {num:21,words:[["Ua outou faalogo, na fai mai i e anamua,", "Ye have heard that it was said by them of old time,"], ["Aua e te fasioti tagata;", "Thou shalt not kill;"], ["ai se fasioti tagata, e nofo sala o ia i le faamasinoga.", "and whosoever shall kill shall be in danger of the judgment:"]]},
  {num:22,words:[["A o a'u,", "But I say unto you,"], ["ou te fai atu ia te outou,", "That whosoever is angry with his brother without a cause shall be in danger of the judgment:"], ["ai se ita fua i lona uso, e nofo sala o ia i le faamasinoga;", "and whosoever shall say to his brother,"], ["ai se fai atu foi i lona uso,", "Raca,"], ["Raka,", "shall be in danger of the council:"], ["e nofo sala o ia i le fono; ai se fai atu foi,", "but whosoever shall say,"], ["Le vale e,", "Thou fool,"], ["e nofo sala o ia i le afi o Kēna.", "shall be in danger of hell fire."]]},
  {num:23,words:[["Pe afai foi e te avatu lau taulaga i le fata faitaulaga,", "Therefore if thou bring thy gift to the altar,"], ["ona e manatua ai lea ua i lou uso se mea e tiga ai o ia ia te oe,", "and there rememberest that thy brother hath ought against thee;"]]},
  {num:24,words:[["ina tuu ia i lea mea o lau taulaga i luma o le fata faitaulaga,", "Leave there thy gift before the altar,"], ["a e alu oe ia muai faalelei i lou uso,", "and go thy way;"], ["i le e sau ai,", "first be reconciled to thy brother,"], ["ma avatu lau taulaga.", "and then come and offer thy gift."]]},
  {num:25,words:[["Ia vave ona oulua lelei ma loo tagi i ana mea ua ia te oe,", "Agree with thine adversary quickly,"], ["manū o i le ala oulua ma ia;", "whiles thou art in the way with him;"], ["ina ne'i tuuina atu oe i le faamasino e le ua tagi i ana mea,", "lest at any time the adversary deliver thee to the judge,"], ["e tuuina atu foi oe e le faamasino i le auauna,", "and the judge deliver thee to the officer,"], ["ona tuuina atu lea o oe i le fale puipui.", "and thou be cast into prison."]]},
  {num:26,words:[["E moni,", "Verily I say unto thee,"], ["ou te fai atu ia te oe, e te le toe ulufafo ai lava,", "Thou shalt by no means come out thence,"], ["seia e avatu tupe uma lava.", "till thou hast paid the uttermost farthing."]]},
  {num:27,words:[["Ua outou faalogo, na fai mai i e anamua,", "Ye have heard that it was said by them of old time,"], ["Aua e te mulilua.", "Thou shalt not commit adultery:"]]},
  {num:28,words:[["A ou te fai atu a'u ia te outou, ai se vaai atu i le fafine ina ia manao i ai,", "But I say unto you,"], ["ua uma ona mulilua ma ia i lona loto.", "That whosoever looketh on a woman to lust after her hath committed adultery with her already in his heart."]]},
  {num:29,words:[["Afai foi e te tausuai i lou mata taumatau,", "And if thy right eye offend thee,"], ["ina sali ese ia,", "pluck it out,"], ["ma e lafoai;", "and cast it from thee:"], ["auā e lelei ina fano se tasi ou fāsi tino,", "for it is profitable for thee that one of thy members should perish,"], ["a e leaga pe a lafoina lou tino uma i Kēna.", "and not that thy whole body should be cast into hell."]]},
  {num:30,words:[["Afai foi e te tausuai i lou lima taumatau,", "And if thy right hand offend thee,"], ["ina tutū ese ia,", "cut it off,"], ["ma e lafoai;", "and cast it from thee:"], ["auā e lelei ina fano se tasi ou fāsi tino,", "for it is profitable for thee that one of thy members should perish,"], ["a e leaga pe a lafoina lou tino uma i Kēna.", "and not that thy whole body should be cast into hell."]]},
  {num:31,words:[["Sa fai mai foi,", "It hath been said,"], ["Ai se faatea i lana avā,", "Whosoever shall put away his wife,"], ["ia avatu ia te ia le tusi alei.", "let him give her a writing of divorcement:"]]},
  {num:32,words:[["A ou te fai atu a'u ia te outou,", "But I say unto you,"], ["ai se faatea lana avā,", "That whosoever shall put away his wife,"], ["a e lei mulilua ia, ua ia faamulilua ia te ia;", "saving for the cause of fornication,"], ["ai se fai mana avā le ua faateaina,", "causeth her to commit adultery:"], ["ua mulilua foi o ia.", "and whosoever shall marry her that is divorced committeth adultery."]]},
  {num:33,words:[["Ua faalogo foi outou,", "Again,"], ["na fai mai i e anamua,", "ye have heard that it hath been said by them of old time,"], ["Aua e te tauto pepelo;", "Thou shalt not forswear thyself,"], ["a ia e avatu i le Alii o mea e te tauto ai.", "but shalt perform unto the Lord thine oaths:"]]},
  {num:34,words:[["A ou te fai atu a'u ia te outou,", "But I say unto you,"], ["aua lava ne'i tauto;", "Swear not at all;"], ["aua le tauto i le lagi,", "neither by heaven;"], ["auā o le nofoalii lea o le Atua;", "for it is God's throne:"]]},
  {num:35,words:[["po o le lalolagi,", "Nor by the earth;"], ["auā o le mea e tu ai ona aao lea;", "for it is his footstool:"], ["po o Ierusalema,", "neither by Jerusalem;"], ["auā o le aai lea a le Tupu silisili.", "for it is the city of the great King."]]},
  {num:36,words:[["Aua foi ne'i e tauto i lou ulu, auā e te le mafaia ona faasinasina,", "Neither shalt thou swear by thy head,"], ["pe faauliuli se lauulu e tasi.", "because thou canst not make one hair white or black."]]},
  {num:37,words:[["A ia faapea la outou upu,", "But let your communication be,"], ["Ioe,", "Yea,"], ["ioe; E leai,", "yea;"], ["e leai;", "Nay,"], ["auā o le upu e sili i na upu ,", "nay:"], ["mai le leaga lava ia.", "for whatsoever is more than these cometh of evil."]]},
  {num:38,words:[["Ua outou faalogo,", "Ye have heard that it hath been said,"], ["na fai mai, E suia le mata i le mata,", "An eye for an eye,"], ["e suia foi le nifo i le nifo.", "and a tooth for a tooth:"]]},
  {num:39,words:[["A ou te fai atu a'u ia te outou,", "But I say unto you,"], ["aua ne'i outou tetee atu i le leaga;", "That ye resist not evil:"], ["ai se na te po mai i lou alafau taumatau,", "but whosoever shall smite thee on thy right cheek,"], ["ia e liliu atu ia te ia le isi.", "turn to him the other also."]]},
  {num:40,words:[["O lē fia fai se faamasinoga ma oe e ave lou ofu tino,", "And if any man will sue thee at the law, and take away thy coat,"], ["ia e tuu atu foi i ai ma lou ofu tele.", "let him have thy cloke also."]]},
  {num:41,words:[["Ai se na te tauanau mai lua te o ma ia i le maila e tasi,", "And whosoever shall compel thee to go a mile,"], ["ina o ia oulua ma ia i maila e lua.", "go with him twain."]]},
  {num:42,words:[["Ia e avatu i le ua ole mai ia te oe;", "Give to him that asketh thee,"], ["aua foi e te liliu ese i le ua fia nonō tupe ia te oe.", "and from him that would borrow of thee turn not thou away."]]},
  {num:43,words:[["Ua outou faalogo,", "Ye have heard that it hath been said,"], ["na fai mai, Ia e alofa atu i lē lua te tuaoi,", "Thou shalt love thy neighbour,"], ["a ia 'ino'ino i le ua ita mai ia te oe.", "and hate thine enemy."]]},
  {num:44,words:[["A ou te fai atu a'u ia te outou,", "But I say unto you,"], ["ia outou alolofa atu i e ua ita mai ia te outou,", "Love your enemies,"], ["ia outou faamanuia atu i e ua fetuu mai ia te outou,", "bless them that curse you, do good to them that hate you,"], ["ia outou agalelei atu i e ua 'ino'ino mai ia te outou,", "and pray for them which despitefully use you,"], ["ia outou tatalo foi mo e ua tuua'i fua mai ma faasaua mai ia te outou;", "and persecute you;"]]},
  {num:45,words:[["ina ia faia outou ma atalii o lo outou Tamā o i le lagi,", "That ye may be the children of your Father which is in heaven:"], ["o le na te faaoso i lona la i e ua amio leaga atoa ma e ua amio lelei; ua ia faatotō ifo foi le ua i e ua amiotonu,", "for he maketh his sun to rise on the evil and on the good,"], ["atoa ma e ua amioletonu.", "and sendeth rain on the just and on the unjust."]]},
  {num:46,words:[["Auā afai tou te alolofa atu i e ua alolofa mai ia te outou,", "For if ye love them which love you,"], ["se a ea se taui tou te maua ai? e le faia ea e le au telona o lea lava mea?", "what reward have ye? do not even the publicans the same?"]]},
  {num:47,words:[["Pe afai tou te faapito lo outou fealofani i o outou uso,", "And if ye salute your brethren only,"], ["se a se mea sili ua outou faia? e le faapea ea ona faia e le au telona?", "what do ye more than others? do not even the publicans so?"]]},
  {num:48,words:[["O lenei, ia atoatoa ona lelei o la outou amio,", "Be ye therefore perfect,"], ["e pei o lo outou Tamā o i le lagi e atoatoa ona lelei o ia.", "even as your Father which is in heaven is perfect."]]},
];
renderVerseSet(mat_ch_5_Verses, 'mat-ch5-verses');

var mat_ch_6_Verses = [
  {num:1,words:[["Ia outou, ne'i avatu ni a outou mea alofa i luma o tagata,", "Take heed that ye do not your alms before men,"], ["ina ia iloa ai e i latou;", "to be seen of them:"], ["a faapea, ona leai ai lea o so outou taui mai lo outou Tamā o i le lagi.", "otherwise ye have no reward of your Father which is in heaven."]]},
  {num:2,words:[["O lea a e avatu ai ni mea alofa,", "Therefore when thou doest thine alms,"], ["aua ne'i e ilia le pu i ou luma,", "do not sound a trumpet before thee,"], ["pei ona faia e tagata pepelo i sunako ma ala,", "as the hypocrites do in the synagogues and in the streets,"], ["ina ia viia o i latou e tagata.", "that they may have glory of men."], ["E moni, ou te fai atu ia te outou,", "Verily I say unto you,"], ["ua maua e i latou lo latou taui.", "They have their reward."]]},
  {num:3,words:[["A ē avatu ni mea alofa,", "But when thou doest alms,"], ["aua ne'i iloa e lou lima tauagavale le mea ua faia e lou lima taumatau;", "let not thy left hand know what thy right hand doeth:"]]},
  {num:4,words:[["ina ia lilo au mea alofa; o lou Tamā foi,", "That thine alms may be in secret:"], ["o lē silafia i le mea lilo, o ia lava na te avatu faaaliali se taui ia te oe.", "and thy Father which seeth in secret himself shall reward thee openly."]]},
  {num:5,words:[["Pe a e tatalo,", "And when thou prayest,"], ["aua ne'i e pei o tagata pepelo,", "thou shalt not be as the hypocrites are:"], ["auā ua latou fia tutū ma tatalo i sunako ma fetaulaigāala,", "for they love to pray standing in the synagogues and in the corners of the streets,"], ["ina ia iloa i latou e tagata.", "that they may be seen of men."], ["E moni, ou te fai atu ia te outou,", "Verily I say unto you,"], ["ua maua e i latou lo latou taui.", "They have their reward."]]},
  {num:6,words:[["A o oe,", "But thou,"], ["pe a e tatalo,", "when thou prayest,"], ["ina ulu atu ia i lou afeafe, ma pupuni lona puipui,", "enter into thy closet,"], ["i le e tatalo ai i lou Tamā o i le mea lilo;", "and when thou hast shut thy door,"], ["o lou Tamā foi o lē silasila i le mea lilo,", "pray to thy Father which is in secret;"], ["na te avatu faaaliali se taui ia te oe.", "and thy Father which seeth in secret shall reward thee openly."]]},
  {num:7,words:[["A outou tatalo,", "But when ye pray,"], ["aua ne'i tāutu i a outou upu,", "use not vain repetitions,"], ["e pei o nuu ese; auā fa tei latou,", "as the heathen do:"], ["o le tele o a latou upu e talia ai i latou.", "for they think that they shall be heard for their much speaking."]]},
  {num:8,words:[["O lenei,", "Be not ye therefore like unto them:"], ["aua ne'i outou faapei o i latou; auā ua silafia e lo outou Tamā mea ua outou matitiva ai,", "for your Father knoweth what things ye have need of,"], ["a o lei ole atu outou ia te ia.", "before ye ask him."]]},
  {num:9,words:[["O lenei, ia faapea outou ona tatalo,", "After this manner therefore pray ye:"], ["Lo matou Tamā e,", "Our Father which art in heaven,"], ["o i le lagi, ia paia lou suafa.", "Hallowed be thy name."]]},
  {num:10,words:[["Ia oo mai lou malo. Ia faia lou finagalo i le lalolagi,", "Thy kingdom come. Thy will be done in earth,"], ["e pei ona faia i le lagi.", "as it is in heaven."]]},
  {num:11,words:[["Ia e foai mai ia te i matou i le aso nei a matou mea e 'ai e tatau ma le aso.", "Give us this day our daily bread."]]},
  {num:12,words:[["Ia e faamagalo ia te i matou i a matou agasala,", "And forgive us our debts,"], ["e pei o i matou foi ona matou faamagaloina atu i e ua agaleaga mai ia te i matou.", "as we forgive our debtors."]]},
  {num:13,words:[["Aua foi e te ta'ita'iina i matou i le tofotofoga;", "And lead us not into temptation,"], ["a ia e laveai ia i matou ai le leaga. Auā e ou le malo,", "but deliver us from evil:"], ["ma le mana,", "For thine is the kingdom,"], ["atoa ma le viiga,", "and the power,"], ["e faavavau lava,", "and the glory,"], ["Amene.", "for ever. Amen."]]},
  {num:14,words:[["Auā afai tou te faamagaloina atu tagata i a latou agasala,", "For if ye forgive men their trespasses,"], ["e faamagaloina foi outou e lo outou Tamā o i le lagi.", "your heavenly Father will also forgive you:"]]},
  {num:15,words:[["A e afai tou te le faamagaloina atu tagata i a latou agasala,", "But if ye forgive not men their trespasses,"], ["e le faamagaloina foi e lo outou Tamā a outou agasala.", "neither will your Father forgive your trespasses."]]},
  {num:16,words:[["Pe a outou anapopogi,", "Moreover when ye fast, be not,"], ["aua ne'i outou mata faanoanoa pei o tagata pepelo;", "as the hypocrites,"], ["auā ua latou faalaleaga o latou mata,", "of a sad countenance:"], ["ina ia iloa e tagata ua latou anapopogi.", "for they disfigure their faces, that they may appear unto men to fast."], ["E moni, ou te fai atu ia te outou,", "Verily I say unto you,"], ["ua maua e i latou lo latou taui.", "They have their reward."]]},
  {num:17,words:[["A o oe,", "But thou,"], ["pe a e anapogi,", "when thou fastest,"], ["ia uu lou ulu,", "anoint thine head,"], ["ma mulumulu ou mata;", "and wash thy face;"]]},
  {num:18,words:[["ina ia le iloa e tagata ua e anapogi,", "That thou appear not unto men to fast,"], ["na o lou Tamā o i le mea lilo;", "but unto thy Father which is in secret:"], ["o lou Tamā foi o loo silasila i le mea lilo,", "and thy Father, which seeth in secret,"], ["na te avatu faaaliali se taui ia te oe.", "shall reward thee openly."]]},
  {num:19,words:[["Aua tou te tolo'a'i oa mo outou i le lalolagi,", "Lay not up for yourselves treasures upon earth,"], ["o i ai le mogamoga ma le ele e faaumatia ai; o i ai foi tagata gaoi e eli atu,", "where moth and rust doth corrupt,"], ["ma gaoi ai.", "and where thieves break through and steal:"]]},
  {num:20,words:[["A ia outou tolo'a'i oa mo outou i le lagi, e le o i ai se mogamoga,", "But lay up for yourselves treasures in heaven,"], ["po o se ele e faaumatia ai;", "where neither moth nor rust doth corrupt,"], ["e le o i ai foi tagata gaoi e eli atu, ma gaoi ai.", "and where thieves do not break through nor steal:"]]},
  {num:21,words:[["Auā o le mea ua i ai lo outou oa,", "For where your treasure is,"], ["e i ai atoa foi ma o outou loto.", "there will your heart be also."]]},
  {num:22,words:[["O le lamepa o le tino,", "The light of the body is the eye:"], ["o mata ia; pe afai foi e lelei ou mata,", "if therefore thine eye be single,"], ["e malamalama uma ai lou tino.", "thy whole body shall be full of light."]]},
  {num:23,words:[["A e afai e leaga ou mata,", "But if thine eye be evil,"], ["e pouliuli uma ai lou tino. O lenei,", "thy whole body shall be full of darkness. If therefore the light that is in thee be darkness,"], ["afai e pouliuli le malamalama ua i totonu ia te oe ona matuā tele ai lea o le pouliuli.", "how great is that darkness!"]]},
  {num:24,words:[["E leai se na te mafaia ona auauna i alii e toalua;", "No man can serve two masters:"], ["auā e 'ino'ino o ia i le tasi,", "for either he will hate the one,"], ["a e alofa atu i le tasi; a le o lea,", "and love the other;"], ["e faapipii atu ia i le tasi,", "or else he will hold to the one,"], ["a e faaleaoga i le tasi.", "and despise the other."], ["Tou te le mafaia ona auauna i le Atua atoa ma mamone.", "Ye cannot serve God and mammon."]]},
  {num:25,words:[["O le mea lea ou te fai atu ai ia te outou,", "Therefore I say unto you,"], ["aua ne'i outou popole i o outou ola,", "Take no thought for your life,"], ["i mea tou te aai ai,", "what ye shall eat,"], ["ma mea tou te inu ai,", "or what ye shall drink;"], ["po o outou tino,", "nor yet for your body,"], ["i mea tou te oofu ai. E le sili ea le ola i le mea e 'ai,", "what ye shall put on. Is not the life more than meat,"], ["ma le tino i le ofu?", "and the body than raiment?"]]},
  {num:26,words:[["Ia outou vaavaai i manu felelei;", "Behold the fowls of the air:"], ["latou te le lulu saito,", "for they sow not,"], ["pe selesele,", "neither do they reap,"], ["pe faaputu i fale saito,", "nor gather into barns;"], ["a e fagaina i latou e lo outou Tamā o i le lagi. E le sili ea o outou lelei i lo latou?", "yet your heavenly Father feedeth them. Are ye not much better than they?"]]},
  {num:27,words:[["O ai ea so outou na te mafaia i lona popole ona faateleina le umi o lona olaga i le kupita e tasi?", "Which of you by taking thought can add one cubit unto his stature?"]]},
  {num:28,words:[["Se a foi le mea tou te popole ai i ofu? Ia outou mafaufau i lautalotalo o le vao,", "And why take ye thought for raiment? Consider the lilies of the field,"], ["pe faapefea ona tupu;", "how they grow;"], ["latou te le galulue,", "they toil not,"], ["latou te le milo foi;", "neither do they spin:"]]},
  {num:29,words:[["a ou te fai atu ia te outou,", "And yet I say unto you,"], ["o Solomona ma lona matagofie tele na le ofu o ia pei o le tasi o na mea.", "That even Solomon in all his glory was not arrayed like one of these."]]},
  {num:30,words:[["Afai e faapea ona faaofuina e le Atua le vao o le fanua,", "Wherefore, if God so clothe the grass of the field,"], ["o ola mai i le asō,", "which to day is,"], ["a e lafoina a taeao i le ogaumu;", "and to morrow is cast into the oven,"], ["e le sili ea ona faaofuina o outou e faatuatua itiiti?", "shall he not much more clothe you, O ye of little faith?"]]},
  {num:31,words:[["O lenei,", "Therefore take no thought,"], ["aua ne'i outou popole,", "saying,"], ["ma faapea ane. Ni a mea tatou te aai ai,", "What shall we eat? or,"], ["ni a foi mea tatou te inu ai,", "What shall we drink? or,"], ["ni a foi mea tatou te oofu ai?", "Wherewithal shall we be clothed?"]]},
  {num:32,words:[["auā o mea uma ia ua sailia e nuu ese. Auā ua silafia e lo outou Tamā o i le lagi e aoga ia mea uma ia te outou.", "(For after all these things do the Gentiles seek:) for your heavenly Father knoweth that ye have need of all these things."]]},
  {num:33,words:[["A ia outou muai saili le malo o le Atua ma lana amiotonu;", "But seek ye first the kingdom of God, and his righteousness;"], ["ona faaopoopoina atu lea o ia mea uma ia te outou.", "and all these things shall be added unto you."]]},
  {num:34,words:[["O lenei, aua tou te popole i le aso a taeao;", "Take therefore no thought for the morrow:"], ["auā e popole le aso a taeao i ana lava mea.", "for the morrow shall take thought for the things of itself."], ["E tatau i le aso lona lava leaga.", "Sufficient unto the day is the evil thereof."]]},
];
renderVerseSet(mat_ch_6_Verses, 'mat-ch6-verses');

var mat_ch_7_Verses = [
  {num:1,words:[["Aua tou te faamasino atu,", "Judge not,"], ["ina ne'i faamasinoina outou.", "that ye be not judged."]]},
  {num:2,words:[["Auā o le faamasinoga tou te faamasinoina atu ai,", "For with what judgment ye judge,"], ["e faamasinoina ai outou;", "ye shall be judged:"], ["o le fua foi tou te fuaina atu ai,", "and with what measure ye mete,"], ["e toe fuaina mai ai ia te outou.", "it shall be measured to you again."]]},
  {num:3,words:[["Se a le mea e te vaai atu ai i se fāsi laau i le mata o lou uso a e te le iloa e oe le utupoto i lou lava mata?", "And why beholdest thou the mote that is in thy brother's eye, but considerest not the beam that is in thine own eye?"]]},
  {num:4,words:[["Pe faapefea foi ona e fai atu i lou uso,", "Or how wilt thou say to thy brother,"], ["Tuu mai ia,", "Let me pull out the mote out of thine eye;"], ["so'u eu ese le fāsi laau i lou mata;", "and,"], ["faauta foi,", "behold,"], ["o i lou lava mata le utupoto?", "a beam is in thine own eye?"]]},
  {num:5,words:[["O oe na le pepelo,", "Thou hypocrite,"], ["ia e muai tiai le utupoto i lou lava mata,", "first cast out the beam out of thine own eye;"], ["ona e iloa lelei ai lea e eueseina atu le fāsi laau i le mata o lou uso.", "and then shalt thou see clearly to cast out the mote out of thy brother's eye."]]},
  {num:6,words:[["Aua tou te avatu le mea paia i ulī;", "Give not that which is holy unto the dogs,"], ["aua foi tou te lafo a outou penina i luma o puaa,", "neither cast ye your pearls before swine,"], ["ne'i latou soli ai i o latou vae, ma liliu mai,", "lest they trample them under their feet,"], ["i le saeia ai outou.", "and turn again and rend you."]]},
  {num:7,words:[["Ia outou ole atu,", "Ask,"], ["ona foaiina mai ai lea ia te outou;", "and it shall be given you;"], ["ia outou saili,", "seek,"], ["ona outou maua ai lea;", "and ye shall find;"], ["ia outou tu'itu'i atu,", "knock,"], ["ona toina ai lea ia te outou.", "and it shall be opened unto you:"]]},
  {num:8,words:[["Auā ai se ole atu, e maua e ia;", "For every one that asketh receiveth;"], ["o lē saili foi,", "and he that seeketh findeth;"], ["e iloa e ia; e toina foi i lē tu'itu'i atu.", "and to him that knocketh it shall be opened."]]},
  {num:9,words:[["O ai foi se tagata o outou pe a ole mai lona atalii se areto,", "Or what man is there of you, whom if his son ask bread,"], ["na te avane ea ia te ia se maa?", "will he give him a stone?"]]},
  {num:10,words:[["a ole mai foi se i'a,", "Or if he ask a fish,"], ["na te avane ea ia te ia se gata?", "will he give him a serpent?"]]},
  {num:11,words:[["O lenei,", "If ye then,"], ["o outou e leaga,", "being evil,"], ["afai ua iloa e outou ona avatu o mea lelei mā a outou fanau,", "know how to give good gifts unto your children,"], ["e le sili ea ona foaiina mai e lo outou Tamā o i le lagi o mea lelei i e ole atu ai ia te ia?", "how much more shall your Father which is in heaven give good things to them that ask him?"]]},
  {num:12,words:[["O mea uma foi tou te loto i ai ia faia e tagata ia te outou,", "Therefore all things whatsoever ye would that men should do to you,"], ["ia faapea lava ona outou faia ia te i latou;", "do ye even so to them:"], ["auā o le tulafono lea ma le au perofeta.", "for this is the law and the prophets."]]},
  {num:13,words:[["Ia outou ulu atu i le faitotoa va apiapi;", "Enter ye in at the strait gate:"], ["auā e va tele le faitotoa,", "for wide is the gate,"], ["e lautele foi le ala e tau atu i le malaia,", "and broad is the way, that leadeth to destruction,"], ["e toatele foi i latou o e ui atu ai.", "and many there be which go in thereat:"]]},
  {num:14,words:[["Auā e va apiapi le faitotoa,", "Because strait is the gate,"], ["e lauitiiti foi le ala e tau atu i le ola,", "and narrow is the way, which leadeth unto life,"], ["e toaitiiti foi i latou o e maua.", "and few there be that find it."]]},
  {num:15,words:[["Ia outou ma perofeta pepelo,", "Beware of false prophets,"], ["o e o mai ia te outou i ofu faamamoe,", "which come to you in sheep's clothing,"], ["a o totonu o luko feai lava i latou.", "but inwardly they are ravening wolves."]]},
  {num:16,words:[["Tou te iloa i latou i o latou fua. Pe tau mai ea tagata se fuifui vine mai le laau tuitui,", "Ye shall know them by their fruits. Do men gather grapes of thorns,"], ["po o mati mai le laau talatala?", "or figs of thistles?"]]},
  {num:17,words:[["E faapea foi laau lelei taitasi ma fua mai i fua lelei;", "Even so every good tree bringeth forth good fruit;"], ["a o le laau leaga e fua mai i fua leaga.", "but a corrupt tree bringeth forth evil fruit."]]},
  {num:18,words:[["E le mafai i le laau lelei ona fua mai i fua leaga,", "A good tree cannot bring forth evil fruit,"], ["e le mafai foi i le laau leaga ona fua mai i fua lelei.", "neither can a corrupt tree bring forth good fruit."]]},
  {num:19,words:[["O laau uma e le fua mai i fua lelei,", "Every tree that bringeth not forth good fruit is hewn down,"], ["e taia ia ma lafoina i le afi.", "and cast into the fire."]]},
  {num:20,words:[["O lea foi tou te iloa ai i latou i o latou fua.", "Wherefore by their fruits ye shall know them."]]},
  {num:21,words:[["E le sao atu i le malo o le lagi i latou uma o e fai mai ia te au,", "Not every one that saith unto me,"], ["Le Alii e,", "Lord,"], ["le Alii e;", "Lord, shall enter into the kingdom of heaven;"], ["na o le na te faia le finagalo o lo'u Tamā o i le lagi.", "but he that doeth the will of my Father which is in heaven."]]},
  {num:22,words:[["E toatele latou te fai mai ia te au i lea aso, Le Alii e,", "Many will say to me in that day,"], ["le Alii e,", "Lord,"], ["matou te lei perofeta ane ea i lou igoa,", "Lord,"], ["o lou igoa foi na matou tulia ai temoni, o lou igoa foi na matou fai ai vavega e tele?", "have we not prophesied in thy name? and in thy name have cast out devils? and in thy name done many wonderful works?"]]},
  {num:23,words:[["Ona ou ta'utino atu ai lea ia te i latou,", "And then will I profess unto them,"], ["Ou te lei iloa lava outou;", "I never knew you:"], ["ina o ese ia outou ia te au,", "depart from me,"], ["o outou o e fai amio leaga.", "ye that work iniquity."]]},
  {num:24,words:[["O lenei,", "Therefore whosoever heareth these sayings of mine,"], ["ai se faalogo i a'u upu nei,", "and doeth them,"], ["ma faia e ia, ou te faatusaina o ia i le tagata poto,", "I will liken him unto a wise man,"], ["ua na faia lona fale i luga o le papa;", "which built his house upon a rock:"]]},
  {num:25,words:[["ona to mai lea o uaga,", "And the rain descended,"], ["ua oo mai foi tafega,", "and the floods came,"], ["ua agi mai foi o matagi,", "and the winds blew,"], ["ua pesi mai i lea fale,", "and beat upon that house;"], ["a e lei paū lava ia;", "and it fell not:"], ["auā ua faavaeina i luga o le papa.", "for it was founded upon a rock."]]},
  {num:26,words:[["Ai se faalogo foi i a'u upu nei,", "And every one that heareth these sayings of mine,"], ["a e le faia,", "and doeth them not,"], ["e faatusaina o ia i le tagata valea,", "shall be likened unto a foolish man,"], ["na na faia lona fale i luga o le oneone;", "which built his house upon the sand:"]]},
  {num:27,words:[["ona to mai lea o uaga,", "And the rain descended,"], ["ua oo mai foi tafega,", "and the floods came,"], ["ua agi mai foi o matagi,", "and the winds blew,"], ["ua pesi mai i lea fale,", "and beat upon that house;"], ["ona paū ai lea,", "and it fell:"], ["ua nutipalaina lava.", "and great was the fall of it."]]},
  {num:28,words:[["Ua faaiu e Iesu o nei upu,", "And it came to pass, when Jesus had ended these sayings,"], ["ona matuā taufaiofo ai lea o le motu o tagata i lana mataupu;", "the people were astonished at his doctrine:"]]},
  {num:29,words:[["auā ua ia a'oa'o ia te i latou e pei o se ua i ai le pule,", "For he taught them as one having authority,"], ["a e le pei o le au tusiupu.", "and not as the scribes."]]},
];
renderVerseSet(mat_ch_7_Verses, 'mat-ch7-verses');

var mat_ch_8_Verses = [
  {num:1,words:[["Ua maliu ifo ia i le mauga,", "When he was come down from the mountain,"], ["ona mulimuli mai ai lea ia te ia o le motu o tagata e toatele.", "great multitudes followed him."]]},
  {num:2,words:[["Faauta foi,", "And,"], ["ua sau le lepela,", "behold,"], ["ua ifo mai ia te ia,", "there came a leper and worshipped him, saying,"], ["ua faapea mai,", "Lord,"], ["Le Alii e,", "if thou wilt,"], ["a ē finagalo i ai e te mafaia lava ona faamamā mai ia te au.", "thou canst make me clean."]]},
  {num:3,words:[["Ona aapa atu lea e Iesu o lona aao,", "And Jesus put forth his hand,"], ["ua pa'i atu ia te ia,", "and touched him,"], ["ua faapea atu,", "saying,"], ["Ou te loto i ai;", "I will;"], ["ina mamā ia oe. Ona mamā loa lea o lona lepela.", "be thou clean. And immediately his leprosy was cleansed."]]},
  {num:4,words:[["Ona fetalai atu lea o Iesu ia te ia,", "And Jesus saith unto him,"], ["Ia oe,", "See thou tell no man;"], ["ne'i e ta'u atu i se tasi; a ia e alu,", "but go thy way,"], ["ina faaali oe i le faitaulaga,", "shew thyself to the priest,"], ["ma e avatu le taulaga na poloai ai Mose,", "and offer the gift that Moses commanded,"], ["e fai ma faailoga ia te i latou.", "for a testimony unto them."]]},
  {num:5,words:[["Ua oo atu Iesu i Kapanaumi,", "And when Jesus was entered into Capernaum,"], ["ona sau ai lea ia te ia o le ta'ita'i o le toaselau,", "there came unto him a centurion,"], ["ua aioi mai ia te ia,", "beseeching him,"]]},
  {num:6,words:[["ua faapea mai,", "And saying,"], ["Le Alii e,", "Lord,"], ["ua taoto la'u auauna i le fale e ma'i i le supa,", "my servant lieth at home sick of the palsy,"], ["ua matua tiga lava.", "grievously tormented."]]},
  {num:7,words:[["Ona fetalai atu lea o Iesu ia te ia,", "And Jesus saith unto him,"], ["O le a a'u alu atu e faamalolo ia te ia.", "I will come and heal him."]]},
  {num:8,words:[["Ua tali mai le ta'ita'i o le toaselau,", "The centurion answered and said,"], ["ua faapea mai Le Alii e,", "Lord,"], ["e le aoga a'u ona e ulufale atu i lalo ifo o lo'u fale;", "I am not worthy that thou shouldest come under my roof:"], ["tau lava ina oo mai sau fetalaiga,", "but speak the word only,"], ["e malolo ai la'u auauna.", "and my servant shall be healed."]]},
  {num:9,words:[["Auā o a'u foi o le tagata ua pule i ai le tasi,", "For I am a man under authority,"], ["ua ou pule foi i le 'au tau;", "having soldiers under me:"], ["a a'u fai atu i le tasi,", "and I say to this man,"], ["Ina alu ia,", "Go,"], ["ona alu ai lea;", "and he goeth;"], ["ma le tasi,", "and to another,"], ["Ina sau ia,", "Come,"], ["ona sau ai lea;", "and he cometh;"], ["ma la'u auauna,", "and to my servant,"], ["Ina faia lenei mea,", "Do this,"], ["ona fai ai lea.", "and he doeth it."]]},
  {num:10,words:[["Ua faafofoga i ai Iesu,", "When Jesus heard it,"], ["ona ofo ai lea,", "he marvelled,"], ["ua faapea atu foi i e ua mulimuli mai,", "and said to them that followed, Verily I say unto you,"], ["E moni,", "I have not found so great faith,"], ["ou te fai atu ia te outou,", "no,"], ["ou te lei iloa ia Isaraelu lava se faatuatua e faapena ona tele.", "not in Israel."]]},
  {num:11,words:[["Ou te fai atu foi ia te outou,", "And I say unto you,"], ["e toatele e o mai mai sasae ma sisifo,", "That many shall come from the east and west,"], ["e taooto e aai faatasi ma Aperaamo,", "and shall sit down with Abraham,"], ["ma Isaako,", "and Isaac,"], ["ma Iakopo,", "and Jacob,"], ["i le malo o le lagi;", "in the kingdom of heaven."]]},
  {num:12,words:[["a o tagata o le malo, e tulia i latou i le pouliuli i fafo,", "But the children of the kingdom shall be cast out into outer darkness:"], ["e i ai le taufaitagiaue ma le lilivau o nifo.", "there shall be weeping and gnashing of teeth."]]},
  {num:13,words:[["Ona fetalai atu ai lea o Iesu i le ta'ita'i o le toaselau,", "And Jesus said unto the centurion,"], ["Ina alu ia,", "Go thy way;"], ["e pei ona e faatuatua,", "and as thou hast believed,"], ["ia faapea lava ona faia mo oe. Ona malolo ai lea o lana auauna i lea lava itu aso.", "so be it done unto thee. And his servant was healed in the selfsame hour."]]},
  {num:14,words:[["Ua ulufale atu Iesu i le fale o Peteru,", "And when Jesus was come into Peter's house, he saw his wife's mother laid,"], ["ona silafia ai lea e ia le tinā o lana avā ua taoto i le ma'i vevela.", "and sick of a fever."]]},
  {num:15,words:[["Ua pa'i atu o ia i le lima o le fafine,", "And he touched her hand,"], ["ona te'a lava lea o le ma'i vevela ia te ia;", "and the fever left her:"], ["ona tulai lea o ia,", "and she arose,"], ["ua auauna ia te i latou.", "and ministered unto them."]]},
  {num:16,words:[["Ua oo i le afiafi,", "When the even was come,"], ["ona latou au mai ai lea ia te ia o tagata e toatele ua uluitinoina e temoni;", "they brought unto him many that were possessed with devils:"], ["ona ia tulia ai lea o agaga i le upu lava,", "and he cast out the spirits with his word,"], ["ua faamaloloina foi e ia o i latou uma na mamai.", "and healed all that were sick:"]]},
  {num:17,words:[["Ona taunuu ai lea o le upu a le perofeta o Isaia,", "That it might be fulfilled which was spoken by Esaias the prophet,"], ["ua faapea mai,", "saying,"], ["O ia lava na na aveina o tatou vaivai,", "Himself took our infirmities,"], ["ma na tauave o tatou ma'i.", "and bare our sicknesses."]]},
  {num:18,words:[["Ua silafia e Iesu le motu o tagata o toatele ua vagavagai mai ia te ia,", "Now when Jesus saw great multitudes about him,"], ["ona fetalai atu ai lea o ia ia o atu i le tasi itu.", "he gave commandment to depart unto the other side."]]},
  {num:19,words:[["Ona sau ai lea o le tasi tusiupu,", "And a certain scribe came,"], ["ua faapea mai ia te ia,", "and said unto him,"], ["Le a'oa'o e,", "Master,"], ["ou te mulimuli atu ia te oe i mea uma e te maliu atu i ai.", "I will follow thee whithersoever thou goest."]]},
  {num:20,words:[["Ona fetalai atu ai lea o Iesu ia te ia,", "And Jesus saith unto him,"], ["E fai lua o alope,", "The foxes have holes,"], ["e fai foi mea e momoe ai manu felelei; a o le Atalii o le tagata,", "and the birds of the air have nests;"], ["e leai se mea e moe ai o ia.", "but the Son of man hath not where to lay his head."]]},
  {num:21,words:[["Ua fai mai foi ia te ia o le tasi o ona soo,", "And another of his disciples said unto him,"], ["Le Alii e, tuu mai ia ia te au,", "Lord,"], ["so'u muai alu e tanu i lo'u tamā.", "suffer me first to go and bury my father."]]},
  {num:22,words:[["A ua fetalai atu Iesu ia te ia,", "But Jesus said unto him,"], ["Mulimuli mai ia ia te au,", "Follow me;"], ["a e tuu pea ia i e ua oti e tanu i o latou tagata oti.", "and let the dead bury their dead."]]},
  {num:23,words:[["Ua maliu ae ia i le vaa,", "And when he was entered into a ship,"], ["ona mulimuli atu ai lea ia te ia o ona soo.", "his disciples followed him."]]},
  {num:24,words:[["Faauta foi,", "And,"], ["ua to mai le afā tele i le vai,", "behold,"], ["ona osofia mai ai lea o le vaa e peau;", "there arose a great tempest in the sea, insomuch that the ship was covered with the waves:"], ["a ua tofa o ia.", "but he was asleep."]]},
  {num:25,words:[["Ona o mai ai lea o ona soo,", "And his disciples came to him,"], ["ua fafagu ia te ia,", "and awoke him,"], ["ua faapea mai,", "saying,"], ["Le Alii e,", "Lord,"], ["ia e faaola mai ia te i matou,", "save us:"], ["o le a maotu fano.", "we perish."]]},
  {num:26,words:[["Ona fetalai atu ai lea o ia ia te i latou,", "And he saith unto them,"], ["Se a le mea ua outou matatau ai,", "Why are ye fearful,"], ["outou e faatuatua itiiti? Ona tulai ai lea o ia,", "O ye of little faith? Then he arose,"], ["ua vavao i le matagi ma le vai,", "and rebuked the winds and the sea;"], ["ona tele ai lea o le malū.", "and there was a great calm."]]},
  {num:27,words:[["Ona taufaiofo ai lea o tagata,", "But the men marvelled,"], ["ua faapea ane,", "saying, What manner of man is this,"], ["Ua silisili lava lenei Alii! auā ua usiusitai ia te ia le matagi ma le vai.", "that even the winds and the sea obey him!"]]},
  {num:28,words:[["Ua oo atu ia i le tasi itu i le nuu o Kerekese,", "And when he was come to the other side into the country of the Gergesenes,"], ["ona fetaiai ai lea ma ia o tagata e toalua ua uluitinoina e temoni,", "there met him two possessed with devils,"], ["ua o mai mai tuugamau,", "coming out of the tombs,"], ["ua matuā faavalemalosi i laua,", "exceeding fierce,"], ["e le mafai ai se tasi ona ui ane i lea ala.", "so that no man might pass by that way."]]},
  {num:29,words:[["Faauta foi,", "And,"], ["ua alalaga i laua,", "behold,"], ["ua faapea mai,", "they cried out,"], ["Se a lau na ia te i matou nei,", "saying,"], ["Iesu e,", "What have we to do with thee,"], ["le Alo o le Atua? Ua e maliu mai ea iinei,", "Jesus,"], ["e te faatiga ia te i matou a o lei oo i ona po?", "thou Son of God? art thou come hither to torment us before the time?"]]},
  {num:30,words:[["Ua mamao ane foi ma i latou le lafu puaa e tele o tataa.", "And there was a good way off from them an herd of many swine feeding."]]},
  {num:31,words:[["Ua aioi mai temoni ia te ia,", "So the devils besought him,"], ["ua faapea mai,", "saying,"], ["Afai a ē tulia i matou i fafo,", "If thou cast us out,"], ["tuu mai ia ia te i matou e o atu i le lafu puaa.", "suffer us to go away into the herd of swine."]]},
  {num:32,words:[["Ona fetalai atu ai lea o ia ia te i latou,", "And he said unto them,"], ["Ina o ia.", "Go."], ["Ona latou o i fafo ai lea,", "And when they were come out,"], ["ua o atu i le lafu puaa;", "they went into the herd of swine:"], ["faauta foi,", "and, behold,"], ["ua feosofi ifo le lafu puaa uma i le tofē i le vai,", "the whole herd of swine ran violently down a steep place into the sea,"], ["ua mamate ai i le vai.", "and perished in the waters."]]},
  {num:33,words:[["Ona sosola ai lea o e sa fagaina,", "And they that kept them fled,"], ["ua oo i le aai,", "and went their ways into the city,"], ["ma tala atu ai mea uma,", "and told every thing,"], ["atoa ma mea ua oo i e sa i ai temoni.", "and what was befallen to the possessed of the devils."]]},
  {num:34,words:[["Faauta foi,", "And,"], ["ua o uma mai le aai e faafetaiai ia Iesu;", "behold,"], ["ua latou iloa o ia,", "the whole city came out to meet Jesus: and when they saw him,"], ["ona latou aioi mai ai lea ia alu ese o ia i lo latou nuu.", "they besought him that he would depart out of their coasts."]]},
];
renderVerseSet(mat_ch_8_Verses, 'mat-ch8-verses');

var mat_ch_9_Verses = [
  {num:1,words:[["Ona maliu ae lea o ia i le vaa,", "And he entered into a ship,"], ["ua maliu atu i le tasi itu,", "and passed over,"], ["ona oo lea i lana lava aai.", "and came into his own city."]]},
  {num:2,words:[["Faauta foi,", "And,"], ["ua latou au mai ia te ia le tagata supa,", "behold,"], ["ua taoto i le moega;", "they brought to him a man sick of the palsy,"], ["ua silafia foi e Iesu lo latou faatuatua,", "lying on a bed:"], ["ona fetalai atu ai lea o ia i le supa,", "and Jesus seeing their faith said unto the sick of the palsy;"], ["Lo'u atalii e,", "Son,"], ["ina faalototele ia oe,", "be of good cheer;"], ["ua faamagaloina au agasala.", "thy sins be forgiven thee."]]},
  {num:3,words:[["Faauta foi,", "And,"], ["ua faapea ifo nisi o le au tusiupu i o latou loto,", "behold, certain of the scribes said within themselves,"], ["Ua upu leaga lenei tagata i le Atua .", "This man blasphemeth."]]},
  {num:4,words:[["Ua silafia e Iesu o latou manatunatu, ona faapea atu lea o ia,", "And Jesus knowing their thoughts said,"], ["Se a le mea ua manatunatu leaga ai o outou loto?", "Wherefore think ye evil in your hearts?"]]},
  {num:5,words:[["auā po o le fea le faigofie? po o le fai atu,", "For whether is easier,"], ["Ua faamagaloina au agasala;", "to say,"], ["po o le faiatu,", "Thy sins be forgiven thee; or to say,"], ["Tulai ia,", "Arise,"], ["ina savali?", "and walk?"]]},
  {num:6,words:[["A e peitai ina ia iloa e outou o i ai i le Atalii o le tagata i le lalolagi le pule e faamagalo ai agasala,", "But that ye may know that the Son of man hath power on earth to forgive sins,"], ["(ona fetalai atu ai lea o ia i le supa,", "(then saith he to the sick of the palsy,"], [") Ina tulai ia,", ") Arise,"], ["ina ave lou moega,", "take up thy bed,"], ["ma alu i lou fale.", "and go unto thine house."]]},
  {num:7,words:[["Ona tulai ai lea o ia,", "And he arose,"], ["ua alu i lona fale.", "and departed to his house."]]},
  {num:8,words:[["Ua iloa e le motu o tagata,", "But when the multitudes saw it,"], ["ona taufaiofo ai lea;", "they marvelled, and glorified God,"], ["ua latou vivii atu i le Atua le ua foaiina mai le pule faapena i tagata.", "which had given such power unto men."]]},
  {num:9,words:[["Ua maliu ese Iesu i lea mea,", "And as Jesus passed forth from thence,"], ["ona silafia ai lea e ia o le tagata ua nofo i le fale e tali ai taulaga,", "he saw a man,"], ["o Mataio lona igoa;", "named Matthew, sitting at the receipt of custom:"], ["ua faapea atu ia te ia,", "and he saith unto him,"], ["Ina mulimuli mai ia ia te au.", "Follow me."], ["Ona tulai ai lea o ia,", "And he arose,"], ["ua mulimuli atu ia te ia.", "and followed him."]]},
  {num:10,words:[["Ua taoto o ia i le fale e taumafa,", "And it came to pass,"], ["faauta foi,", "as Jesus sat at meat in the house,"], ["o le au telona e toatele ma e ua agasala ua o mai ai,", "behold,"], ["ua latou taooto e aai faatasi ma Iesu ma ona soo.", "many publicans and sinners came and sat down with him and his disciples."]]},
  {num:11,words:[["Ua iloa e le au faresaio,", "And when the Pharisees saw it,"], ["ona latou fai atu ai lea i ona soo,", "they said unto his disciples,"], ["Se a le mea ua aai faatasi ai la outou a'oa'o ma le au telona ma e ua agasala?", "Why eateth your Master with publicans and sinners?"]]},
  {num:12,words:[["A ua lagona e Iesu,", "But when Jesus heard that,"], ["ona fetalai atu ai lea o ia ia te i latou,", "he said unto them,"], ["E le aoga le fomai i e malolo,", "They that be whole need not a physician,"], ["na o e mamai.", "but they that are sick."]]},
  {num:13,words:[["Ina o ia,", "But go ye and learn what that meaneth,"], ["ina a'oa'o po o le a le uiga o lea upu ,", "I will have mercy,"], ["Ou te loto i le alofa, a e le o le taulaga;", "and not sacrifice:"], ["auā ou te lei sau e valaau i e ua amiotonu,", "for I am not come to call the righteous,"], ["a o e ua agasala ina ia latou salamo.", "but sinners to repentance."]]},
  {num:14,words:[["Ona o mai ai lea o soo o Ioane ia te ia,", "Then came to him the disciples of John,"], ["ua faapea mai,", "saying,"], ["Se a le mea ua anapopogi soo ai i matou ma le au faresaio, a o ou soo,", "Why do we and the Pharisees fast oft,"], ["e le anapopogi i latou?", "but thy disciples fast not?"]]},
  {num:15,words:[["Ona fetalai atu ai lea o Iesu ia te i latou,", "And Jesus said unto them, Can the children of the bridechamber mourn,"], ["E mafai ea ona faanoanoa o aumea a le faatoafaiavā i ona aso o ia te i latou o le faatoafaiavā? A e oo mai ona aso e aveeseina ai ia te i latou o le faatoafaiavā,", "as long as the bridegroom is with them? but the days will come,"], ["ona latou anapopogi ai lea.", "when the bridegroom shall be taken from them, and then shall they fast."]]},
  {num:16,words:[["E leai se tasi na te fonoa le matuā ofu i le ie fou;", "No man putteth a piece of new cloth unto an old garment,"], ["auā e masae le ofu i lona fono,", "for that which is put in to fill it up taketh from the garment,"], ["ona atili ai lea ona masae.", "and the rent is made worse."]]},
  {num:17,words:[["E le utufia foi le uaina fou i fagu pa'u tuai;", "Neither do men put new wine into old bottles:"], ["a faapea,", "else the bottles break,"], ["ona pāpā ai lea o fagu pa'u, ona masaa lea o le uaina,", "and the wine runneth out,"], ["e māumau foi fagu pa'u;", "and the bottles perish:"], ["a e utufia le uaina fou i fagu pa'u fou,", "but they put new wine into new bottles,"], ["ona faatau saogalemu ai lea.", "and both are preserved."]]},
  {num:18,words:[["Ua fetalai atu ia i ia upu ia te i latou,", "While he spake these things unto them,"], ["faauta,", "behold,"], ["ua sau le alii,", "there came a certain ruler,"], ["ua ifo mai ia te ia,", "and worshipped him,"], ["ua faapea mai, Ua oti nei lava lo'u afafine;", "saying,"], ["a ia e maliu atu,", "My daughter is even now dead:"], ["ma faaee lou aao i luga ia te ia,", "but come and lay thy hand upon her,"], ["ona ola ai lea o ia.", "and she shall live."]]},
  {num:19,words:[["Ona tulai ai lea o Iesu,", "And Jesus arose, and followed him,"], ["ua mulimuli atu ia te ia o ia ma ona soo.", "and so did his disciples."]]},
  {num:20,words:[["Faauta foi,", "And, behold,"], ["o le fafine na i ai le puna toto i tausaga e sefulu ma le lua,", "a woman,"], ["ua alu ane ia i ona tua,", "which was diseased with an issue of blood twelve years,"], ["ua ia pa'i ane i le tuupao o lona ofu;", "came behind him, and touched the hem of his garment:"]]},
  {num:21,words:[["auā ua fai ifo ia i lona loto,", "For she said within herself,"], ["Afai ou te pa'i atu tau o lona ofu,", "If I may but touch his garment,"], ["ou te ola ai.", "I shall be whole."]]},
  {num:22,words:[["A ua fāliu Iesu,", "But Jesus turned him about,"], ["ua silafia o ia,", "and when he saw her,"], ["ona faapea atu ai lea o ia,", "he said,"], ["Lo'u afafine e,", "Daughter,"], ["ina faalototele ia oe,", "be of good comfort;"], ["ua e ola i lou faatuatua. Ona ola ai lea o le fafine talu lea lava itu aso.", "thy faith hath made thee whole. And the woman was made whole from that hour."]]},
  {num:23,words:[["Ua ulufale atu Iesu i le fale o le alii,", "And when Jesus came into the ruler's house,"], ["ona silafia ai lea e ia o e ili fagufagu ma le motu o tagata ua pa le lauaitu,", "and saw the minstrels and the people making a noise,"]]},
  {num:24,words:[["ua faapea atu o ia ia te i latou,", "He said unto them,"], ["Ina o ese ia;", "Give place:"], ["auā e lei oti le teine,", "for the maid is not dead,"], ["ua na ona moe. Ona latou tapisa mai ai lea ia te ia.", "but sleepeth. And they laughed him to scorn."]]},
  {num:25,words:[["Ua tulia le motu o tagata,", "But when the people were put forth,"], ["ona ulu atu ai lea o ia,", "he went in,"], ["ua tago i lona lima,", "and took her by the hand,"], ["ona tulai ae lea o le teine.", "and the maid arose."]]},
  {num:26,words:[["Ona logo atu lea o lenei mea i lea nuu uma.", "And the fame hereof went abroad into all that land."]]},
  {num:27,words:[["Ua maliu ese Iesu i lea mea,", "And when Jesus departed thence,"], ["ona mulimuli mai ai lea ia te ia o tauaso e toalua,", "two blind men followed him,"], ["ua alalaga,", "crying,"], ["ua faapea mai,", "and saying,"], ["Le alo e o Tavita,", "Thou Son of David,"], ["ia e alofa mai ia te i maua.", "have mercy on us."]]},
  {num:28,words:[["Ua ulufale ia i le fale,", "And when he was come into the house,"], ["ua o mai ai ia te ia o ia tauaso;", "the blind men came to him:"], ["ona fetalai atu ai lea o Iesu ia te i laua,", "and Jesus saith unto them,"], ["Ua oulua faatuatua mai ea ia te au ou te mafaia lenei mea? Ona la fai mai ai lea ia te ia,", "Believe ye that I am able to do this? They said unto him,"], ["Ioe,", "Yea,"], ["le Alii e.", "Lord."]]},
  {num:29,words:[["Ona pa'i atu ai lea o ia i o la mata,", "Then touched he their eyes,"], ["ua faapea atu, E pei ona oulua faatuatua,", "saying,"], ["ia faapea lava ona faia ia te oulua.", "According to your faith be it unto you."]]},
  {num:30,words:[["Ona pupula ai lea o laua mata. Ona matuā fetalai atu lea o Iesu ia te i laua,", "And their eyes were opened;"], ["ua faapea atu,", "and Jesus straitly charged them,"], ["Ia oulua,", "saying,"], ["ne'i faailoa atu i se tasi.", "See that no man know it."]]},
  {num:31,words:[["A ua la o ma faalauaitele le tala ia te ia i lea nuu uma.", "But they, when they were departed, spread abroad his fame in all that country."]]},
  {num:32,words:[["Ua la o,", "As they went out,"], ["faauta, ua latou au mai ia te ia le tagata gūgū,", "behold,"], ["ua uluitinoina e le temoni.", "they brought to him a dumb man possessed with a devil."]]},
  {num:33,words:[["Ua tulia le temoni,", "And when the devil was cast out,"], ["ona tautala mai ai lea o le gūgū. Ona taufaiofo ai lea o le motu o tagata,", "the dumb spake:"], ["ua faapea ane,", "and the multitudes marvelled, saying,"], ["E lei iloa mai anamua se mea faapena i Isaraelu.", "It was never so seen in Israel."]]},
  {num:34,words:[["A ua fai ane le au faresaio,", "But the Pharisees said,"], ["O le temoni sili ua tulia ai e ia e temoni.", "He casteth out devils through the prince of the devils."]]},
  {num:35,words:[["Ua faataamilo Iesu i aai uma ma faoa aai,", "And Jesus went about all the cities and villages,"], ["ua a'oa'o i o latou sunako,", "teaching in their synagogues,"], ["ma tala'i i le tala lelei o le malo, ua ia faamalolo foi i ma'i uma,", "and preaching the gospel of the kingdom,"], ["ma ma'i tiga uma o le nuu.", "and healing every sickness and every disease among the people."]]},
  {num:36,words:[["Ua silafia e ia le motu o tagata,", "But when he saw the multitudes,"], ["ona mutimuti vale ai lea o lona alofa ia te i latou,", "he was moved with compassion on them,"], ["ona ua lailoa i latou ma tuulafoaiina,", "because they fainted, and were scattered abroad,"], ["e pei o mamoe e leai so latou leoleo.", "as sheep having no shepherd."]]},
  {num:37,words:[["Ona fetalai atu ai lea o ia i ona soo,", "Then saith he unto his disciples,"], ["E tele le saito e seleseleina,", "The harvest truly is plenteous,"], ["a o le au fai galuega e toaitiiti ia;", "but the labourers are few;"]]},
  {num:38,words:[["o lea ia outou aioi atu ai i le Alii e ana le saito e seleseleina,", "Pray ye therefore the Lord of the harvest,"], ["ina ia aauina mai e ia ni e galulue i lana saito e seleseleina.", "that he will send forth labourers into his harvest."]]},
];
renderVerseSet(mat_ch_9_Verses, 'mat-ch9-verses');

var mat_ch_10_Verses = [
  {num:1,words:[["Ua valaau atu e ia ona soo e toasefulu ma le toalua,", "And when he had called unto him his twelve disciples,"], ["ona tuu atu lea e ia ia te i latou le pule i agaga leaga,", "he gave them power against unclean spirits,"], ["ina ia tutuli ia te i latou,", "to cast them out,"], ["ma faamalolo i ma'i uma ma ma'i tiga uma.", "and to heal all manner of sickness and all manner of disease."]]},
  {num:2,words:[["O igoa nei o le au aposetolo e toasefulu ma le toalua;", "Now the names of the twelve apostles are these;"], ["e muamua Simona e igoa ia Peteru,", "The first, Simon,"], ["ma Aneterea lona uso,", "who is called Peter,"], ["o Iakopo le atalii o Sepetaio ma Ioane lona uso,", "and Andrew his brother; James the son of Zebedee,"], ["o Filipo ma Patolomaio,", "and John his brother;"]]},
  {num:3,words:[["o Toma ma Mataio le telona,", "Philip, and Bartholomew; Thomas, and Matthew the publican;"], ["o Iakopo le atalii o Alefaio ma Lepaio e igoa ia Tataio,", "James the son of Alphaeus, and Lebbaeus, whose surname was Thaddaeus;"]]},
  {num:4,words:[["o Simona le Kanana ma Iuta le Sekara,", "Simon the Canaanite, and Judas Iscariot,"], ["o ia foi na faalata ia te ia.", "who also betrayed him."]]},
  {num:5,words:[["Ua aauina atu e Iesu o lenei toasefulu ma le toalua,", "These twelve Jesus sent forth,"], ["ua ia fetalai atu ia te i latou,", "and commanded them,"], ["ua faapea atu,", "saying,"], ["Aua tou te ui i se ala o nuu ese,", "Go not into the way of the Gentiles,"], ["aua foi tou te o atu i se aai o Samaria;", "and into any city of the Samaritans enter ye not:"]]},
  {num:6,words:[["a e lelei ona outou o atu i mamoe o le aiga o Isaraelu ua le iloa.", "But go rather to the lost sheep of the house of Israel."]]},
  {num:7,words:[["A outou o,", "And as ye go,"], ["ia outou tala'i atu,", "preach,"], ["ia faapea atu,", "saying,"], ["Ua latalata mai le malo o le lagi.", "The kingdom of heaven is at hand."]]},
  {num:8,words:[["Ia outou faamalolo i e mamai,", "Heal the sick,"], ["faamamā lepela,", "cleanse the lepers,"], ["faatutū i e ua oti,", "raise the dead, cast out devils:"], ["tutuli i temoni. Ua maua fua e outou,", "freely ye have received,"], ["ia outou foaifuaina atu.", "freely give."]]},
  {num:9,words:[["Aua ne'i teu ma outou o auro,", "Provide neither gold,"], ["po o ario,", "nor silver,"], ["po o 'apa memea i o outou fusi.", "nor brass in your purses,"]]},
  {num:10,words:[["Aua foi le ave se taga i le malaga,", "Nor scrip for your journey,"], ["aua foi le tailua o ofu tino,", "neither two coats,"], ["po o see vae,", "neither shoes,"], ["po o se tootoo;", "nor yet staves:"], ["auā e tatau ona avatu le mea e 'ai i le fai galuega.", "for the workman is worthy of his meat."]]},
  {num:11,words:[["O se aai po o se faoa aai tou te oo atu i ai,", "And into whatsoever city or town ye shall enter,"], ["ia fesili po o ai se i ai ua tatau;", "enquire who in it is worthy;"], ["ia outou nonofo ai i le tou o ai.", "and there abide till ye go thence."]]},
  {num:12,words:[["A outou ulufale atu i se aiga,", "And when ye come into an house,"], ["ia outou ofo alofa atu i ai.", "salute it."]]},
  {num:13,words:[["Pe afai foi ua tatau lea aiga,", "And if the house be worthy,"], ["ia oo atu i ai la outou faamanuia;", "let your peace come upon it:"], ["a e afai ua le tatau,", "but if it be not worthy,"], ["ia toe foi mai ai ia te outou la outou faamanuia.", "let your peace return to you."]]},
  {num:14,words:[["Ai se le talia outou,", "And whosoever shall not receive you,"], ["pe le faalogo i a outou upu,", "nor hear your words,"], ["a outou o atu nai lea fale po o lea aai,", "when ye depart out of that house or city,"], ["ia outou tūtū atu le eleele nai o outou vae.", "shake off the dust of your feet."]]},
  {num:15,words:[["E moni,", "Verily I say unto you,"], ["ou te fai atu ia te outou,", "It shall be more tolerable for the land of Sodom and Gomorrha in the day of judgment,"], ["O le aso faamasino e feoloolo ai Sotoma ma Komoro i lea lava aai.", "than for that city."]]},
  {num:16,words:[["Faauta,", "Behold,"], ["ou te aau atu ia te outou e pei o mamoe i le va o luko;", "I send you forth as sheep in the midst of wolves:"], ["o lenei, ia outou atamamai pei o gata,", "be ye therefore wise as serpents,"], ["a ia fifilemu e pei o lupe.", "and harmless as doves."]]},
  {num:17,words:[["Ia outou ma tagata;", "But beware of men:"], ["auā latou te tuuina atu outou i fono,", "for they will deliver you up to the councils,"], ["ma latou sasa ia te outou i o latou sunako.", "and they will scourge you in their synagogues;"]]},
  {num:18,words:[["E ta'ita'iina atu foi outou i luma o alii ma tupu ona o a'u,", "And ye shall be brought before governors and kings for my sake,"], ["e fai ma molimau ia te i latou atoa ma nuu ese.", "for a testimony against them and the Gentiles."]]},
  {num:19,words:[["Pe a latou tuuina atu outou,", "But when they deliver you up,"], ["aua tou te popole pe faapefea, pe se a foi tou te fai atu ai;", "take no thought how or what ye shall speak:"], ["auā e foaiina mai ia te outou i lea lava itu aso se upu tou te fai atu ai.", "for it shall be given you in that same hour what ye shall speak."]]},
  {num:20,words:[["Auā e le o outou e tautala atu ai,", "For it is not ye that speak,"], ["a o le Agaga o lo outou Tamā e tautala mai ai i totonu ia te outou.", "but the Spirit of your Father which speaketh in you."]]},
  {num:21,words:[["E tuuina atu le uso e le uso ia oti,", "And the brother shall deliver up the brother to death,"], ["e tuuina atu foi le fanau e le tamā;", "and the father the child: and the children shall rise up against their parents,"], ["e tutū atu foi le fanau i o latou matua ina ia fasiotia i latou.", "and cause them to be put to death."]]},
  {num:22,words:[["E inosia foi outou e tagata uma ona o lo'u igoa; a o lē tumau seia oo atu i le gataaga,", "And ye shall be hated of all men for my name's sake:"], ["e faaolaina o ia.", "but he that endureth to the end shall be saved."]]},
  {num:23,words:[["Pe a latou faasaua ia te outou i le tasi aai,", "But when they persecute you in this city,"], ["ia outou sosola i se tasi;", "flee ye into another:"], ["auā e moni,", "for verily I say unto you,"], ["ou te fai atu ia te outou,", "Ye shall not have gone over the cities of Israel,"], ["e le soo aai o Isaraelu ia te outou seia sau le Atalii o le tagata.", "till the Son of man be come."]]},
  {num:24,words:[["E le silli le soo i le a'oa'o,", "The disciple is not above his master,"], ["e le sili foi le auauna i lona alii;", "nor the servant above his lord."]]},
  {num:25,words:[["tau lava ina avea le soo ia faapei o lona a'oa'o,", "It is enough for the disciple that he be as his master,"], ["o le auauna foi ia faapei o lona alii. Afai ua latou ta'ua le matai o le aiga o Pelesepulo,", "and the servant as his lord. If they have called the master of the house Beelzebub,"], ["pe le sili ona latou faapea atu i lona aiga i se a?", "how much more shall they call them of his household?"]]},
  {num:26,words:[["O lenei,", "Fear them not therefore:"], ["aua tou te matatau ia te i latou;", "for there is nothing covered,"], ["auā e leai se mea o loo ufiufitia e le faaalia,", "that shall not be revealed; and hid,"], ["e leai foi se mea lilo e le faailoaina.", "that shall not be known."]]},
  {num:27,words:[["O la'u e fai atu ia te outou i le pouliuli,", "What I tell you in darkness,"], ["tou te ta'u atu lea i le malamalama;", "that speak ye in light:"], ["o le mea foi ua lagona i o outou taliga,", "and what ye hear in the ear,"], ["ia outou tala'i atu i luga o fale.", "that preach ye upon the housetops."]]},
  {num:28,words:[["Aua foi tou te matatau i e fasioti le tino,", "And fear not them which kill the body,"], ["a e latou te le mafaia ona fasioti le agaga;", "but are not able to kill the soul:"], ["a e lelei ona outou matatau i le ua mafai ona fano ia te ia le agaga atoa ma le tino i Kēna.", "but rather fear him which is able to destroy both soul and body in hell."]]},
  {num:29,words:[["E le faataulia ea ni manu iti se lua i le asari? e leai foi so laua e paū i le eleele e aunoa ma lo outou Tamā.", "Are not two sparrows sold for a farthing? and one of them shall not fall on the ground without your Father."]]},
  {num:30,words:[["A o outou lauulu lava ua faitaulia uma ia.", "But the very hairs of your head are all numbered."]]},
  {num:31,words:[["O lea aua tou te matatau ai;", "Fear ye not therefore,"], ["e sili outou i manu iti e tele.", "ye are of more value than many sparrows."]]},
  {num:32,words:[["O lenei, ai se na te ta'uta'u a'u i luma o tagata,", "Whosoever therefore shall confess me before men,"], ["o a'u foi ou te ta'uta'uina o ia i luma o lo'u Tamā o i le lagi.", "him will I confess also before my Father which is in heaven."]]},
  {num:33,words:[["Ai se faafiti foi ia te au i luma o tagata,", "But whosoever shall deny me before men,"], ["ou te faafitia foi o ia i luma o lo'u Tamā o i le lagi.", "him will I also deny before my Father which is in heaven."]]},
  {num:34,words:[["Aua tou te manatunatu ua ou sau e avatu le filemu i le lalolagi;", "Think not that I am come to send peace on earth:"], ["ou te lei sau e avatu le filemu,", "I came not to send peace,"], ["a o le pelu.", "but a sword."]]},
  {num:35,words:[["Auā ua ou sau e faamasesei le tagata ma lona tamā,", "For I am come to set a man at variance against his father,"], ["o le tama teine foi e faamasesei ma lona tinā,", "and the daughter against her mother,"], ["o le avā foi e faamasesei ma le tinā o lana tane.", "and the daughter in law against her mother in law."]]},
  {num:36,words:[["E fai foi le tagata ma fili o lona aiga.", "And a man's foes shall be they of his own household."]]},
  {num:37,words:[["O le ua tele lona alofa i lona tamā po o lona tinā, a e itiiti ia te au, e le aoga lea ia te au;", "He that loveth father or mother more than me is not worthy of me:"], ["o le ua tele foi lona alofa i lona atalii po o lona afafine, a e itiiti ia te au, e le aoga foi lea ia te au.", "and he that loveth son or daughter more than me is not worthy of me."]]},
  {num:38,words:[["O se le ave lona satauro,", "And he that taketh not his cross,"], ["ma le lē mulimuli mai ia te au,", "and followeth after me,"], ["e le aoga foi lea ia te au.", "is not worthy of me."]]},
  {num:39,words:[["O lē maua lona ola, e māumau ai ia te ia;", "He that findeth his life shall lose it:"], ["a o le faamāumau i lona ola ona o a'u, e maua e ia.", "and he that loseth his life for my sake shall find it."]]},
  {num:40,words:[["O lē talia outou, ua talia e ia o a'u;", "He that receiveth you receiveth me,"], ["o lē talia foi a'u, ua talia e ia o le na auina mai a'u.", "and he that receiveth me receiveth him that sent me."]]},
  {num:41,words:[["O lē talia foi o se perofeta i le igoa o le perofeta, e maua e ia le taui o le perofeta;", "He that receiveth a prophet in the name of a prophet shall receive a prophet's reward;"], ["o lē talia foi se tagata amiotonu i le igoa o le tagata amiotonu, e maua e ia le taui o le tagata amiotonu.", "and he that receiveth a righteous man in the name of a righteous man shall receive a righteous man's reward."]]},
  {num:42,words:[["Ai se avane foi tau lava se ipu vai mālulu e inu ai se tasi o i latou nei e faatauvaa i le igoa o le soo,", "And whosoever shall give to drink unto one of these little ones a cup of cold water only in the name of a disciple,"], ["e moni, ou te fai atu ia te outou,", "verily I say unto you,"], ["e le māumau lona taui.", "he shall in no wise lose his reward."]]},
];
renderVerseSet(mat_ch_10_Verses, 'mat-ch10-verses');

var mat_ch_11_Verses = [
  {num:1,words:[["Ua uma ona poloai e Iesu i ona soo e toasefulu ma le toalua,", "And it came to pass,"], ["ona maliu ese ai lea o ia i lea mea,", "when Jesus had made an end of commanding his twelve disciples,"], ["e a'oa'o atu ma tala'i atu i o latou aai.", "he departed thence to teach and to preach in their cities."]]},
  {num:2,words:[["Ua lagona e Ioane i le fale puipui o galuega a Keriso, ona aauina mai ai lea e ia ni ona soo se toalua,", "Now when John had heard in the prison the works of Christ,"], ["ua faapea mai ia te ia,", "he sent two of his disciples,"]]},
  {num:3,words:[["O oe ea lē maliu mai,", "And said unto him, Art thou he that should come,"], ["pe matou te faatali i se tasi?", "or do we look for another?"]]},
  {num:4,words:[["Ona tali atu ai lea o Iesu, ua faapea atu ia te i laua,", "Jesus answered and said unto them,"], ["Ina o atu ia oulua, ma faailoa atu ia Ioane o mea na oulua faalogo i ai, ma vaai i ai;", "Go and shew John again those things which ye do hear and see:"]]},
  {num:5,words:[["ua pupula tauaso ma ua savavali pipili,", "The blind receive their sight, and the lame walk,"], ["ua faamamāina lepela ma ua logo tutuli,", "the lepers are cleansed, and the deaf hear,"], ["ua faatutūina o e na oti ma ua folafolaina foi le tala lelei i e matitiva.", "the dead are raised up, and the poor have the gospel preached to them."]]},
  {num:6,words:[["E manuia foi se le tausuai ia te a'u.", "And blessed is he, whosoever shall not be offended in me."]]},
  {num:7,words:[["Ua la o,", "And as they departed,"], ["ona oo ane lea o le lauga a Iesu i le motu o tagata ia Ioane,", "Jesus began to say unto the multitudes concerning John,"], ["Na outou o atu ea i le vao e matamata i ni a? o le u ea ua luluina e le matagi?", "What went ye out into the wilderness to see? A reed shaken with the wind?"]]},
  {num:8,words:[["Pe na outou o lava e matamata i ni a? o le tagata ea ua ofu i ofu malulu? faauta,", "But what went ye out for to see? A man clothed in soft raiment? behold,"], ["o e oofu i ofu malulu o i maota o tupu i latou.", "they that wear soft clothing are in kings' houses."]]},
  {num:9,words:[["A o le a ea na outou o atu e matamata i ai? o le perofeta ea? E moni,", "But what went ye out for to see? A prophet? yea,"], ["ou te fai atu ia te outou,", "I say unto you,"], ["E sili lava ia i le perofeta.", "and more than a prophet."]]},
  {num:10,words:[["Auā o ia lea ua tusi mai i ai,", "For this is he,"], ["Faauta,", "of whom it is written,"], ["ou te auina atu la'u sāvali i ou luma,", "Behold, I send my messenger before thy face,"], ["o le na te teuteua lou ala i ou luma.", "which shall prepare thy way before thee."]]},
  {num:11,words:[["E moni, ou te fai atu ia te outou,", "Verily I say unto you,"], ["e lei tu mai i e na fananau i fafine sē sili ia Ioane le papatiso;", "Among them that are born of women there hath not risen a greater than John the Baptist:"], ["a o lē aupito itiiti i le malo o le lagi, e sili lea ia te ia.", "notwithstanding he that is least in the kingdom of heaven is greater than he."]]},
  {num:12,words:[["Na afua mai i ona po o Ioane le papatiso, ua oo i nei ona po,", "And from the days of John the Baptist until now the kingdom of heaven suffereth violence,"], ["ua taufaoa ai le malo o le lagi, o loo ua avea faamalosi foi e i latou o taufao.", "and the violent take it by force."]]},
  {num:13,words:[["Auā ua vavalo mai le au perofeta uma ma le tulafono, ua oo lava ia Ioane.", "For all the prophets and the law prophesied until John."]]},
  {num:14,words:[["Afai foi tou te loto ina talia,", "And if ye will receive it, this is Elias,"], ["o Elia lava lea na tuu e sau.", "which was for to come."]]},
  {num:15,words:[["O le ua i ai taliga e faalogo ai,", "He that hath ears to hear,"], ["ina faalogo mai ia o ia.", "let him hear."]]},
  {num:16,words:[["Ou te faatusaina i ni a lenei tupulaga?? E tusa ia ma tama iti ua nonofo i malae,", "But whereunto shall I liken this generation? It is like unto children sitting in the markets,"], ["ma valaau atu i a latou aumea,", "and calling unto their fellows,"]]},
  {num:17,words:[["ua faapea atu,", "And saying,"], ["Ua matou faaili atu ia te outou,", "We have piped unto you,"], ["a e tou te lei saasaa mai;", "and ye have not danced;"], ["ua matou tagi aue ia te outou,", "we have mourned unto you,"], ["a e tou te lei taufaitagitu'i mai.", "and ye have not lamented."]]},
  {num:18,words:[["Auā na sau Ioane, e lei 'ai,", "For John came neither eating nor drinking,"], ["e lei inu foi ia;", "and they say,"], ["ona latou fai ane ai lea, Ua ia te ia le temoni.", "He hath a devil."]]},
  {num:19,words:[["Ua sau foi le Atalii o le tagata,", "The Son of man came eating and drinking,"], ["ua 'ai o ia ma inu;", "and they say,"], ["ona latou fai ane ai lea, Faauta,", "Behold a man gluttonous,"], ["o le tagata 'ai tele ma le inu uaina,", "and a winebibber,"], ["o le uo a telona ma ē agasala.", "a friend of publicans and sinners."], ["A e ta'uamiotonuina le poto e ana tama.", "But wisdom is justified of her children."]]},
  {num:20,words:[["Ona faasa'i atu ai lea o ia i aai na fai ai le tele o ona vavega,", "Then began he to upbraid the cities wherein most of his mighty works were done,"], ["auā latou te lei salamo.", "because they repented not:"]]},
  {num:21,words:[["Oi talofa ia te oe Koasini! oi talofa ia te oe Petesaita! auā ana faia i Turo ma Saitonu o vavega na faia ia te outou,", "Woe unto thee, Chorazin! woe unto thee, Bethsaida! for if the mighty works,"], ["po ua leva ona latou salamo i le ie talatala ma le lefulefu.", "which were done in you, had been done in Tyre and Sidon, they would have repented long ago in sackcloth and ashes."]]},
  {num:22,words:[["O lea ou te fai atu ai ia te outou,", "But I say unto you, It shall be more tolerable for Tyre and Sidon at the day of judgment,"], ["E feoloolo Turo ma Saitonu i le aso faamasino ia te outou.", "than for you."]]},
  {num:23,words:[["O oe foi Kapanaumi,", "And thou, Capernaum,"], ["ua faaeaina e oo i le lagi,", "which art exalted unto heaven,"], ["e lafotuina oe i lalo lava i seoli;", "shalt be brought down to hell: for if the mighty works,"], ["auā ana faia i Sotoma o vavega na faia ia te oe,", "which have been done in thee,"], ["po ua tumau ia ua oo i nei ona po.", "had been done in Sodom, it would have remained until this day."]]},
  {num:24,words:[["O lea foi ou te fai atu ai ia te outou,", "But I say unto you, That it shall be more tolerable for the land of Sodom in the day of judgment,"], ["E feoloolo le nuu o Sotoma i le aso faamasino ia te oe.", "than for thee."]]},
  {num:25,words:[["O lea lava itu aso ua fetalai atu ai Iesu,", "At that time Jesus answered and said,"], ["ua faapea atu,", "I thank thee,"], ["Ou te faafetai ia te oe, lo'u Tamā e,", "O Father,"], ["le Alii o le lagi ma le lalolagi,", "Lord of heaven and earth,"], ["ina ua e nanā ia mea i e popoto ma e atamamai,", "because thou hast hid these things from the wise and prudent,"], ["a ua faaalia atu ia mea i tama valevale.", "and hast revealed them unto babes."]]},
  {num:26,words:[["O lea lava,", "Even so,"], ["lo'u Tamā e,", "Father:"], ["auā o lou finagalo lava lea.", "for so it seemed good in thy sight."]]},
  {num:27,words:[["Ua tuuina mai mea uma ia te au e lo'u Tamā;", "All things are delivered unto me of my Father:"], ["e leai foi se tasi ua iloa le Atalii,", "and no man knoweth the Son,"], ["ua na o le Tamā;", "but the Father;"], ["e leai foi se tasi ua iloa le Tamā,", "neither knoweth any man the Father,"], ["ua na o le Atalii,", "save the Son,"], ["ma se ua loto le Atalii e faaali atu i ai.", "and he to whomsoever the Son will reveal him."]]},
  {num:28,words:[["Ia outou o mai ia te au,", "Come unto me,"], ["o outou uma o e tigaina ma mafatia i avega,", "all ye that labour and are heavy laden,"], ["o a'u foi e malolo ai outou.", "and I will give you rest."]]},
  {num:29,words:[["Ia outou amoina la'u amo,", "Take my yoke upon you,"], ["ma ia outou faaa'oa'o ia te au,", "and learn of me;"], ["auā o a'u lē agamalu ma le loto maulalo;", "for I am meek and lowly in heart:"], ["ona maua lea e outou o le malologa mo outou agaga.", "and ye shall find rest unto your souls."]]},
  {num:30,words:[["Auā e avegofie la'u amo,", "For my yoke is easy,"], ["o la'u avega foi e māmā ia.", "and my burden is light."]]},
];
renderVerseSet(mat_ch_11_Verses, 'mat-ch11-verses');

var mat_ch_12_Verses = [
  {num:1,words:[["O ia ona aso ua ui atu ai Iesu i tosaito i le sapati;", "At that time Jesus went on the sabbath day through the corn;"], ["ua fia aai foi ona soo,", "and his disciples were an hungred,"], ["ona ooti ai lea e i latou o 'au saito,", "and began to pluck the ears of corn,"], ["ma aai ai.", "and to eat."]]},
  {num:2,words:[["Ua iloa atu e le au faresaio,", "But when the Pharisees saw it,"], ["ona latou faapea atu ai lea ia te ia,", "they said unto him,"], ["Faauta,", "Behold,"], ["ua faia e ou soo le mea e sa ona fai i le sapati.", "thy disciples do that which is not lawful to do upon the sabbath day."]]},
  {num:3,words:[["A ua fetalai atu o ia ia te i latou,", "But he said unto them,"], ["E lei faitaulia ea e outou le mea na faia e Tavita,", "Have ye not read what David did,"], ["ina ua fia 'ai o ia,", "when he was an hungred,"], ["atoa ma i latou sa ia te ia;", "and they that were with him;"]]},
  {num:4,words:[["na ulufale ia i le fale o le Atua,", "How he entered into the house of God,"], ["na 'ai foi o ia areto ua laulauina i luma,", "and did eat the shewbread,"], ["o mea o sa ona 'ai ai o ia,", "which was not lawful for him to eat,"], ["atoa ma i latou sa ia te ia,", "neither for them which were with him,"], ["e gata lava i le au faitaulaga?", "but only for the priests?"]]},
  {num:5,words:[["E lei faitaulia ea foi e outou i le tulafono,", "Or have ye not read in the law,"], ["o sapati uma ua solia ai le sapati e le au faitaulaga i le malumalu,", "how that on the sabbath days the priests in the temple profane the sabbath,"], ["a e le sala i latou?", "and are blameless?"]]},
  {num:6,words:[["Ou te fai atu foi ia te outou,", "But I say unto you,"], ["O iinei le ua sili i le malumalu.", "That in this place is one greater than the temple."]]},
  {num:7,words:[["Ana outou iloa le uiga o lea upu ,", "But if ye had known what this meaneth,"], ["Ou te loto i le alofa,", "I will have mercy,"], ["a e le o le taulaga,", "and not sacrifice,"], ["po ua outou le faasalaina o e le sala.", "ye would not have condemned the guiltless."]]},
  {num:8,words:[["Auā o le Atalii o le tagata, o le Alii lava ia o le sapati.", "For the Son of man is Lord even of the sabbath day."]]},
  {num:9,words:[["Ua maliu ese ia i lea mea,", "And when he was departed thence,"], ["ona ulu atu ai lea o ia i lo latou sunako.", "he went into their synagogue:"]]},
  {num:10,words:[["Faauta foi,", "And,"], ["sa i ai le tagata ua gase lona lima; ona latou fesili mai ai lea ia te ia,", "behold,"], ["ua faapea mai.", "there was a man which had his hand withered."], ["E tatau ea ona faamalolo i le sapati? ina ia latou momoli ia te ia.", "And they asked him, saying, Is it lawful to heal on the sabbath days? that they might accuse him."]]},
  {num:11,words:[["Ona fetalai atu ai lea o ia ia te i latou,", "And he said unto them,"], ["O ai ea so outou e ana le mamoe e tasi,", "What man shall there be among you,"], ["afai foi e paū o ia i le lua i le sapati,", "that shall have one sheep, and if it fall into a pit on the sabbath day,"], ["e le tago ea i ai,", "will he not lay hold on it,"], ["ma avae i luga?", "and lift it out?"]]},
  {num:12,words:[["e le sili lava ea le tagata i le mamoe? o lea e tatau ai ona agalelei i le sapati.", "How much then is a man better than a sheep? Wherefore it is lawful to do well on the sabbath days."]]},
  {num:13,words:[["Ona fetalai atu ai lea o ia i le tagata,", "Then saith he to the man,"], ["Ina faaloaloa ia o lou lima. Ona faaloaloa ai lea e ia,", "Stretch forth thine hand. And he stretched it forth;"], ["ona toe lelei ai lea,", "and it was restored whole,"], ["ua pei o le tasi.", "like as the other."]]},
  {num:14,words:[["A ua o i fafo le au faresaio,", "Then the Pharisees went out,"], ["ona latou taupulepule ai lea ia te ia,", "and held a council against him,"], ["ina ia latou fasioti ia te ia.", "how they might destroy him."]]},
  {num:15,words:[["A ua silafia e Iesu,", "But when Jesus knew it,"], ["ona maliu ese ai lea o ia i lea mea;", "he withdrew himself from thence:"], ["ua mulimuli mai foi ia te ia le motu o tagata e toatele;", "and great multitudes followed him,"], ["ona faamaloloina ai lea e ia o i latou uma;", "and he healed them all;"]]},
  {num:16,words:[["ua matua fetalai atu foi o ia ia te i latou, aua ne'i latou faalaua'i tele ia;", "And charged them that they should not make him known:"]]},
  {num:17,words:[["ina ia taunuu ai le upu a le perofeta o Isaia,", "That it might be fulfilled which was spoken by Esaias the prophet,"], ["ua faapea mai.", "saying,"]]},
  {num:18,words:[["Faauta,", "Behold my servant,"], ["o la'u auauna na ou filifilia,", "whom I have chosen;"], ["o la'u pele o loo fiafia i ai lo'u loto;", "my beloved, in whom my soul is well pleased:"], ["ou te tuuina atu lo'u Agaga i ona luga,", "I will put my spirit upon him,"], ["e faailoa atu e ia le faamasinoga i nuu ese;", "and he shall shew judgment to the Gentiles."]]},
  {num:19,words:[["e le finau ia,", "He shall not strive,"], ["e le alaga foi o ia,", "nor cry;"], ["e le lagona foi lona leo e se tasi i ala.", "neither shall any man hear his voice in the streets."]]},
  {num:20,words:[["E le gagau e ia le u ua gapēpē,", "A bruised reed shall he not break,"], ["e le tinei foi e ia le vavae ua mu itiiti;", "and smoking flax shall he not quench,"], ["seia faamanumalo e ia le faamasinoga.", "till he send forth judgment unto victory."]]},
  {num:21,words:[["O lona igoa foi e faamoemoe i ai nuu ese.", "And in his name shall the Gentiles trust."]]},
  {num:22,words:[["Ona aumaia lea ia te ia o le tagata ua uluitinoina e le temoni,", "Then was brought unto him one possessed with a devil,"], ["o le tauaso foi o ia ma gūgū;", "blind,"], ["ona faamaloloina ai lea e ia o ia,", "and dumb: and he healed him,"], ["ona tautala ai lea ma vaai lē sa tauaso ma gūgū.", "insomuch that the blind and dumb both spake and saw."]]},
  {num:23,words:[["Ona taufaiofo ai lea o le motu o tagata uma,", "And all the people were amazed,"], ["ua faapea ane,", "and said,"], ["E le o le atalii ea lenei o Tavita?", "Is not this the son of David?"]]},
  {num:24,words:[["A ua lagona e le au faresaio,", "But when the Pharisees heard it,"], ["ona latou fai ane ai lea,", "they said,"], ["Aua le se anoa Pelesepulo le alii o temoni,", "This fellow doth not cast out devils,"], ["e le tulia e lena tagata o Temoni.", "but by Beelzebub the prince of the devils."]]},
  {num:25,words:[["A ua silafia e Iesu o latou manatunatu,", "And Jesus knew their thoughts,"], ["ona fetalai atu ai lea o ia ia te i latou,", "and said unto them,"], ["O malo uma ua fevaevaeai e faaumatia ia;", "Every kingdom divided against itself is brought to desolation;"], ["o aai uma foi po o aiga e fevaevaeai e lē tumau ia.", "and every city or house divided against itself shall not stand:"]]},
  {num:26,words:[["Afai foi e tulia e Satani ia Satani,", "And if Satan cast out Satan,"], ["ona fevaevaeai lea o ia ia te ia;", "he is divided against himself;"], ["pe faapefea foi ona tumau o lona malo?", "how shall then his kingdom stand?"]]},
  {num:27,words:[["Afai foi o Pelesepulo ou te tulia ai e a'u temoni,", "And if I by Beelzebub cast out devils,"], ["po o ai ua tulia ai temoni e a outou fanau? O le mea lea e fai ai i latou ma faamasino ia te outou.", "by whom do your children cast them out? therefore they shall be your judges."]]},
  {num:28,words:[["A e afai o le Agaga o le Atua ou te tulia ai e a'u o temoni,", "But if I cast out devils by the Spirit of God,"], ["ua oo mai lava ia te outou le malo o le Atua.", "then the kingdom of God is come unto you."]]},
  {num:29,words:[["E mafai faapefea se tasi ona ulu atu i le fale o le tagata malosi,", "Or else how can one enter into a strong man's house,"], ["ma vete ana mea? seia muai fusifusia le tagata malosi,", "and spoil his goods,"], ["i le vete ai lona fale.", "except he first bind the strong man? and then he will spoil his house."]]},
  {num:30,words:[["O se le 'au ia te au, e 'au ese lea ia te au;", "He that is not with me is against me;"], ["o se le faaputu faatasi ma a'u, e faataapeape lea.", "and he that gathereth not with me scattereth abroad."]]},
  {num:31,words:[["O le mea lea ou te fai atu ai ia te outou,", "Wherefore I say unto you,"], ["O agasala uma ma upu leaga e faamagaloina ia i tagata; a o le upu leaga i le Agaga,", "All manner of sin and blasphemy shall be forgiven unto men:"], ["e le faamagaloina lea i tagata.", "but the blasphemy against the Holy Ghost shall not be forgiven unto men."]]},
  {num:32,words:[["Ai sē fai upu i le Atalii o le tagata,", "And whosoever speaketh a word against the Son of man, it shall be forgiven him:"], ["e faamagaloina lea;", "but whosoever speaketh against the Holy Ghost,"], ["a o lē fai upu i le Agaga Paia,", "it shall not be forgiven him,"], ["e le faamagaloina lea i le olaga nei po o lē atali.", "neither in this world, neither in the world to come."]]},
  {num:33,words:[["Ia outou ta'ua le laau e lelei,", "Either make the tree good,"], ["ia lelei foi ma ona fua;", "and his fruit good;"], ["a le o lea, ia outou ta'ua le laau e leaga,", "or else make the tree corrupt,"], ["ia leaga foi ma ona fua;", "and his fruit corrupt:"], ["auā o ona fua ua iloga ai le laau.", "for the tree is known by his fruit."]]},
  {num:34,words:[["Fanau a gata feai e,", "O generation of vipers,"], ["outou o loo leaga,", "how can ye, being evil,"], ["e mafaia faapefea ona outou upu lelei? auā o le tele o mea i le loto e tautala mai ai le gutu.", "speak good things? for out of the abundance of the heart the mouth speaketh."]]},
  {num:35,words:[["Ua au mai mea lelei e le tagata amio lelei i mea lelei ua teu i lona loto; o le tagata amio leaga foi,", "A good man out of the good treasure of the heart bringeth forth good things:"], ["ua au mai mea leaga i mea leaga ua teu i lona loto.", "and an evil man out of the evil treasure bringeth forth evil things."]]},
  {num:36,words:[["A ou te fai atu ia te outou,", "But I say unto you,"], ["o upu faatauvaa uma e faia e tagata,", "That every idle word that men shall speak,"], ["latou te talatala atu ai le tala i le aso faamasino.", "they shall give account thereof in the day of judgment."]]},
  {num:37,words:[["Auā o au upu e ta'uamiotonuina ai oe,", "For by thy words thou shalt be justified,"], ["o au upu foi e faasalaina ai oe.", "and by thy words thou shalt be condemned."]]},
  {num:38,words:[["Ona tali mai ai lea o isi o le au tusiupu ma le au faresaio,", "Then certain of the scribes and of the Pharisees answered,"], ["ua faapea mai,", "saying,"], ["Le a'oa'o e,", "Master,"], ["ua matou fia iloa se faailoga ia te oe.", "we would see a sign from thee."]]},
  {num:39,words:[["A ua tali atu o ia,", "But he answered and said unto them,"], ["ua faapea atu ia te i latou,", "An evil and adulterous generation seeketh after a sign;"], ["O le tupulaga leaga ma le mulilulua ua latou sailia mai se faailoga; a e leai se faailoga e avatua i ai,", "and there shall no sign be given to it,"], ["ua na o le faailoga o Iona le perofeta.", "but the sign of the prophet Jonas:"]]},
  {num:40,words:[["Auā e pei o Iona sa i le manava o le i'a tele i ao e tolu ma po e tolu,", "For as Jonas was three days and three nights in the whale's belly;"], ["e faapea foi ona i ai o le Atalii o le tagata i lalo i le eleele i ao e tolu ma po e tolu.", "so shall the Son of man be three days and three nights in the heart of the earth."]]},
  {num:41,words:[["E tutū mai tagata o Nineva i le faamasinoga faatasi ma le tupulaga nei,", "The men of Nineveh shall rise in judgment with this generation,"], ["e faasala i ai;", "and shall condemn it:"], ["auā na latou salamo i le tala'iga a Iona;", "because they repented at the preaching of Jonas; and,"], ["faauta foi,", "behold,"], ["o iinei lē sili ia Iona.", "a greater than Jonas is here."]]},
  {num:42,words:[["E tutū mai faatasi le tupu fafine o le itu i toga ma le tupulaga nei i le faamasinoga,", "The queen of the south shall rise up in the judgment with this generation,"], ["e faasala i ai;", "and shall condemn it:"], ["auā na sau o ia mai le gataaga o le lalolagi e faalogologo i le poto o Solomona;", "for she came from the uttermost parts of the earth to hear the wisdom of Solomon; and,"], ["faauta foi,", "behold,"], ["o iinei lē sili ia Solomona.", "a greater than Solomon is here."]]},
  {num:43,words:[["Pe a alu i fafo i le tagata le agaga leaga,", "When the unclean spirit is gone out of a man,"], ["ona fealuai ai lea o ia i nuu naumati,", "he walketh through dry places,"], ["ua saili se malologa,", "seeking rest,"], ["a e le maua.", "and findeth none."]]},
  {num:44,words:[["Ona faapea ane ai lea o ia,", "Then he saith,"], ["Ou te foi atu i lo'u fale na ou sau ai;", "I will return into my house from whence I came out;"], ["ua alu i ai,", "and when he is come, he findeth it empty,"], ["ona iloa ai lea ua tuufua,", "swept,"], ["ua uma foi ona tafitafi ma teuteu.", "and garnished."]]},
  {num:45,words:[["Ona alu ai lea o ia,", "Then goeth he,"], ["ua na aumaia isi agaga e toafitu e sili lo latou leaga i lona,", "and taketh with himself seven other spirits more wicked than himself,"], ["ona latou ulufale atu ai lea, ua nonofo ai;", "and they enter in and dwell there:"], ["ona sili ai lea o le leaga o le iuga o lea tagata i lona amataga.", "and the last state of that man is worse than the first."], ["E faapea foi ona fai i lenei tupulaga leaga.", "Even so shall it be also unto this wicked generation."]]},
  {num:46,words:[["Ua tautala ia i le motu o tagata,", "While he yet talked to the people,"], ["faauta,", "behold,"], ["ua tutū mai i fafo o lona tinā ma ona uso,", "his mother and his brethren stood without,"], ["ua fia tautala ma ia.", "desiring to speak with him."]]},
  {num:47,words:[["Ona fai mai ai lea o le tasi ia te ia,", "Then one said unto him,"], ["Faauta,", "Behold,"], ["ua tutū mai i fafo lou tinā ma ou uso,", "thy mother and thy brethren stand without,"], ["ua fia tautala ma oe.", "desiring to speak with thee."]]},
  {num:48,words:[["Ona tali atu ai lea o ia, ua faapea atu i le na ta'u mai ia te ia,", "But he answered and said unto him that told him,"], ["O ai ea lo'u tinā? o ai foi o'u uso?", "Who is my mother? and who are my brethren?"]]},
  {num:49,words:[["Ona faaloaloa ai lea e ia o lona aao i ona soo,", "And he stretched forth his hand toward his disciples,"], ["ua faapea atu, Faauta,", "and said,"], ["o lo'u tinā ma o'u uso,", "Behold my mother and my brethren!"]]},
  {num:50,words:[["Auā o lē faia le finagalo o lo'u Tamā o i le lagi,", "For whosoever shall do the will of my Father which is in heaven,"], ["o lo'u uso lea,", "the same is my brother,"], ["ma lo'u tuafafine,", "and sister,"], ["ma lo'u tinā.", "and mother."]]},
];
renderVerseSet(mat_ch_12_Verses, 'mat-ch12-verses');

var mat_ch_13_Verses = [
  {num:1,words:[["O lea lava aso ua ulufafo ai Iesu nai le fale,", "The same day went Jesus out of the house,"], ["ua nofo i lalo e latalata ane i le vai;", "and sat by the sea side."]]},
  {num:2,words:[["ona faapotopoto mai ai lea ia te ia o le motu o tagata e toatele,", "And great multitudes were gathered together unto him,"], ["o le mea lea na maliu ae ai o ia i le vaa,", "so that he went into a ship,"], ["ua nofo ai;", "and sat;"], ["ua tutū mai foi le motu o tagata uma i le auvai.", "and the whole multitude stood on the shore."]]},
  {num:3,words:[["Ona fetalai atu lea o ia ia te i latou i mea e tele i faataoto,", "And he spake many things unto them in parables,"], ["ua faapea atu,", "saying,"], ["Faauta,", "Behold,"], ["ua alu atu le tagata lulu saito e lulu ai saito.", "a sower went forth to sow;"]]},
  {num:4,words:[["Ua ia lulu saito,", "And when he sowed,"], ["ua pa'u ai isi i le auala; ona o ane lea o manu felelei,", "some seeds fell by the way side,"], ["ma aai ai.", "and the fowls came and devoured them up:"]]},
  {num:5,words:[["Ua paū foi isi i le mea papa,", "Some fell upon stony places,"], ["e itiiti le eleele sa i ai;", "where they had not much earth:"], ["ona vave tupu ai lea,", "and forthwith they sprung up,"], ["ona o le eleele ina itiiti;", "because they had no deepness of earth:"]]},
  {num:6,words:[["ua alu ae le la,", "And when the sun was up,"], ["ua velasia;", "they were scorched;"], ["ona magumagu ai lea,", "and because they had no root,"], ["ona ua leai ni aa.", "they withered away."]]},
  {num:7,words:[["Ua paū foi isi i le vao tuitui,", "And some fell among thorns;"], ["ua tutupu ae foi le vao tuitui,", "and the thorns sprung up,"], ["ona fetinaiina ai lea.", "and choked them:"]]},
  {num:8,words:[["A ua paū isi i le eleele lelei,", "But other fell into good ground, and brought forth fruit,"], ["ona fua mai ai lea e taiselau i nisi ma taionogafulu i nisi ma taitolugafulu i nisi.", "some an hundredfold, some sixtyfold, some thirtyfold."]]},
  {num:9,words:[["O le ua i ai taliga e faalogo ai,", "Who hath ears to hear,"], ["ina faalogo mai ia o ia.", "let him hear."]]},
  {num:10,words:[["Ona o mai ai lea o ona soo,", "And the disciples came,"], ["ua faapea mai ia te ia,", "and said unto him,"], ["Se a le mea ua e fetalai atu ai ia te i latou i faataoto?", "Why speakest thou unto them in parables?"]]},
  {num:11,words:[["Ona tali atu ai lea o ia,", "He answered and said unto them,"], ["ua faapea atu ia te i latou, Ua foaiina atu ia te outou ia outou iloa mea lilo a le malo o le lagi,", "Because it is given unto you to know the mysteries of the kingdom of heaven,"], ["a ua le foaiina atu ia te i latou.", "but to them it is not given."]]},
  {num:12,words:[["Auā o le ua i ai mea,", "For whosoever hath,"], ["e foaiina atu ia te ia,", "to him shall be given,"], ["e atili tele ai ana mea;", "and he shall have more abundance:"], ["a o se le i ai mea,", "but whosoever hath not,"], ["e aveeseina foi ia te ia le mea ua ia te ia.", "from him shall be taken away even that he hath."]]},
  {num:13,words:[["O le mea lea ou te tautala atu ai ia te i latou i faataoto,", "Therefore speak I to them in parables:"], ["auā o lo latou vaai latou te le vaai ai,", "because they seeing see not;"], ["o lo latou faalogo foi, latou te le faalogo ai,", "and hearing they hear not,"], ["pe lagona.", "neither do they understand."]]},
  {num:14,words:[["Ua taunuu ai ia te i latou le valoaga a Isaia,", "And in them is fulfilled the prophecy of Esaias,"], ["ua faapea mai,", "which saith,"], ["E faalogo lava outou,", "By hearing ye shall hear,"], ["a e tou te le lagona;", "and shall not understand;"], ["e matuā vaavaai foi outou,", "and seeing ye shall see,"], ["a e tou te le iloa.", "and shall not perceive:"]]},
  {num:15,words:[["Auā ua mafiafia loto o lenei nuu,", "For this people's heart is waxed gross,"], ["ma ua faalogo gata o latou taliga i faalogo,", "and their ears are dull of hearing,"], ["ua moeiini foi o latou mata;", "and their eyes they have closed;"], ["ne'i vaai o latou mata,", "lest at any time they should see with their eyes, and hear with their ears,"], ["ma faalogo o latou taliga,", "and should understand with their heart,"], ["ma lagona o latou loto ma liliuina i latou,", "and should be converted,"], ["ma ou faamaloloina i latou.", "and I should heal them."]]},
  {num:16,words:[["Amuia o outou mata,", "But blessed are your eyes,"], ["auā ua vaavaai;", "for they see:"], ["ma o outou taliga,", "and your ears,"], ["auā ua faalogo;", "for they hear."]]},
  {num:17,words:[["auā e moni,", "For verily I say unto you,"], ["ou te fai atu ia te outou,", "That many prophets and righteous men have desired to see those things which ye see,"], ["E toatele perofeta ma tagata amiotonu sa naunau i le fia iloa o mea ua outou vaai i ai, a e lei iloa;", "and have not seen them;"], ["na latou fia faalogo foi i mea ua outou faalogo i ai,", "and to hear those things which ye hear,"], ["a e lei faalogo ai lava.", "and have not heard them."]]},
  {num:18,words:[["O lenei, ina faalogologo mai ia outou i le faataoto i le tagata lulu saito.", "Hear ye therefore the parable of the sower."]]},
  {num:19,words:[["A faalogo se tasi i le upu o le malo,", "When any one heareth the word of the kingdom,"], ["a e le lagona,", "and understandeth it not,"], ["ona alu ane ai lea o le ua leaga, ua fao le mea sa luluina i lona loto;", "then cometh the wicked one,"], ["o le mea lea sa luluina i le auala.", "and catcheth away that which was sown in his heart. This is he which received seed by the way side."]]},
  {num:20,words:[["A o le mea sa luluina i le mea papa,", "But he that received the seed into stony places,"], ["o le tagata lea ua faalogo i le upu,", "the same is he that heareth the word,"], ["ona talia loa lea ma le fiafia;", "and anon with joy receiveth it;"]]},
  {num:21,words:[["a ua leai ni aa ia te ia,", "Yet hath he not root in himself,"], ["ua faaletumau ia;", "but dureth for a while:"], ["auā pe a tupu le puapuaga, po o le sauaga ona o le upu,", "for when tribulation or persecution ariseth because of the word,"], ["ona tausuai loa lea o ia.", "by and by he is offended."]]},
  {num:22,words:[["O le mea sa luluina i le vao tuitui,", "He also that received seed among the thorns is he that heareth the word;"], ["o ia lea ua faalogo i le upu,", "and the care of this world,"], ["a o le loto popole i mea a lenei lalolagi,", "and the deceitfulness of riches,"], ["ma le pepelo o le oa ua fetinaiina ai le upu,", "choke the word,"], ["ona le fua mai lava lea.", "and he becometh unfruitful."]]},
  {num:23,words:[["A o le mea sa luluina i le eleele lelei,", "But he that received seed into the good ground is he that heareth the word,"], ["o ia lea ua faalogo i le upu,", "and understandeth it;"], ["ma lagona ai;", "which also beareth fruit,"], ["ua fua mai lava ia,", "and bringeth forth,"], ["e taiselau i nisi,", "some an hundredfold,"], ["e taiono gafulu i nisi,", "some sixty,"], ["e taitolugafulu foi i nisi.", "some thirty."]]},
  {num:24,words:[["Ua sauni atu e ia le tasi faataoto ia te i latou,", "Another parable put he forth unto them,"], ["ua faapea atu,", "saying,"], ["Ua faatusaina le malo o le lagi i le tagata ua luluina le saito lelei i lona fanua;", "The kingdom of heaven is likened unto a man which sowed good seed in his field:"]]},
  {num:25,words:[["ua momoe tagata,", "But while men slept,"], ["ona alu ane ai lea o le ua ita mai ia te ia, ua na luluina le titania i totonu o le saito,", "his enemy came and sowed tares among the wheat,"], ["ona alu ese ai lea o ia.", "and went his way."]]},
  {num:26,words:[["Ua totogo ae le saito,", "But when the blade was sprung up,"], ["ma fua mai,", "and brought forth fruit,"], ["ona iloa ai lea o le titania.", "then appeared the tares also."]]},
  {num:27,words:[["Ona o mai ai lea o auauna a le matai o le aiga, ua faapea mai ia te ia,", "So the servants of the householder came and said unto him,"], ["Le alii e,", "Sir,"], ["e le o le saito lelei ea na e luluina i lou fanua? O lenei, pe naifea nei titania?", "didst not thou sow good seed in thy field? from whence then hath it tares?"]]},
  {num:28,words:[["Ona fai atu ai lea o ia ia te i latou,", "He said unto them,"], ["Ua fai lenei mea e se tagata ua ita mai. Ona fai mai ai lea o auauna ia te ia,", "An enemy hath done this. The servants said unto him,"], ["E te finagalo ea matou te o atu e veleeseina ia mea?", "Wilt thou then that we go and gather them up?"]]},
  {num:29,words:[["A ua fai atu ia,", "But he said,"], ["Aua;", "Nay; lest while ye gather up the tares,"], ["ina ne'i outou liai ma le saito pe a outou vele ese le titania.", "ye root up also the wheat with them."]]},
  {num:30,words:[["Tuu ia, ia tupu lua pea seia oo i le seleselega;", "Let both grow together until the harvest:"], ["a oo atu i ona po e selesele ai,", "and in the time of harvest I will say to the reapers,"], ["ou te fai atu ai i e selesele, Ia outou muai faapotopoto mai le titania,", "Gather ye together first the tares,"], ["ma outou fusia i fusi e susunu ai;", "and bind them in bundles to burn them:"], ["a o le saito, tou te faaputuina lea i lo'u fale saito.", "but gather the wheat into my barn."]]},
  {num:31,words:[["Ua sauni atu e ia le tasi faataoto ia te i latou,", "Another parable put he forth unto them,"], ["ua faapea atu,", "saying,"], ["E tusa le malo o le lagi ma le fua o le sinapi,", "The kingdom of heaven is like to a grain of mustard seed,"], ["na ave e le tasi tagata,", "which a man took,"], ["ma totō i lona fanua;", "and sowed in his field:"]]},
  {num:32,words:[["e itiiti lava ia i fua o laau uma;", "Which indeed is the least of all seeds:"], ["pe a uma ona tupu,", "but when it is grown,"], ["e sili ia i laau afu, e iu ina fai ma laau tele,", "it is the greatest among herbs,"], ["e o mai ai manu felelei,", "and becometh a tree,"], ["ma latou momoe i ona la.", "so that the birds of the air come and lodge in the branches thereof."]]},
  {num:33,words:[["Ua fetalai atu e ia le tasi faataoto ia te i latou,", "Another parable spake he unto them;"], ["E tusa le malo o le lagi ma le mea faafefete,", "The kingdom of heaven is like unto leaven,"], ["na ave e le fafine,", "which a woman took,"], ["ma tuu i totonu o le falaoa e tolu tumu,", "and hid in three measures of meal,"], ["ua oo ina faafefeteina uma ai.", "till the whole was leavened."]]},
  {num:34,words:[["Ua fealai atu Iesu ia mea uma i le motu o tagata i faataoto,", "All these things spake Jesus unto the multitude in parables;"], ["ua na o faataoto na fetalai atu ai o ia ia te i latou.", "and without a parable spake he not unto them:"]]},
  {num:35,words:[["Ina ia taunuu ai o le upu a le perofeta,", "That it might be fulfilled which was spoken by the prophet,"], ["ua faapea mai,", "saying,"], ["Ou te tautala atu i faataoto,", "I will open my mouth in parables;"], ["ou te ta'u atu mea na lilo talu ona faavaeina o le lalolagi.", "I will utter things which have been kept secret from the foundation of the world."]]},
  {num:36,words:[["Ona tuuna ai lea e Iesu o le motu o tagata,", "Then Jesus sent the multitude away,"], ["ua ulufale atu ai i le fale;", "and went into the house:"], ["ona o mai ai lea ia te ia o ona soo,", "and his disciples came unto him,"], ["ua faapea mai,", "saying,"], ["Ia e faamatala mai ia te i matou le faataoto i le titania i le fanua.", "Declare unto us the parable of the tares of the field."]]},
  {num:37,words:[["Ona tali atu ai lea o ia, ua faapea atu ia te i latou,", "He answered and said unto them,"], ["O lē lulu le saito lelei, o le Atalii lea o le tagata;", "He that soweth the good seed is the Son of man;"]]},
  {num:38,words:[["a o le fanua, o le lalolagi lea;", "The field is the world;"], ["o le saito lelei, o tagata ia o le malo;", "the good seed are the children of the kingdom;"], ["o le titania, o le fanau ia a le ua leaga;", "but the tares are the children of the wicked one;"]]},
  {num:39,words:[["o le ua ita mai na na luluina ia mea, o le tiapolo lea;", "The enemy that sowed them is the devil;"], ["o le seleselega, o le gataaga lea o le lalolagi;", "the harvest is the end of the world;"], ["o e selesele, o agelu ia.", "and the reapers are the angels."]]},
  {num:40,words:[["O lea e pei ona faaputuina ai o le titania, ma susunuina i le afi,", "As therefore the tares are gathered and burned in the fire;"], ["e faapea foi ona faia i le gataaga o lenei lalolagi.", "so shall it be in the end of this world."]]},
  {num:41,words:[["E aauina atu e le Atalii o le tagata ana agelu,", "The Son of man shall send forth his angels, and they shall gather out of his kingdom all things that offend,"], ["latou te faapotopotoina nai lona malo mea uma e tausuai ai ma ē amio leaga.", "and them which do iniquity;"]]},
  {num:42,words:[["E lafoina i latou i totonu o le ogāumu aasa;", "And shall cast them into a furnace of fire:"], ["e i ai le tagiaue ma le lilivau o nifo.", "there shall be wailing and gnashing of teeth."]]},
  {num:43,words:[["Ona pupula ai lea o e amiotonu e pei o le la i le malo o lo latou Tamā. O le ua i ai taliga e faalogo ai,", "Then shall the righteous shine forth as the sun in the kingdom of their Father. Who hath ears to hear,"], ["ina faalogo mai ia o ia.", "let him hear."]]},
  {num:44,words:[["E tusa foi le malo o le lagi i le oa ua natia i le fanua;", "Again,"], ["ua iloa e le tasi,", "the kingdom of heaven is like unto treasure hid in a field;"], ["ona nanā ai lea e ia;", "the which when a man hath found,"], ["ua alu foi ma le fiafia,", "he hideth,"], ["ma faatau atu ana mea uma,", "and for joy thereof goeth and selleth all that he hath,"], ["i le faatau a'i mai lea fanua.", "and buyeth that field."]]},
  {num:45,words:[["E tusa foi le malo o le lagi ma le tagata faatauoa,", "Again, the kingdom of heaven is like unto a merchant man,"], ["ua sailiili penina lelei;", "seeking goodly pearls:"]]},
  {num:46,words:[["ua iloa e ia le tasi penina tau tele,", "Who,"], ["ona alu ai lea o ia,", "when he had found one pearl of great price,"], ["ua faatau atu ana mea uma,", "went and sold all that he had,"], ["i le faatau a'i mai.", "and bought it."]]},
  {num:47,words:[["E tusa foi le malo o le lagi ma le upega ua lafo i le vai,", "Again, the kingdom of heaven is like unto a net,"], ["ua maua ai i'a eseese uma.", "that was cast into the sea, and gathered of every kind:"]]},
  {num:48,words:[["Ua tumu,", "Which, when it was full,"], ["ona latou toso ae ai lea i le matafaga,", "they drew to shore,"], ["ua nonofo ma fafao i'a lelei i ola,", "and sat down,"], ["a o i'a leaga ua lafoai.", "and gathered the good into vessels, but cast the bad away."]]},
  {num:49,words:[["E faapea foi i le gataaga o le lalolagi;", "So shall it be at the end of the world: the angels shall come forth,"], ["e o atu le au agelu e vavae ese i e amio leaga ma e amiotonu,", "and sever the wicked from among the just,"]]},
  {num:50,words:[["ona latou lafoina lea ia te i latou i le ogāumu aasa;", "And shall cast them into the furnace of fire:"], ["e i ai le tagiaue ma le lilivau o nifo.", "there shall be wailing and gnashing of teeth."]]},
  {num:51,words:[["Ona fetalai atu lea o Iesu ia te i latou,", "Jesus saith unto them,"], ["Ua outou lagona ea nei mea uma? Ua latou fai mai ia te ia,", "Have ye understood all these things? They say unto him,"], ["Ioe,", "Yea,"], ["le Alii e.", "Lord."]]},
  {num:52,words:[["Ona fetalai atu lea o ia ia te i latou, O lenei,", "Then said he unto them,"], ["o tusiupu uma o e ua a'oa'oina i le malo o le lagi,", "Therefore every scribe which is instructed unto the kingdom of heaven is like unto a man that is an householder,"], ["e tusa i latou ma le matai o le aiga, ua au mai mea fou ma mea tuai mai lona fale oloa.", "which bringeth forth out of his treasure things new and old."]]},
  {num:53,words:[["Ua faaiu e Iesu nei faataoto,", "And it came to pass, that when Jesus had finished these parables,"], ["ona maliu ese ai lea o ia i lea mea.", "he departed thence."]]},
  {num:54,words:[["Ua oo atu ia i lona lava nuu,", "And when he was come into his own country,"], ["ona a'oa'o atu ai lea o ia ia te i latou i lo latou sunako;", "he taught them in their synagogue,"], ["ua latou taufaiofo ai,", "insomuch that they were astonished, and said,"], ["ua faapea ane,", "Whence hath this man this wisdom,"], ["Po o fea na maua ai e lenei tagata lenei poto ma ia vavega?", "and these mighty works?"]]},
  {num:55,words:[["E le o le atalii ea lenei o le tufuga? e le o Maria ea le igoa o lona tinā,", "Is not this the carpenter's son? is not his mother called Mary? and his brethren,"], ["o ona uso foi o Iakopo,", "James,"], ["ma Iose,", "and Joses,"], ["ma Simona,", "and Simon,"], ["ma Iuta?", "and Judas?"]]},
  {num:56,words:[["E le o ia te i tatou ea ona tuafāfine uma? po o fea foi na maua ai e lenei tagata nei mea uma?", "And his sisters, are they not all with us? Whence then hath this man all these things?"]]},
  {num:57,words:[["Ona latou tausuai ai lea ia te ia.", "And they were offended in him."], ["A ua fetalai atu Iesu ia te i latou,", "But Jesus said unto them,"], ["E leai se perofeta e le mamalu,", "A prophet is not without honour, save in his own country,"], ["ua na o lona lava nuu ma lona aiga e le mamalu ai .", "and in his own house."]]},
  {num:58,words:[["Ua le tele foi ni vavega na na faia i lea mea, ona o lo latou le faatuatua.", "And he did not many mighty works there because of their unbelief."]]},
];
renderVerseSet(mat_ch_13_Verses, 'mat-ch13-verses');

var mat_ch_14_Verses = [
  {num:1,words:[["O ia ona po ua lagona ai e le tupu o Herota le tala ia Iesu;", "At that time Herod the tetrarch heard of the fame of Jesus,"]]},
  {num:2,words:[["ona fai atu lea o ia i ana auauna,", "And said unto his servants,"], ["O Ioane le papatiso lena;", "This is John the Baptist;"], ["ua tu mai o ia i e ua oti;", "he is risen from the dead;"], ["o le mea foi lea ua fai ai vavega e ia.", "and therefore mighty works do shew forth themselves in him."]]},
  {num:3,words:[["Auā na pue e Herota ia Ioane,", "For Herod had laid hold on John,"], ["ua fusifusi foi ia te ia,", "and bound him,"], ["ma tuuina atu o ia i le fale puipui,", "and put him in prison for Herodias' sake,"], ["ona o Herotia le avā a Filipo lona uso.", "his brother Philip's wife."]]},
  {num:4,words:[["Auā na fai atu Ioane ia te ia. E sa ona fai o ia mau avā.", "For John said unto him, It is not lawful for thee to have her."]]},
  {num:5,words:[["Ua ia fia fasioti ia te ia,", "And when he would have put him to death,"], ["a ua mata'u i le motu o tagata,", "he feared the multitude,"], ["auā o la latou taofi o le perofeta ia.", "because they counted him as a prophet."]]},
  {num:6,words:[["Ua oo ina fai le faamanatuga o le aso na fanau mai ai Herota,", "But when Herod's birthday was kept,"], ["na saasaa i o latou luma le tama teine a Herotia,", "the daughter of Herodias danced before them,"], ["na ia faafiafia foi ia Herota.", "and pleased Herod."]]},
  {num:7,words:[["O le mea lea na ia matuā fai atu ai ia te ia ma le augani na te avatu ia te ia se mea na te ole mai ai.", "Whereupon he promised with an oath to give her whatsoever she would ask."]]},
  {num:8,words:[["A o ia,", "And she,"], ["ua faaosoina e lona tinā,", "being before instructed of her mother,"], ["ua fai atu,", "said,"], ["Ia e au mai iinei ia te au le ulu o Ioane le papatiso i se tanoa.", "Give me here John Baptist's head in a charger."]]},
  {num:9,words:[["Ona tiga ai lea o le tupu;", "And the king was sorry:"], ["a ona o le augani,", "nevertheless for the oath's sake,"], ["ma e ua taooto e aai faatasi ma ia,", "and them which sat with him at meat,"], ["ua ia poloai atu e avatua.", "he commanded it to be given her."]]},
  {num:10,words:[["Ona auina atu ai lea e ia se tasi ,", "And he sent,"], ["ua vavae mai le ulu o Ioane i le fale puipui.", "and beheaded John in the prison."]]},
  {num:11,words:[["Ona au mai ai lea o lona ulu i le tanoa,", "And his head was brought in a charger,"], ["ua avane i le teine,", "and given to the damsel:"], ["ua na aveina atu foi i lona tinā.", "and she brought it to her mother."]]},
  {num:12,words:[["Ona o ane ai lea o ona soo,", "And his disciples came,"], ["ua ave le tino,", "and took up the body,"], ["na tanu ai; ua latou o mai foi,", "and buried it,"], ["ma ta'u mai ia Iesu.", "and went and told Jesus."]]},
  {num:13,words:[["Ua faafofoga i ai Iesu,", "When Jesus heard of it,"], ["ona maliu ese ai lea o ia i lea mea i le vaa i le mea tuufua ua na o ia. Ua faalogo ai le motu o tagata,", "he departed thence by ship into a desert place apart:"], ["ona latou mulimuli atu ai lea ia te ia,", "and when the people had heard thereof,"], ["ua ui a uta mai aai.", "they followed him on foot out of the cities."]]},
  {num:14,words:[["Ua maliu atu Iesu,", "And Jesus went forth,"], ["ua na silafia le motu o tagata e toatele,", "and saw a great multitude,"], ["ona mutimuti vale ai lea o lona alofa ia te i latou,", "and was moved with compassion toward them,"], ["ua faamalolo foi e ia o latou ma'i.", "and he healed their sick."]]},
  {num:15,words:[["Ua oo i le afiafi,", "And when it was evening,"], ["ona o mai ai lea o ona soo ia te ia,", "his disciples came to him,"], ["ua faapea mai,", "saying,"], ["O le mea tuufua lenei,", "This is a desert place, and the time is now past;"], ["ua leva foi le aso;", "send the multitude away,"], ["ia e tuuina atu le motu o tagata,", "that they may go into the villages,"], ["ina ia latou o i aai e faatau ni mea e 'ai mā latou.", "and buy themselves victuals."]]},
  {num:16,words:[["A ua fetalai atu Iesu ia te i latou,", "But Jesus said unto them,"], ["E le aoga ona latou o;", "They need not depart;"], ["ia outou avane ni mea latou te aai ai.", "give ye them to eat."]]},
  {num:17,words:[["Ona latou fai mai lea ia te ia,", "And they say unto him,"], ["E leai ni a tatou mea iinei,", "We have here but five loaves,"], ["ua na o areto e limagafua ma i'a e lua lau.", "and two fishes."]]},
  {num:18,words:[["Ua fetalai atu o ia,", "He said,"], ["Aumaia iinei ia te au.", "Bring them hither to me."]]},
  {num:19,words:[["Ona fetalai atu ai lea o ia i le motu o tagata ia latou taooto i le mutia. Ona tago lea o ia i areto e limagafua ma i'a e lua lau,", "And he commanded the multitude to sit down on the grass,"], ["ua tepa ae i le lagi,", "and took the five loaves, and the two fishes,"], ["ua faafetai;", "and looking up to heaven,"], ["ua ia tofitofi foi i areto,", "he blessed,"], ["ma avatu i le au soo,", "and brake, and gave the loaves to his disciples,"], ["ona avatu ai lea e le au soo i le motu o tagata.", "and the disciples to the multitude."]]},
  {num:20,words:[["Ona aai ai lea o i latou uma lava,", "And they did all eat,"], ["ua maoona; ua latou fu'e foi toe 'aiga,", "and were filled:"], ["ua tutumu ai ato e sefulu ma le lua.", "and they took up of the fragments that remained twelve baskets full."]]},
  {num:21,words:[["O i latou foi na aai pe limagaafe o tane,", "And they that had eaten were about five thousand men,"], ["a e lei faitaulia fafine ma tama iti.", "beside women and children."]]},
  {num:22,words:[["Ona uunai loa lea o Iesu i ona soo e o ae i le vaa,", "And straightway Jesus constrained his disciples to get into a ship,"], ["e muamua atu ia te ia i le tasi itu,", "and to go before him unto the other side,"], ["seia tuuina atu e ia le motu o tagata ia ō.", "while he sent the multitudes away."]]},
  {num:23,words:[["Ua tuuina atu e ia le motu o tagata ia ō,", "And when he had sent the multitudes away,"], ["ona maliu ae lea ua na o ia i le mauga e tatalo. Ua oo i le afiafi,", "he went up into a mountain apart to pray: and when the evening was come,"], ["ua na o ia sa i ai.", "he was there alone."]]},
  {num:24,words:[["A o le vaa ua i totonu o le vasa ua felafoaiina i le sou;", "But the ship was now in the midst of the sea, tossed with waves:"], ["auā ua agi mai i luma le matagi.", "for the wind was contrary."]]},
  {num:25,words:[["Ua maliu atu Iesu ia te i latou i le leoleoga e fa o le po,", "And in the fourth watch of the night Jesus went unto them,"], ["ua savali i luga o le vai.", "walking on the sea."]]},
  {num:26,words:[["Ua iloa mai e le au soo o ia ua savali i luga o le vai,", "And when the disciples saw him walking on the sea,"], ["ona latou atuatuvale ai lea,", "they were troubled,"], ["ua faapea ane,", "saying,"], ["O le aitu;", "It is a spirit;"], ["ona latou uio ai lea i le matatau.", "and they cried out for fear."]]},
  {num:27,words:[["Ona fetalai atu loa lea o Iesu ia te i latou,", "But straightway Jesus spake unto them,"], ["ua faapea atu,", "saying,"], ["Ia outou loto tetele;", "Be of good cheer;"], ["o a'u lava,", "it is I;"], ["aua tou te matatau.", "be not afraid."]]},
  {num:28,words:[["Ua tali mai Peteru ia te ia, ua faapea mai,", "And Peter answered him and said,"], ["Le Alii e,", "Lord,"], ["afai o oe,", "if it be thou,"], ["ia e fetalai mai ia te au, ou te alu atu ia te oe i luga o le vai.", "bid me come unto thee on the water."]]},
  {num:29,words:[["Ona fetalai atu ai lea o ia,", "And he said,"], ["Ina sau ia.", "Come."], ["Ona alu ifo ai lea o Peteru nai le vaa,", "And when Peter was come down out of the ship, he walked on the water,"], ["ua savali i luga o le vai e alu ia Iesu.", "to go to Jesus."]]},
  {num:30,words:[["Ua vaai ia i le matagi ua tetele,", "But when he saw the wind boisterous,"], ["ona fefe ai lea;", "he was afraid;"], ["ona afua ai lea ona goto,", "and beginning to sink,"], ["ua alaga,", "he cried,"], ["ua faapea mai,", "saying,"], ["Le Alii e,", "Lord,"], ["ia e faaola mai ia te au.", "save me."]]},
  {num:31,words:[["Ona aapa atu loa lea e Iesu o lona aao,", "And immediately Jesus stretched forth his hand,"], ["ua tago ia te ia,", "and caught him,"], ["ua faapea atu ia te ia,", "and said unto him,"], ["O oe na lē faatuatua itiiti,", "O thou of little faith,"], ["se a le mea ua e masalosalo vale ai?", "wherefore didst thou doubt?"]]},
  {num:32,words:[["Ona la o ae lea i le vaa,", "And when they were come into the ship,"], ["ona malū ai lea o le matagi.", "the wind ceased."]]},
  {num:33,words:[["Ona o mai ai lea o e na i le vaa, ua ifo mai ia te ia,", "Then they that were in the ship came and worshipped him,"], ["ua faapea mai,", "saying,"], ["E moni, o oe lava o le Alo o le Atua.", "Of a truth thou art the Son of God."]]},
  {num:34,words:[["Ua o atu i latou i le tasi itu,", "And when they were gone over,"], ["ua oo i le nuu o Kenesareta.", "they came into the land of Gennesaret."]]},
  {num:35,words:[["Ua iloa mai o ia e tagata o lea nuu,", "And when the men of that place had knowledge of him,"], ["ona latou feau atu ai lea i lea itu uma lava,", "they sent out into all that country round about,"], ["ua latou au mai ai ia te ia o e mamai uma lava;", "and brought unto him all that were diseased;"]]},
  {num:36,words:[["ma ua latou aioi mai ia te ia, tau lava ina latou papai i le tuupao o lona ofu;", "And besought him that they might only touch the hem of his garment:"], ["ua faamaloloina foi o i latou uma e na papai mai i ai.", "and as many as touched were made perfectly whole."]]},
];
renderVerseSet(mat_ch_14_Verses, 'mat-ch14-verses');

var mat_ch_15_Verses = [
  {num:1,words:[["Ona o mai ai lea ia Iesu o tusiupu ma faresaio mai Ierusalema,", "Then came to Jesus scribes and Pharisees, which were of Jerusalem,"], ["ua faapea mai,", "saying,"]]},
  {num:2,words:[["Se a le mea ua soli ai e ou soo le uputuu a ē anamua? auā ua le fafano o latou lima pe a latou aai.", "Why do thy disciples transgress the tradition of the elders? for they wash not their hands when they eat bread."]]},
  {num:3,words:[["A ua tali atu ia, ua faapea atu ia te i latou,", "But he answered and said unto them,"], ["Se a le mea ua soli ai e outou foi le poloaiga a le Atua i a outou uputuu?", "Why do ye also transgress the commandment of God by your tradition?"]]},
  {num:4,words:[["Auā ua poloai mai le Atua,", "For God commanded,"], ["ua faapea mai,", "saying,"], ["Ia e ava i lou tamā ma lou tinā;", "Honour thy father and mother:"], ["i le ma lea,", "and,"], ["O lē upu leaga i le tamā po o le tinā,", "He that curseth father or mother,"], ["ia fasiotia lava ia.", "let him die the death."]]},
  {num:5,words:[["A ua outou fai mai,", "But ye say,"], ["Ai se fai ane i le tamā po o le tinā,", "Whosoever shall say to his father or his mother,"], ["ai se mea ua ia te au e aoga ia te oe,", "It is a gift,"], ["o le taulaga lea;", "by whatsoever thou mightest be profited by me;"]]},
  {num:6,words:[["ona le toe ava lea o ia i lona tamā po o lona tinā.", "And honour not his father or his mother, he shall be free."], ["Ua faapea ona outou faaleaogaina le poloaiga a le Atua i a outou uputuu.", "Thus have ye made the commandment of God of none effect by your tradition."]]},
  {num:7,words:[["O outou tagata pepelo,", "Ye hypocrites,"], ["e tatau lava ia te outou le valoaga a Isaia,", "well did Esaias prophesy of you,"], ["ua faapea mai,", "saying,"]]},
  {num:8,words:[["Ua faalatalata mai ia te au lenei nuu i o latou gutu,", "This people draweth nigh unto me with their mouth,"], ["ma vivii mai ia te au i oo latou laugutu,", "and honoureth me with their lips;"], ["a o latou loto ua taumamao ia te au.", "but their heart is far from me."]]},
  {num:9,words:[["E tapuai fua mai i latou ia te au i lo latou fai ma mataupu o poloaiga a tagata.", "But in vain they do worship me, teaching for doctrines the commandments of men."]]},
  {num:10,words:[["Ona valaau atu lea o ia i le motu o tagata,", "And he called the multitude,"], ["ua fetalai atu ia te i latou,", "and said unto them,"], ["Faalogo mai ia,", "Hear,"], ["ma ia outou lagona.", "and understand:"]]},
  {num:11,words:[["E le o le mea ua tuu i le gutu e leaga ai le tagata,", "Not that which goeth into the mouth defileth a man;"], ["a o le mea e sau mai le gutu,", "but that which cometh out of the mouth,"], ["o lea ua leaga ai le tagata.", "this defileth a man."]]},
  {num:12,words:[["Ona o mai ai lea o ona soo ia te ia,", "Then came his disciples,"], ["ua fai mai ia te ia,", "and said unto him, Knowest thou that the Pharisees were offended,"], ["Ua e silafia ea ua tiga le au faresaio i lo latou faalogo i lea upu?", "after they heard this saying?"]]},
  {num:13,words:[["A ua tali atu ia,", "But he answered and said,"], ["ua faapea atu,", "Every plant,"], ["O laau uma e lei totōina e lo'u Tamā o i le lagi,", "which my heavenly Father hath not planted,"], ["e liaiina ia.", "shall be rooted up."]]},
  {num:14,words:[["Tuu pea ia i latou,", "Let them alone:"], ["o tauaso i latou e ta'ita'i i e ua tauaso; afai foi e ta'ita'iina le tauaso e le tauaso,", "they be blind leaders of the blind. And if the blind lead the blind,"], ["ona la pauu uma ai lea i le lua.", "both shall fall into the ditch."]]},
  {num:15,words:[["Ona tali mai ai lea o Peteru, ua faapea mai ia te ia,", "Then answered Peter and said unto him,"], ["Ia e faamatala mai ia te i matou lena faataoto.", "Declare unto us this parable."]]},
  {num:16,words:[["Ona fetalai atu ai lea o Iesu,", "And Jesus said,"], ["Tou te le āu lagona foi ea e outou?", "Are ye also yet without understanding?"]]},
  {num:17,words:[["Tou te le āu iloa ea,", "Do not ye yet understand,"], ["o mea uma ua tuu i le gutu, ua oo ia i le manava,", "that whatsoever entereth in at the mouth goeth into the belly,"], ["ona lafoaiina lea i le māliuga?", "and is cast out into the draught?"]]},
  {num:18,words:[["A o mea e sau mai le gutu, ua alu ae ia mai le loto,", "But those things which proceed out of the mouth come forth from the heart;"], ["o mea ia e leaga ai le tagata.", "and they defile the man."]]},
  {num:19,words:[["Auā e alu ae mai le loto o le manatu leaga,", "For out of the heart proceed evil thoughts,"], ["o le fasioti tagata,", "murders,"], ["ole mulilua,", "adulteries,"], ["o le faitaaga,", "fornications,"], ["o le gaoi,", "thefts,"], ["o le molimau pepelo,", "false witness,"], ["ma le upu leaga.", "blasphemies:"]]},
  {num:20,words:[["O mea ia e leaga ai le tagata; a o le 'ai ma lima e lei fafano,", "These are the things which defile a man:"], ["e le o lea e leaga ai le tagata.", "but to eat with unwashen hands defileth not a man."]]},
  {num:21,words:[["Ua maliu ese Iesu i lea mea,", "Then Jesus went thence,"], ["ona oo atu ai lea o ia i le laueleele o Turo ma Saitonu.", "and departed into the coasts of Tyre and Sidon."]]},
  {num:22,words:[["Faauta foi,", "And,"], ["o le fafine o Kanana ua sau mai lea lava itu,", "behold,"], ["ua alaga mai ia te ia,", "a woman of Canaan came out of the same coasts,"], ["ua faapea mai,", "and cried unto him,"], ["Le Alii e,", "saying, Have mercy on me,"], ["le alo o Tavita,", "O Lord,"], ["ia e alofa mai ia te au;", "thou Son of David;"], ["ua leaga lava la'u tama teine i le temoni ua i ai.", "my daughter is grievously vexed with a devil."]]},
  {num:23,words:[["A ua leai se upu na ia tali atu ai ia te ia.", "But he answered her not a word."], ["Ona o mai ai lea o ona soo, ua aioi mai ia te ia,", "And his disciples came and besought him,"], ["ua faapea mai,", "saying,"], ["Ia e tuuina atu ia te ia e alu,", "Send her away;"], ["auā ua mulimuli mai o ia, ma alaga mai ia te i tatou.", "for she crieth after us."]]},
  {num:24,words:[["A ua tali atu ia, ua faapea atu,", "But he answered and said,"], ["E lei auina mai a'u i nisi , a e tau lava o mamoe o le aiga o Isaraelu ua le iloa.", "I am not sent but unto the lost sheep of the house of Israel."]]},
  {num:25,words:[["Ona sau ai lea o ia,", "Then came she and worshipped him,"], ["ua ifo ia te ia,", "saying,"], ["ua faapea mai, Le Alii e,", "Lord,"], ["ia e fesoasoani mai ia te au.", "help me."]]},
  {num:26,words:[["Ona tali atu ai lea o ia,", "But he answered and said,"], ["ua faapea atu, E le tatau ona ave le mea e 'ai a le fanau,", "It is not meet to take the children's bread,"], ["ma lafo i ulī.", "and to cast it to dogs."]]},
  {num:27,words:[["Ona fai mai ai lea o ia,", "And she said,"], ["Le Alii e,", "Truth,"], ["e moni a oe;", "Lord:"], ["auā foi ua aai e ulī o momoi mea ua pauu i laulau a o latou tāula.", "yet the dogs eat of the crumbs which fall from their masters' table."]]},
  {num:28,words:[["Ona tali atu ai lea o Iesu, ua faapea atu ia te ia,", "Then Jesus answered and said unto her,"], ["Funa e,", "O woman,"], ["ua tele lou faatuatua;", "great is thy faith:"], ["e pei o lou manao, ia faapea lava ona faia ia te oe.", "be it unto thee even as thou wilt."], ["Ona malolo ai lea o lana tama teine i lea lava itu aso.", "And her daughter was made whole from that very hour."]]},
  {num:29,words:[["Ua maliu ese Iesu i lea mea,", "And Jesus departed from thence,"], ["ona oo atu ai lea o ia e lata ane i le vai o Kalilaia;", "and came nigh unto the sea of Galilee;"], ["ua maliu ae i le mauga,", "and went up into a mountain,"], ["ua nofo ai i lalo.", "and sat down there."]]},
  {num:30,words:[["Ona o mai ai lea ia te ia o le motu o tagata e toatele,", "And great multitudes came unto him,"], ["ua ia te i latou o e pipili,", "having with them those that were lame,"], ["o e tauaso,", "blind,"], ["o e gūgū,", "dumb,"], ["o e mumutu,", "maimed,"], ["atoa ma nisi e toatele,", "and many others,"], ["ua latou tuu atu ia i latou i vae o Iesu;", "and cast them down at Jesus' feet;"], ["ona faamalolo ai lea e ia o i latou.", "and he healed them:"]]},
  {num:31,words:[["Ona taufaiofo ai lea o le motu o tagata ina ua latou iloa atu o e sa gūgū ua tautala,", "Insomuch that the multitude wondered,"], ["o e sa mumutu ua atoatoa,", "when they saw the dumb to speak,"], ["o e sa pipili ua savavali,", "the maimed to be whole, the lame to walk,"], ["o e sa tauaso foi ua vaai;", "and the blind to see:"], ["ona latou vivii atu ai lea i le Atua o Isaraelu.", "and they glorified the God of Israel."]]},
  {num:32,words:[["Ona valaau atu ai lea o Iesu i ona soo,", "Then Jesus called his disciples unto him,"], ["ua faapea atu,", "and said,"], ["Ou te alofa atu i le motu o tagata,", "I have compassion on the multitude, because they continue with me now three days,"], ["auā o le aso tolu lenei o tatou nonofo ma i latou,", "and have nothing to eat:"], ["e leai foi ni a latou mea e 'ai. Ou te le mafai ona tuuina atu ia te i latou e ō mātelaina,", "and I will not send them away fasting,"], ["ne'i latou lailoa i le ala.", "lest they faint in the way."]]},
  {num:33,words:[["Ona fai mai ai lea o ona soo ia te ia,", "And his disciples say unto him,"], ["Tatou te maua ifea ea i le vao ni areto e tele,", "Whence should we have so much bread in the wilderness,"], ["ina ia maoona ai le motu o tagata ua toatele naua?", "as to fill so great a multitude?"]]},
  {num:34,words:[["Ona fetalai atu ai lea o Iesu ia te i latou,", "And Jesus saith unto them,"], ["E fia ea ni a outou areto? Ona latou fai mai ai lea,", "How many loaves have ye? And they said,"], ["E fitu,", "Seven,"], ["ma nai i'a lāuiti.", "and a few little fishes."]]},
  {num:35,words:[["Ona fetalai atu ai lea o ia i le motu o tagata ia latou taooto i lalo;", "And he commanded the multitude to sit down on the ground."]]},
  {num:36,words:[["ona tago ai lea o ia i areto e fitu ma i'a,", "And he took the seven loaves and the fishes,"], ["ua faafetai,", "and gave thanks,"], ["ma tofitofi,", "and brake them,"], ["ona avatu ai lea e ia i ona soo,", "and gave to his disciples,"], ["ona avatu ai lea e le au soo i le motu o tagata.", "and the disciples to the multitude."]]},
  {num:37,words:[["Ona aai ai lea o i latou uma lava,", "And they did all eat,"], ["ua maoona; ua latou fu'e foi i toe 'aiga,", "and were filled:"], ["ua tutumu ai ete e fitu.", "and they took up of the broken meat that was left seven baskets full."]]},
  {num:38,words:[["O i latou foi na aai e toafagaafe o tane,", "And they that did eat were four thousand men,"], ["a e lei faitaulia fafine ma tama iti.", "beside women and children."]]},
  {num:39,words:[["Ua tuuina atu e ia le motu o tagata e ō,", "And he sent away the multitude,"], ["ona maliu ae ai lea o ia i le vaa,", "and took ship,"], ["ua alu atu i le nuu o Makatala.", "and came into the coasts of Magdala."]]},
];
renderVerseSet(mat_ch_15_Verses, 'mat-ch15-verses');

var mat_ch_16_Verses = [
  {num:1,words:[["Ona o mai ai lea o le au faresaio ma le au satukaio, ua latou faaosooso ia te ia,", "The Pharisees also with the Sadducees came,"], ["ua fai mai ia faaali atu ia te i latou se faailoga mai le lagi.", "and tempting desired him that he would shew them a sign from heaven."]]},
  {num:2,words:[["A ua tali atu o ia,", "He answered and said unto them,"], ["ua faapea atu ia te i latou,", "When it is evening,"], ["A oo i le afiafi ua outou fai ane,", "ye say,"], ["E laofie;", "It will be fair weather:"], ["auā ua mūmū mai le lagi.", "for the sky is red."]]},
  {num:3,words:[["O le taeao foi ua outou fai ane ,", "And in the morning,"], ["E uaga le asō; auā ua mūmū mai,", "It will be foul weather to day:"], ["ma faamalumalu ifo le lagi.", "for the sky is red and lowring."], ["O outou tagata pepelo,", "O ye hypocrites,"], ["ua outou iloa ona mātauina amio a le lagi,", "ye can discern the face of the sky;"], ["a o faailoga o tausaga tou te le mafaia ea?", "but can ye not discern the signs of the times?"]]},
  {num:4,words:[["O le tupulaga leaga ma le mulilulua ua saili mai se faailoga;", "A wicked and adulterous generation seeketh after a sign;"], ["a e leai se faailoga e avatu i ai,", "and there shall no sign be given unto it,"], ["ua na o le faailoga o Iona le perofeta. Ona tuua ai lea e ia o i latou,", "but the sign of the prophet Jonas. And he left them,"], ["ua maliu ese.", "and departed."]]},
  {num:5,words:[["Ona oo atu ai lea o ona soo i le tasi itu,", "And when his disciples were come to the other side,"], ["ua galo ia te i latou ona ave ni areto.", "they had forgotten to take bread."]]},
  {num:6,words:[["Ua fetalai atu Iesu ia te i latou, Ia outou,", "Then Jesus said unto them,"], ["ia matuā 'alo ese i le mea faafefete a le au faresaio ma le au satukaio.", "Take heed and beware of the leaven of the Pharisees and of the Sadducees."]]},
  {num:7,words:[["Ona latou felafolafoai ai lea,", "And they reasoned among themselves,"], ["ua faapea ane,", "saying,"], ["O lana fetalaiga lea ina ua tatou le au mai ni areto.", "It is because we have taken no bread."]]},
  {num:8,words:[["A ua silafia e Iesu,", "Which when Jesus perceived,"], ["ona fetalai atu ai lea o ia ia te i latou,", "he said unto them,"], ["Se a le mea ua outou felafolafoai ai,", "O ye of little faith,"], ["o outou e faatuatua itiiti,", "why reason ye among yourselves,"], ["ina ua le aumaia e outou ni areto?", "because ye have brought no bread?"]]},
  {num:9,words:[["Tou te le āu lagona ea,", "Do ye not yet understand,"], ["tou te le manatua foi i areto e lima ma le toalimagaafe,", "neither remember the five loaves of the five thousand,"], ["pe fia ato na outou fu'e ai?", "and how many baskets ye took up?"]]},
  {num:10,words:[["o areto foi e fitu ma le toafagaafe,", "Neither the seven loaves of the four thousand,"], ["pe fia ete na outou fu'e ai?", "and how many baskets ye took up?"]]},
  {num:11,words:[["E le lagona faapefea outou, e le o le areto na ou fai atu ai ia te outou,", "How is it that ye do not understand that I spake it not to you concerning bread,"], ["ia matuā 'alo ese i le mea faafefete a le au faresaio ma le au satukaio?", "that ye should beware of the leaven of the Pharisees and of the Sadducees?"]]},
  {num:12,words:[["Onā latou lagona ai lea, e le o le mea faafefete o le areto na fetalai atu ai o ia ia matuā alo ese ai,", "Then understood they how that he bade them not beware of the leaven of bread,"], ["a o le mataupu a le au faresaio ma le au satukaio.", "but of the doctrine of the Pharisees and of the Sadducees."]]},
  {num:13,words:[["Ua maliu atu Iesu i le laueleele o Kaisareia Filipo,", "When Jesus came into the coasts of Caesarea Philippi,"], ["ona fesili atu ai lea o ia i ona soo,", "he asked his disciples,"], ["ua faapea atu, Pe se a le upu a tagata ia te au le Atalii o le tagata,", "saying,"], ["po o ai?", "Whom do men say that I the Son of man am?"]]},
  {num:14,words:[["Ona latou fai mai ai lea,", "And they said,"], ["O le upu a isi,", "Some say that thou art John the Baptist:"], ["o oe o Ioane le papatiso;", "some,"], ["a o isi, o Elia,", "Elias;"], ["a o isi,", "and others,"], ["o Ieremia,", "Jeremias,"], ["po o se tasi o le au perofeta.", "or one of the prophets."]]},
  {num:15,words:[["Ona fetalai atu lea o ia ia te i latou, A o outou,", "He saith unto them,"], ["pe se a la outou upu ia te au, po o ai?", "But whom say ye that I am?"]]},
  {num:16,words:[["Ona tali mai ai lea o Simona Peteru,", "And Simon Peter answered and said,"], ["ua faapea mai, O oe o le Keriso,", "Thou art the Christ,"], ["o le Alo o le Atua soifua.", "the Son of the living God."]]},
  {num:17,words:[["Ona tali atu ai lea o Iesu,", "And Jesus answered and said unto him,"], ["ua faapea atu ia te ia,", "Blessed art thou,"], ["Amuia oe Simona Pāiona;", "Simon Bar-jona:"], ["auā e le se tagata na ia faaali atu ai ia te oe,", "for flesh and blood hath not revealed it unto thee,"], ["a o lo'u Tamā o i le lagi.", "but my Father which is in heaven."]]},
  {num:18,words:[["Ou te fai atu nei a'u ia te oe,", "And I say also unto thee,"], ["O Peteru oe,", "That thou art Peter,"], ["ou te ati ae foi la'u ekalesia i luga o lenei papa,", "and upon this rock I will build my church;"], ["e le mafaia foi e faitotoa o seoli ona manumalo i ai.", "and the gates of hell shall not prevail against it."]]},
  {num:19,words:[["Ou te avatu foi ia te oe ki o le malo o le lagi; o se mea foi e te fusifusia i le lalolagi,", "And I will give unto thee the keys of the kingdom of heaven:"], ["e fusifusia foi lea i le lagi;", "and whatsoever thou shalt bind on earth shall be bound in heaven:"], ["o se mea foi e te tālā i le lalolagi, e tatalaina foi lea i le lagi.", "and whatsoever thou shalt loose on earth shall be loosed in heaven."]]},
  {num:20,words:[["Ona vavao atu ai lea e ia i ona soo, aua ne'i latou ta'uta'u atu i se tasi, o ia o Iesu le Keriso.", "Then charged he his disciples that they should tell no man that he was Jesus the Christ."]]},
  {num:21,words:[["O ona po ia na amata ai e Iesu ona faailoa atu i ona soo,", "From that time forth began Jesus to shew unto his disciples,"], ["e tatau ona alu o ia i Ierusalema,", "how that he must go unto Jerusalem,"], ["e faatigaina foi i mea e tele e toeaina ma le au faitaulaga sili, ma le au tusiupu,", "and suffer many things of the elders and chief priests and scribes,"], ["e fasiotia foi o ia,", "and be killed,"], ["e faatuina foi o ia i le aso tolu.", "and be raised again the third day."]]},
  {num:22,words:[["Ona ta'ita'i ane ai lea e Peteru,", "Then Peter took him,"], ["ia te ia,", "and began to rebuke him,"], ["ua vavao ia te ia, ua faapea mai,", "saying,"], ["Le Alii e,", "Be it far from thee,"], ["ia mamao ia te oe lea mea;", "Lord:"], ["e le oo lena mea ia te oe.", "this shall not be unto thee."]]},
  {num:23,words:[["Ona fāliu atu ai lea o ia,", "But he turned,"], ["ua faapea atu ia Peteru,", "and said unto Peter,"], ["Satani e,", "Get thee behind me,"], ["ina alu ia oe i o'u tua,", "Satan:"], ["ua fai oe ma mea ou te tausuai ai;", "thou art an offence unto me:"], ["auā e le o mea a le Atua ua e loto i ai,", "for thou savourest not the things that be of God,"], ["a o mea a tagata.", "but those that be of men."]]},
  {num:24,words:[["Ona fetalai atu ai lea o Iesu i ona soo,", "Then said Jesus unto his disciples,"], ["Ai se tasi e fia mulimuli mai ia te au,", "If any man will come after me,"], ["aua ne'i usiusitai o ia ia te ia,", "let him deny himself,"], ["a ia ave e ia lona satauro,", "and take up his cross,"], ["i le mulimuli mai ai ia te au.", "and follow me."]]},
  {num:25,words:[["Auā ai se fia faasaogalemuina lona ola, e māumau ai ia te ia;", "For whosoever will save his life shall lose it:"], ["a o le faamāumau lona ola ona o a'u, e maua ai e ia.", "and whosoever will lose his life for my sake shall find it."]]},
  {num:26,words:[["Auā se a le aoga i le tagata pe afai na te maua le lalolagi uma,", "For what is a man profited, if he shall gain the whole world,"], ["a e māumau lona ola? se a foi se mea e avatu e le tagata e togiola a'i lona ola?", "and lose his own soul? or what shall a man give in exchange for his soul?"]]},
  {num:27,words:[["Auā e sau le Atalii o le tagata faatasi ma ana agelu i le mamalu o lona Tamā;", "For the Son of man shall come in the glory of his Father with his angels;"], ["ona tauia lea e ia e taitasi e tusa ma lana galuega.", "and then he shall reward every man according to his works."]]},
  {num:28,words:[["E moni,", "Verily I say unto you,"], ["ou te fai atu ia te outou,", "There be some standing here,"], ["O loo tutū mai iinei nisi e le oo ia te i latou le oti,", "which shall not taste of death,"], ["seia latou vaaia le Atalii o le tagata ua sau i lona malo.", "till they see the Son of man coming in his kingdom."]]},
];
renderVerseSet(mat_ch_16_Verses, 'mat-ch16-verses');

var mat_ch_17_Verses = [
  {num:1,words:[["Ua mavae atu aso e ono,", "And after six days Jesus taketh Peter,"], ["ona o ai lea o Iesu ma Peteru,", "James,"], ["ma Iakopo, ma Ioane lona uso,", "and John his brother,"], ["ua ia avae ia te i latou i le mauga māualuga ua na o i latou lava.", "and bringeth them up into an high mountain apart,"]]},
  {num:2,words:[["Ona liua ai lea o ia i o latou luma,", "And was transfigured before them:"], ["ua pupula mai ona fofoga e pei o le la,", "and his face did shine as the sun,"], ["ua sisina mai foi ona ofu e pei o le malamalama.", "and his raiment was white as the light."]]},
  {num:3,words:[["Faauta foi,", "And,"], ["ua faaali mai Mose ma Elia ia i latou,", "behold,"], ["ua latou fetautalatala'i ma ia.", "there appeared unto them Moses and Elias talking with him."]]},
  {num:4,words:[["Ona fai mai ai lea o Peteru,", "Then answered Peter,"], ["ua faapea mai ia Iesu,", "and said unto Jesus,"], ["Le Alii e,", "Lord,"], ["e lelei ona tatou nonofo iinei;", "it is good for us to be here:"], ["a ē finagalo i ai,", "if thou wilt,"], ["matou te faia iinei ni fale apitaga se tolu;", "let us make here three tabernacles;"], ["mo oe le tasi,", "one for thee,"], ["mo Mose le tasi,", "and one for Moses,"], ["mo Elia foi le tasi.", "and one for Elias."]]},
  {num:5,words:[["Faauta,", "While he yet spake,"], ["o le ao pupula ua ufitia ai i latou a o tautala ia;", "behold,"], ["faauta foi,", "a bright cloud overshadowed them:"], ["o le siufofoga mai le ao ua faapea mai,", "and behold a voice out of the cloud, which said,"], ["O lo'u Atalii pele lena,", "This is my beloved Son,"], ["ou te fiafia ia te ia;", "in whom I am well pleased;"], ["ia outou faalogo ia te ia.", "hear ye him."]]},
  {num:6,words:[["Ua faalogo ai le au soo,", "And when the disciples heard it,"], ["ona latou faapauu faō ai lea,", "they fell on their face,"], ["ua matuā matatau lava.", "and were sore afraid."]]},
  {num:7,words:[["Ona maliu atu ai lea o Iesu ua pa'i atu ia te i latou,", "And Jesus came and touched them,"], ["ua faapea atu,", "and said,"], ["Ina tutū ia outou;", "Arise,"], ["aua foi tou te matatau.", "and be not afraid."]]},
  {num:8,words:[["Ona tetepa ae ai lea o latou mata,", "And when they had lifted up their eyes,"], ["ua latou le iloa atu se tasi,", "they saw no man,"], ["ua na o Iesu lava.", "save Jesus only."]]},
  {num:9,words:[["Ua latou o ifo i le mauga,", "And as they came down from the mountain,"], ["ona vavao atu ai lea o Iesu ia te i latou,", "Jesus charged them,"], ["ua faapea atu,", "saying,"], ["Aua ne'i outou ta'u atu i se tasi le mea na vaaia,", "Tell the vision to no man,"], ["seia toe tu mai le Atalii o le tagata mai e ua oti.", "until the Son of man be risen again from the dead."]]},
  {num:10,words:[["Ona fesili mai lea o ona soo ia te ia,", "And his disciples asked him,"], ["ua faapea mai, Se a le mea ua fai mai ai le au tusiupu,", "saying,"], ["e ao ina muai sau o Elia?", "Why then say the scribes that Elias must first come?"]]},
  {num:11,words:[["Ona tali atu ai lea o Iesu,", "And Jesus answered and said unto them,"], ["ua faapea atu ia te i latou, E muai sau lava Elia,", "Elias truly shall first come,"], ["ma toe fuatai mea uma.", "and restore all things."]]},
  {num:12,words:[["A ou te fai atu ia te outou,", "But I say unto you,"], ["Ua mavae ona sau o Elia,", "That Elias is come already,"], ["e lei iloa foi o ia e i latou, a ua latou faia ia te ia o mea uma na latou loto i ai;", "and they knew him not,"], ["e faapea foi le Atalii o le tagata o le a faatigaina e i latou.", "but have done unto him whatsoever they listed. Likewise shall also the Son of man suffer of them."]]},
  {num:13,words:[["Ona iloa ai lea e le au soo, o Ioane le papatiso ua fetalai atu ai o ia ia te i latou.", "Then the disciples understood that he spake unto them of John the Baptist."]]},
  {num:14,words:[["Ua latou oo atu i le motu o tagata,", "And when they were come to the multitude,"], ["ona sau ai lea ia te ia o le tasi tagata,", "there came to him a certain man,"], ["ua tootuli ia te ia,", "kneeling down to him,"], ["ua faapea mai,", "and saying,"]]},
  {num:15,words:[["Le Alii e,", "Lord,"], ["ia e alofa mai i lo'u atalii,", "have mercy on my son:"], ["ua ma'i māliu,", "for he is lunatick,"], ["ua tiga lava;", "and sore vexed:"], ["auā ua paū soo ia i le afi,", "for ofttimes he falleth into the fire,"], ["ua faapea soo foi i le vai.", "and oft into the water."]]},
  {num:16,words:[["Na ou au mai ia te ia i ou soo,", "And I brought him to thy disciples,"], ["a ua latou le mafaia ona faamalolo ia te ia.", "and they could not cure him."]]},
  {num:17,words:[["Ona tali atu ai lea o Iesu,", "Then Jesus answered and said,"], ["ua faapea atu, Le tupulaga le faatuatua ma le faapiopio,", "O faithless and perverse generation,"], ["ou te i ai ia te outou seia afea? ou te faapalepale ia te outou seia afea? au mai ia o ia iinei ia te au.", "how long shall I be with you? how long shall I suffer you? bring him hither to me."]]},
  {num:18,words:[["Ua vavao atu Iesu ia te ia,", "And Jesus rebuked the devil;"], ["ona alu ai lea i fafo o le temoni sa ia te ia;", "and he departed out of him:"], ["ona malolo ai lea o le tama talu i lea lava itu aso.", "and the child was cured from that very hour."]]},
  {num:19,words:[["Ona o ane ai lea o le au soo ia Iesu ua na o i latou,", "Then came the disciples to Jesus apart,"], ["ua faapea ane,", "and said,"], ["Se a le mea na matou le mafai ai ona tulia o ia?", "Why could not we cast him out?"]]},
  {num:20,words:[["Ona fetalai atu ai lea o Iesu ia te i latou,", "And Jesus said unto them,"], ["Ona o lo outou le faatuatua;", "Because of your unbelief:"], ["auā e moni,", "for verily I say unto you,"], ["ou te fai atu ia te outou,", "If ye have faith as a grain of mustard seed,"], ["afai e tusa lo outou faatuatua ma le fua o le sinapi, e fai atu outou i lenei mauga,", "ye shall say unto this mountain,"], ["Alu atu ia oe i lela mea;", "Remove hence to yonder place;"], ["ona alu atu ai lea;", "and it shall remove;"], ["e leai foi se mea tou te le mafaia.", "and nothing shall be impossible unto you."]]},
  {num:21,words:[["A ua na o le tatalo ma le anapogi e o ese ai mea faapena.", "Howbeit this kind goeth not out but by prayer and fasting."]]},
  {num:22,words:[["Ua latou ui ane i Kalilaia,", "And while they abode in Galilee,"], ["ona fetalai atu lea o Iesu ia te i latou,", "Jesus said unto them,"], ["O le a tuuina atu le Atalii o le tagata i lima o tagata;", "The Son of man shall be betrayed into the hands of men:"]]},
  {num:23,words:[["latou te fasioti foi ia te ia,", "And they shall kill him,"], ["a e toe faatuina o ia i le aso tolu. Ona matuā tiga ai lea o i latou.", "and the third day he shall be raised again. And they were exceeding sorry."]]},
  {num:24,words:[["Ua latou oo atu i Kapanaumi,", "And when they were come to Capernaum,"], ["ona o mai ai lea ia Peteru o e tali taulaga,", "they that received tribute money came to Peter,"], ["ua faapea mai,", "and said,"], ["E le faia ea le taulaga e lo outou a'oa'o?", "Doth not your master pay tribute?"]]},
  {num:25,words:[["Ua fai atu ia,", "He saith,"], ["E fai lava. Ua ulufale atu ia i le fale,", "Yes. And when he was come into the house,"], ["ona tomua atu ai lea o le fetalaiga a Iesu ia te ia,", "Jesus prevented him,"], ["ua faapea atu,", "saying,"], ["Simona e,", "What thinkest thou,"], ["pe ni a fa oe? e tali telo ma taulaga mai ia te ai e tupu o le lalolagi? o a latou fanau ea,", "Simon? of whom do the kings of the earth take custom or tribute? of their own children,"], ["po o tagata ese?", "or of strangers?"]]},
  {num:26,words:[["Ona fai mai ai lea o Peteru ia te ia,", "Peter saith unto him,"], ["O tagata ese. Ona fetalai atu ai lea o Iesu ia te ia,", "Of strangers. Jesus saith unto him,"], ["O lea foi ua saoloto ai le fanau.", "Then are the children free."]]},
  {num:27,words:[["A o lenei,", "Notwithstanding,"], ["ne'i latou tausuai ia i tatou,", "lest we should offend them,"], ["ina alu ia oe i le vai,", "go thou to the sea,"], ["ma lafo ai se mātau,", "and cast an hook,"], ["o le uluai i'a e te maua, ia e tago i ai,", "and take up the fish that first cometh up;"], ["ma fafasi lona gutu,", "and when thou hast opened his mouth,"], ["ona e maua ai lea o le setatara;", "thou shalt find a piece of money:"], ["ia e ave lea,", "that take,"], ["ma avatu ia te i latou mā oe ma a'u.", "and give unto them for me and thee."]]},
];
renderVerseSet(mat_ch_17_Verses, 'mat-ch17-verses');

var mat_ch_18_Verses = [
  {num:1,words:[["O lea itu aso ua o ane ai le au soo ia Iesu,", "At the same time came the disciples unto Jesus,"], ["ua faapea ane,", "saying,"], ["O ai ea e sili i le malo o le lagi?", "Who is the greatest in the kingdom of heaven?"]]},
  {num:2,words:[["Ona valaau atu ai lea o Iesu i le tama itiiti,", "And Jesus called a little child unto him,"], ["ua faatu ia te ia i o latou luma,", "and set him in the midst of them,"]]},
  {num:3,words:[["ua faapea atu,", "And said,"], ["E moni,", "Verily I say unto you,"], ["ou te fai atu ia te outou, a le liua outou,", "Except ye be converted,"], ["ma avea ia pei o tama iti,", "and become as little children,"], ["tou te le sao lava i le malo o le lagi.", "ye shall not enter into the kingdom of heaven."]]},
  {num:4,words:[["O lenei o sē faamaulalo o ia ia te ia e pei o le tama itiiti nei,", "Whosoever therefore shall humble himself as this little child,"], ["e sili lea i le malo o le lagi.", "the same is greatest in the kingdom of heaven."]]},
  {num:5,words:[["Ai se talia se tama itiiti faapenei ona o lo'u igoa, ua ia talia a'u;", "And whoso shall receive one such little child in my name receiveth me."]]},
  {num:6,words:[["ai se na te faatausuai se tasi o i latou nei e faatauvaa o e faatuatua ia te au,", "But whoso shall offend one of these little ones which believe in me,"], ["e lelei i lea tagata pe ana nonoa se maaolo tele i lona ua,", "it were better for him that a millstone were hanged about his neck,"], ["ma faagotoina o ia i le moana loloto.", "and that he were drowned in the depth of the sea."]]},
  {num:7,words:[["Oi talofa i le lalolagi i mea e tausuai ai! auā e oo mai lava mea e tausuai ai e ao ai; a e ui lava i lea,", "Woe unto the world because of offences! for it must needs be that offences come;"], ["oi talofa i lea tagata e oo mai ai le mea e tausuai ai.", "but woe to that man by whom the offence cometh!"]]},
  {num:8,words:[["Afai foi e te tausuai i lou lima po o lou vae,", "Wherefore if thy hand or thy foot offend thee,"], ["ina tutū ese ia,", "cut them off,"], ["ma e lafoai; e lelei ona e sao i le ola a ua lima mutu,", "and cast them from thee:"], ["pe pipili,", "it is better for thee to enter into life halt or maimed,"], ["a e leaga pe a lafoina oe i le afi e faavavau ma ou lima e lua ma ou vae e lua.", "rather than having two hands or two feet to be cast into everlasting fire."]]},
  {num:9,words:[["Afai foi e te tausuai i lou mata,", "And if thine eye offend thee,"], ["ina sali ese ia,", "pluck it out,"], ["ma e lafoai;", "and cast it from thee:"], ["e lelei ona e sao i le ola ma le mata e tasi,", "it is better for thee to enter into life with one eye,"], ["a e leaga pe a lafoina oe ma ou mata e lua i le afi o Kēna.", "rather than having two eyes to be cast into hell fire."]]},
  {num:10,words:[["Ia outou,", "Take heed that ye despise not one of these little ones;"], ["ne'i tou faaleaogaina se tasi o i latou nei e faatauvaa; auā ou te fai atu ia te outou,", "for I say unto you,"], ["o a latou agelu i le lagi e le aunoa ona latou vaavaai i fofoga o lo'u Tamā o i le lagi.", "That in heaven their angels do always behold the face of my Father which is in heaven."]]},
  {num:11,words:[["Auā ua sau le Atalii o le tagata e faaola i le na le iloa.", "For the Son of man is come to save that which was lost."]]},
  {num:12,words:[["Pe ni a fa outou? ai se tagata o i ai mamoe e selau,", "How think ye? if a man have an hundred sheep,"], ["afai e sē le tasi,", "and one of them be gone astray,"], ["na te le tuua ea le ivagafulu ma le iva i mauga,", "doth he not leave the ninety and nine, and goeth into the mountains,"], ["a e alu o ia e saili i le na sē?", "and seeketh that which is gone astray?"]]},
  {num:13,words:[["Afai foi na te maua,", "And if so be that he find it,"], ["e moni,", "verily I say unto you,"], ["ou te fai atu ia te outou, e tele lona olioli i lea,", "he rejoiceth more of that sheep,"], ["a e itiiti i le ivagafulu ma le iva e lei sē.", "than of the ninety and nine which went not astray."]]},
  {num:14,words:[["E faapea lo outou Tamā o i le lagi,", "Even so it is not the will of your Father which is in heaven,"], ["e le finagalo ia ina ia fano se tasi o i latou nei e faatauvaa.", "that one of these little ones should perish."]]},
  {num:15,words:[["Afai e agaleaga mai lou uso ia te oe,", "Moreover if thy brother shall trespass against thee,"], ["ia e alu,", "go and tell him his fault between thee and him alone:"], ["ma aoai ia te ia tau lava o oulua ma ia. Afai e faalogo mai o ia ia te oe,", "if he shall hear thee,"], ["ua e maua lou uso.", "thou hast gained thy brother."]]},
  {num:16,words:[["A e afai e le faalogo mai o ia, lua te o ma se tasi,", "But if he will not hear thee,"], ["po o se toalua,", "then take with thee one or two more,"], ["ina ia faamaoni ai upu uma i le mau a le toalua, po o le toatolu.", "that in the mouth of two or three witnesses every word may be established."]]},
  {num:17,words:[["A le faalogo lava o ia ia te i laua, ia e ta'u atu i le ekalesia;", "And if he shall neglect to hear them,"], ["pe afai e le faalogo lava o ia i le ekalesia,", "tell it unto the church:"], ["ia avea o ia ia te oe,", "but if he neglect to hear the church,"], ["ia pei o le faapaupau, po o le telona.", "let him be unto thee as an heathen man and a publican."]]},
  {num:18,words:[["E moni, ou te fai atu ia te outou,", "Verily I say unto you,"], ["O mea uma tou te fusifusia i le lalolagi, e fusifusia ia i le lagi;", "Whatsoever ye shall bind on earth shall be bound in heaven:"], ["o mea uma foi tou te tālā i le lalolagi, e tatalaina ia i le lagi.", "and whatsoever ye shall loose on earth shall be loosed in heaven."]]},
  {num:19,words:[["Ou te fai atu foi ia te outou,", "Again I say unto you,"], ["Afai e loto gatasi se toalua o outou o i le lalolagi i se mea la te ole atu ai,", "That if two of you shall agree on earth as touching any thing that they shall ask,"], ["e faia lea mo i laua e lo'u Tamā o i le lagi.", "it shall be done for them of my Father which is in heaven."]]},
  {num:20,words:[["Auā o le mea ua faapotopoto ai se toalua, po o se toatolu i lo'u igoa,", "For where two or three are gathered together in my name,"], ["ou te i ai faatasi ma i latou.", "there am I in the midst of them."]]},
  {num:21,words:[["Ona alu ane ai lea o Peteru ia te ia,", "Then came Peter to him,"], ["ua faapea ane,", "and said,"], ["Le Alii e,", "Lord,"], ["e agaleaga mai faafia ea lo'u uso ia te au,", "how oft shall my brother sin against me,"], ["ma ou faamagalo ia te ia? seia atu fitu ea?", "and I forgive him? till seven times?"]]},
  {num:22,words:[["Ua fetalai atu Iesu ia te ia,", "Jesus saith unto him,"], ["Ou te le fai atu ia te oe,", "I say not unto thee,"], ["seia atu fitu,", "Until seven times: but,"], ["a ia fitugafulu ni fitu.", "Until seventy times seven."]]},
  {num:23,words:[["O le mea lea e tusa ai le malo o le lagi ma le tasi tupu,", "Therefore is the kingdom of heaven likened unto a certain king,"], ["o le na manatu e faamasino i mea ua i ana auauna.", "which would take account of his servants."]]},
  {num:24,words:[["Ua amata e ia ona faamasino,", "And when he had begun to reckon, one was brought unto him,"], ["ona au mai ai lea ia te ia o le tasi ua i ai ana taleni e sefulu afe.", "which owed him ten thousand talents."]]},
  {num:25,words:[["Ua le maua e ia ni mea e taui a'i,", "But forasmuch as he had not to pay,"], ["ona fai atu lea o lona alii ia faatauina o ia,", "his lord commanded him to be sold,"], ["ma lana avā,", "and his wife,"], ["ma ana fanau,", "and children,"], ["atoa ma ana mea uma,", "and all that he had,"], ["ina ia taui a'i mai.", "and payment to be made."]]},
  {num:26,words:[["Ona faapaū ai lea o le auauna,", "The servant therefore fell down,"], ["ua ifo ia te ia,", "and worshipped him,"], ["ua faapea mai,", "saying,"], ["Le alii e,", "Lord,"], ["ia e faapalepale mai ia te au,", "have patience with me,"], ["ou te taui atu ai au mea uma.", "and I will pay thee all."]]},
  {num:27,words:[["Ona mutimuti vale ai lea o le alofa o le alii o lea auauna,", "Then the lord of that servant was moved with compassion,"], ["ua tuu atu o ia ia saoloto,", "and loosed him,"], ["ma faamagalo atu ana tupe ua i ai.", "and forgave him the debt."]]},
  {num:28,words:[["Ona alu atu lea o lea auauna,", "But the same servant went out,"], ["ua iloa e ia le tasi o ona uso a auauna ua i ai ana tenari e selau;", "and found one of his fellowservants, which owed him an hundred pence:"], ["ona pue lea ma titina ia te ia,", "and he laid hands on him,"], ["ua faapea atu,", "and took him by the throat, saying,"], ["Ina taui mai ia a'u mea ua ia te oe.", "Pay me that thou owest."]]},
  {num:29,words:[["Ona faapaū atu ai lea o lona uso a auauna i ona vae,", "And his fellowservant fell down at his feet,"], ["ua aioi atu ia te ia,", "and besought him,"], ["ua faapea atu,", "saying,"], ["Ia e faapalepale mai ia te au,", "Have patience with me,"], ["ou te taui atu au mea uma.", "and I will pay thee all."]]},
  {num:30,words:[["A ua le mafai o ia;", "And he would not:"], ["a ua alu ma tuu atu ia te ia i le fale puipui,", "but went and cast him into prison,"], ["seia tauia mai ana mea.", "till he should pay the debt."]]},
  {num:31,words:[["Ua iloa e ona uso a auauna o mea na faia,", "So when his fellowservants saw what was done,"], ["ona latou matuā tiga ai lea; ua latou o atu,", "they were very sorry,"], ["ma ta'u atu i lo latou alii o mea uma lava na faia.", "and came and told unto their lord all that was done."]]},
  {num:32,words:[["Ona valaau atu ai lea o lona alii ia te ia,", "Then his lord,"], ["ua faapea atu ia te ia,", "after that he had called him,"], ["Le auauna leaga e,", "said unto him, O thou wicked servant,"], ["na a'u faamagaloina atu a'u mea uma ua ia te oe,", "I forgave thee all that debt,"], ["ina ua e aioi mai ia te au;", "because thou desiredst me:"]]},
  {num:33,words:[["e le tatau ea ona e alofa atu i lou uso a auauna,", "Shouldest not thou also have had compassion on thy fellowservant,"], ["e pei o a'u foi na ou alofa atu ia te oe?", "even as I had pity on thee?"]]},
  {num:34,words:[["Ona ita ai lea o lona alii,", "And his lord was wroth,"], ["ua tuu atu ia te ia i e faataumaoi,", "and delivered him to the tormentors,"], ["seia tauia mai ana mea uma.", "till he should pay all that was due unto him."]]},
  {num:35,words:[["E faapea foi ona faia ia te outou e lo'u Tamā o i le lagi,", "So likewise shall my heavenly Father do also unto you,"], ["pe afai tou te le taitasi ma faamagalo ma o outou loto atoa i o outou uso pe a latou agaleaga mai.", "if ye from your hearts forgive not every one his brother their trespasses."]]},
];
renderVerseSet(mat_ch_18_Verses, 'mat-ch18-verses');

var mat_ch_19_Verses = [
  {num:1,words:[["Ua faaiu e Iesu o ia upu,", "And it came to pass,"], ["ona tuua lea e ia o Kalilaia,", "that when Jesus had finished these sayings, he departed from Galilee,"], ["ua oo atu i le laueleele o Iutaia i tala atu o Ioritana.", "and came into the coasts of Judaea beyond Jordan;"]]},
  {num:2,words:[["Ua mulimuli mai foi ia te ia le motu o tagata e toatele;", "And great multitudes followed him;"], ["Ona faamalolo lea e ia ia te i latou i lea mea.", "and he healed them there."]]},
  {num:3,words:[["Ona o mai ai lea ia te ia o faresaio,", "The Pharisees also came unto him,"], ["ua faaosooso mai ia te ia,", "tempting him,"], ["ua faapea mai ia te ia,", "and saying unto him,"], ["Pe sa ea i se tasi ona faatea o lana avā ona o mea uma?", "Is it lawful for a man to put away his wife for every cause?"]]},
  {num:4,words:[["Ona tali atu ai lea o ia, ua faapea atu ia te i latou,", "And he answered and said unto them,"], ["Tou te lei faitaulia ea,", "Have ye not read,"], ["o le na faia tagata i le amataga, na ia faia i laua o le tane ma le fafine,", "that he which made them at the beginning made them male and female,"]]},
  {num:5,words:[["na ia fetalai ane foi,", "And said,"], ["O le mea lea e tuua ai e le tane o lona tamā ma lona tinā,", "For this cause shall a man leave father and mother,"], ["a e faatasi ma lana avā;", "and shall cleave to his wife:"], ["ona avea lea o i laua o le tino e tasi?", "and they twain shall be one flesh?"]]},
  {num:6,words:[["O lea e le toe toalua ai, a o le tino e tasi i laua;", "Wherefore they are no more twain,"], ["o lenei,", "but one flesh. What therefore God hath joined together,"], ["o e ua faatasia e le Atua, aua ne'i faateaeseina e se tagata.", "let not man put asunder."]]},
  {num:7,words:[["Ona latou fai mai ai lea ia te ia,", "They say unto him, Why did Moses then command to give a writing of divorcement,"], ["Se a foi le mea na poloai mai ai Mose e avatu le tusi alei e faatea ai ia te ia?", "and to put her away?"]]},
  {num:8,words:[["Ona fetalai atu ai lea o ia ia te i latou,", "He saith unto them,"], ["Ona o outou loto ina maaa na tuu mai ai e Mose ia te outou e faatea i a outou avā;", "Moses because of the hardness of your hearts suffered you to put away your wives:"], ["a e lei faapea talu mai i le amataga.", "but from the beginning it was not so."]]},
  {num:9,words:[["Ou te fai atu foi ia te outou,", "And I say unto you,"], ["Ai se faatea i lana avā,", "Whosoever shall put away his wife,"], ["a o lei mulilua ia, ma fai avā i se tasi,", "except it be for fornication,"], ["ua mulilua ia;", "and shall marry another,"], ["o se fai avā i le na faate'aina,", "committeth adultery:"], ["ua mulilua foi lea.", "and whoso marrieth her which is put away doth commit adultery."]]},
  {num:10,words:[["Ona fai mai ai lea ona soo ia te ia,", "His disciples say unto him,"], ["Afai e faapea le tu a le tane ma le fafine,", "If the case of the man be so with his wife,"], ["e ao ina le fai avā.", "it is not good to marry."]]},
  {num:11,words:[["A ua fetalai atu ia ia te i latou,", "But he said unto them,"], ["E le mafai ona talia lena upu e tagata uma,", "All men cannot receive this saying,"], ["ua na o e ua foaiina atu i ai;", "save they to whom it is given."]]},
  {num:12,words:[["auā o i ai eunuka o e faapea ina fanau mai;", "For there are some eunuchs, which were so born from their mother's womb:"], ["o i ai foi eunuka o e ua faaeunukaina e tagata;", "and there are some eunuchs,"], ["o i ai foi eunuka o e ua faaeunukaina i latou e i latou,", "which were made eunuchs of men:"], ["ona o le malo o le lagi.", "and there be eunuchs, which have made themselves eunuchs for the kingdom of heaven's sake."], ["Ai se na te mafaia ona talia,", "He that is able to receive it,"], ["ina talia lea e ia.", "let him receive it."]]},
  {num:13,words:[["Ona au mai ai lea ia te ia o tama iti,", "Then were there brought unto him little children,"], ["ina ia faaee ona aao ia te i latou,", "that he should put his hands on them,"], ["ma tatalo;", "and pray:"], ["ona vavao atu ai lea o ona soo ia te i latou.", "and the disciples rebuked them."]]},
  {num:14,words:[["A ua fetalai atu Iesu,", "But Jesus said,"], ["Ina tuu mai ia o tama iti e o mai ia te au,", "Suffer little children,"], ["aua le vaoia i latou;", "and forbid them not, to come unto me:"], ["auā e faapei o i latou nei o e o i le malo o le lagi.", "for of such is the kingdom of heaven."]]},
  {num:15,words:[["Ua faaee ona aao ia te i latou,", "And he laid his hands on them,"], ["ona maliu ese ai lea o ia i lea mea.", "and departed thence."]]},
  {num:16,words:[["Faauta foi,", "And,"], ["ua sau le tasi tagata,", "behold,"], ["ua faapea mai ia te ia,", "one came and said unto him, Good Master,"], ["Le a'oa'o lelei e,", "what good thing shall I do,"], ["se a se mea lelei ou te faia ou te maua ai le ola faavavau?", "that I may have eternal life?"]]},
  {num:17,words:[["Ona fetalai atu ai lea o ia ia te ia,", "And he said unto him,"], ["Se a le mea e te ta'ulelei mai ai a'u? e leai se tasi e lelei,", "Why callest thou me good? there is none good but one,"], ["ua na o le toatasi,", "that is, God:"], ["o le Atua lea. Afai e te fia oo i le ola,", "but if thou wilt enter into life,"], ["ia e tausi i poloaiga.", "keep the commandments."]]},
  {num:18,words:[["Ua fai mai o ia ia te ia,", "He saith unto him,"], ["Po o le fea? Ona faapea atu ai lea o Iesu,", "Which? Jesus said,"], ["Aua e te fasioti tagata;", "Thou shalt do no murder,"], ["aua e te mulilua;", "Thou shalt not commit adultery,"], ["aua e te gaoi;", "Thou shalt not steal,"], ["aua e te molimau pepelo;", "Thou shalt not bear false witness,"]]},
  {num:19,words:[["ia e ava i lou tamā ma lou tinā;", "Honour thy father and thy mother:"], ["ma ia e alofa atu i lē lua te tuaoi,", "and,"], ["ia pei o oe lava ia te oe.", "Thou shalt love thy neighbour as thyself."]]},
  {num:20,words:[["Ona fai mai ai lea o le taulealea ia te ia,", "The young man saith unto him,"], ["Ua ou tausia na mea uma talu ina ou itiiti,", "All these things have I kept from my youth up:"], ["se a se mea o toe ou te lei faia?", "what lack I yet?"]]},
  {num:21,words:[["Ua tali atu Iesu ia te ia,", "Jesus said unto him,"], ["Afai e te manao ina ia atoatoa ona lelei o lau amio ia e alu ma e faatau atu au mea,", "If thou wilt be perfect,"], ["i le e avatu ai i e matitiva;", "go and sell that thou hast, and give to the poor,"], ["ona ia te oe lea o le faulaigāoloa i le lagi,", "and thou shalt have treasure in heaven:"], ["i le e sau ma mulimuli mai ia te au.", "and come and follow me."]]},
  {num:22,words:[["Ua faalogo le taulealea i lea upu,", "But when the young man heard that saying,"], ["ona alu ese ai lea o ia ma le tiga,", "he went away sorrowful:"], ["auā e tele lava ana mea.", "for he had great possessions."]]},
  {num:23,words:[["Ona fetalai atu ai lea o Iesu i ona soo,", "Then said Jesus unto his disciples,"], ["E moni, ou te fai atu ia te outou,", "Verily I say unto you,"], ["e faigata ona sao atu o le mauoa i le malo o le lagi.", "That a rich man shall hardly enter into the kingdom of heaven."]]},
  {num:24,words:[["Ou te fai atu foi ia te outou,", "And again I say unto you,"], ["e faigofie ona ui atu o se kamela i le pu o le au,", "It is easier for a camel to go through the eye of a needle,"], ["a e faigata ona sao o le mauoa i le malo o le Atua.", "than for a rich man to enter into the kingdom of God."]]},
  {num:25,words:[["Ua faalogo ai ona soo,", "When his disciples heard it,"], ["ona latou matuā taufaiofo ai lea,", "they were exceedingly amazed,"], ["ua faapea ane, Afai o lea,", "saying,"], ["o ai se tasi e mafai ona faaolaina?", "Who then can be saved?"]]},
  {num:26,words:[["Ona silasila atu ai lea o Iesu,", "But Jesus beheld them,"], ["ua faapea atu ia te i latou,", "and said unto them,"], ["E le mafaia e tagata lenei mea,", "With men this is impossible;"], ["a e mafaia mea uma e le Atua.", "but with God all things are possible."]]},
  {num:27,words:[["Ona tali mai ai lea o Peteru,", "Then answered Peter and said unto him,"], ["ua faapea mai ia te ia,", "Behold,"], ["Faauta, ua matou tuua mea uma,", "we have forsaken all,"], ["a e matou mulimuli atu ia te oe;", "and followed thee;"], ["se a foi se mea matou te maua?", "what shall we have therefore?"]]},
  {num:28,words:[["Ona fetalai atu ai lea o Iesu ia te i latou,", "And Jesus said unto them,"], ["E moni,", "Verily I say unto you,"], ["ou te fai atu ia te outou, o outou ua mulimuli mai ia te au,", "That ye which have followed me,"], ["pe a tietie le Atalii o le tagata i lona nofoālii mamalu i le toefuataiga,", "in the regeneration when the Son of man shall sit in the throne of his glory,"], ["tou te tietie ai foi i nofoālii e sefulu ma le lua,", "ye also shall sit upon twelve thrones,"], ["e faamasino ai i itu aiga o Isaraelu e sefulu ma le lua.", "judging the twelve tribes of Israel."]]},
  {num:29,words:[["Ai se tasi ua ia tuua o fale,", "And every one that hath forsaken houses,"], ["po o uso,", "or brethren,"], ["po o tuafāfine,", "or sisters,"], ["po o le tamā,", "or father,"], ["po o le tinā,", "or mother, or wife,"], ["po o le avā,", "or children,"], ["po o le fanau,", "or lands,"], ["p o fanua ona o lo'u igoa,", "for my name's sake,"], ["e maua e ia e taisautuaselau,", "shall receive an hundredfold,"], ["e fai foi mona tofi le ola faavavau.", "and shall inherit everlasting life."]]},
  {num:30,words:[["A e toatele o e ua muamua e avea ma mulimuli;", "But many that are first shall be last;"], ["o e ua mulimuli foi e avea ma muamua.", "and the last shall be first."]]},
];
renderVerseSet(mat_ch_19_Verses, 'mat-ch19-verses');

var mat_ch_20_Verses = [
  {num:1,words:[["Auā e tusa le malo o le lagi ma le tasi matai na alausu atu e tautala ma nisi e faigaluega i lona tovine a e taui atu.", "For the kingdom of heaven is like unto a man that is an householder, which went out early in the morning to hire labourers into his vineyard."]]},
  {num:2,words:[["Ua tautala o ia ma ē faigaluega, o le aso ma le tenari;", "And when he had agreed with the labourers for a penny a day,"], ["ona aauina atu ai lea e ia o i latou i lana tovine.", "he sent them into his vineyard."]]},
  {num:3,words:[["O le itu aso foi e tolu ua alu atu ai o ia,", "And he went out about the third hour,"], ["ona iloa atu ai lea e ia o isi ua tutū i le malae e leai se galuega;", "and saw others standing idle in the marketplace,"]]},
  {num:4,words:[["ona fai atu ai lea o ia ia te i latou,", "And said unto them;"], ["Ina o atu ia outou foi i le tovine,", "Go ye also into the vineyard,"], ["a e ou te avatu ia te outou se mea e tusa. Ona latou o atu ai lea.", "and whatsoever is right I will give you. And they went their way."]]},
  {num:5,words:[["Ua toe alu atu ia i le itu aso e ono, ma le iva,", "Again he went out about the sixth and ninth hour,"], ["ua faapea foi ona fai.", "and did likewise."]]},
  {num:6,words:[["O le itu aso foi e sefulu ma le tasi ua alu atu ai o ia,", "And about the eleventh hour he went out,"], ["ona iloa atu ai lea e ia nisi ua tutū e leai se galuega,", "and found others standing idle,"], ["ua na fai atu foi ia te i latou,", "and saith unto them,"], ["Se a le mea tou te tutu mai ai iinei i le aso uma e leai se galuega?", "Why stand ye here all the day idle?"]]},
  {num:7,words:[["Ua latou fai mai ia te ia,", "They say unto him,"], ["E leai se na fai mai ia te i matou.", "Because no man hath hired us."], ["Ua fai atu ia ia te i latou,", "He saith unto them,"], ["Ina o atu ia o outou foi i le tovine,", "Go ye also into the vineyard; and whatsoever is right,"], ["a e maua e outou se mea e tusa.", "that shall ye receive."]]},
  {num:8,words:[["Ua oo i le afiafi,", "So when even was come,"], ["ona fai atu ai lea o le alii e ana le tovine i lana auauna e pule,", "the lord of the vineyard saith unto his steward,"], ["Valaau ia i e faigaluega, ma avatu le taui ia te i latou,", "Call the labourers,"], ["ia afua i e na mulimuli,", "and give them their hire,"], ["ia oo i e na muamua.", "beginning from the last unto the first."]]},
  {num:9,words:[["Ua o mai foi o e na o ane i le itu aso e sefulu ma le tasi,", "And when they came that were hired about the eleventh hour,"], ["ua taitasi ma latou maua le tenari.", "they received every man a penny."]]},
  {num:10,words:[["Ona o mai ai lea o e na muamua,", "But when the first came,"], ["fa te i latou e sili sa latou mea e maua;", "they supposed that they should have received more;"], ["a ua taitasi foi o i latou ma maua le tenari.", "and they likewise received every man a penny."]]},
  {num:11,words:[["Ua maua ai e i latou,", "And when they had received it,"], ["ona latou muimui ai lea i le matai,", "they murmured against the goodman of the house,"]]},
  {num:12,words:[["ua faapea mai,", "Saying,"], ["E tasi lava le itu aso na galulue ai i latou nei na mulimuli,", "These last have wrought but one hour, and thou hast made them equal unto us,"], ["a ua e faatusaina i latou ma i matou o e na tigaina i le galuega ma le vevela o le aso.", "which have borne the burden and heat of the day."]]},
  {num:13,words:[["Ona tali atu ai lea o ia i le tasi o i latou,", "But he answered one of them,"], ["ua faapea atu,", "and said,"], ["Sole,", "Friend,"], ["e leai sa'u agaleaga ia te oe;", "I do thee no wrong:"], ["ta te lei tautala ea i le tenari e tasi?", "didst not thou agree with me for a penny?"]]},
  {num:14,words:[["Ina tago ia i lau mea,", "Take that thine is,"], ["ma alu;", "and go thy way: I will give unto this last,"], ["o la'u pule lea e avatu lava i lenei na mulimuli e pei o a oe lava.", "even as unto thee."]]},
  {num:15,words:[["E le faitalia ea a'u ona pule i a'u lava mea? e te faaūū mai ea ina ua ou agalelei?", "Is it not lawful for me to do what I will with mine own? Is thine eye evil, because I am good?"]]},
  {num:16,words:[["E faapea ona muamua o e na mulimuli,", "So the last shall be first,"], ["e mulimuli foi e na muamua;", "and the first last:"], ["auā e toatele e ua tala'iina,", "for many be called,"], ["a e toaitiiti e ua filifilia.", "but few chosen."]]},
  {num:17,words:[["Ua maliu ae Iesu i Ierusalema, ona ave ai lea e ia o le au soo e toasefulu ma le toalua i le ala ua na o i latou lava,", "And Jesus going up to Jerusalem took the twelve disciples apart in the way,"], ["ua faapea atu ia te i latou,", "and said unto them,"]]},
  {num:18,words:[["Faauta,", "Behold,"], ["o le a tatou o ae i Ierusalema,", "we go up to Jerusalem;"], ["e tuuina atu ai le Atalii o le tagata i le au faitaulaga sili, ma le au tusiupu,", "and the Son of man shall be betrayed unto the chief priests and unto the scribes,"], ["latou te faasala ia te ia ia oti;", "and they shall condemn him to death,"]]},
  {num:19,words:[["latou te tuuina atu foi ia te ia i nuu ese,", "And shall deliver him to the Gentiles to mock,"], ["ina ia latou faatauemu,", "and to scourge,"], ["ma sasa, ma faasatauro ia te ia;", "and to crucify him:"], ["a e toe faatuina o ia i le aso tolu.", "and the third day he shall rise again."]]},
  {num:20,words:[["Ona sau ai lea o le tinā o atalii o Sepetaio,", "Then came to him the mother of Zebedee's children with her sons,"], ["faatasi ma ana tama tane,", "worshipping him,"], ["ua ifo ma ole mai ia te ia i se mea.", "and desiring a certain thing of him."]]},
  {num:21,words:[["Ona faapea atu ai lea o ia ia te ia,", "And he said unto her,"], ["Se a se mea e te manao i ai? Ua fai mai o ia ia te ia,", "What wilt thou? She saith unto him,"], ["Ia e fetalai ane,", "Grant that these my two sons may sit, the one on thy right hand,"], ["ia nonofo a'u nei tama e toalua,", "and the other on the left,"], ["o le tasi i lou itu taumatau o le isi foi i lou itu tauagavale i lou malo.", "in thy kingdom."]]},
  {num:22,words:[["Ona tali atu ai lea o Iesu, ua faapea atu,", "But Jesus answered and said,"], ["Lua te le iloa le mea lua te ole mai ai na.", "Ye know not what ye ask."], ["Lua te mafaia ea ona inu i le ipu o le a a'u inu ai,", "Are ye able to drink of the cup that I shall drink of,"], ["ma ia papatisoina oulua i le papatisoga o le a papatisoina ai a'u? Ua la fai mai ia te ia,", "and to be baptized with the baptism that I am baptized with? They say unto him,"], ["Ma te mafaia.", "We are able."]]},
  {num:23,words:[["Ona fetalai atu ai lea o ia ia te i laua,", "And he saith unto them,"], ["Lua te feinu lava i la'u ipu,", "Ye shall drink indeed of my cup,"], ["o le papatisoga foi e papatisoina ai a'u e papatisoina ai oulua;", "and be baptized with the baptism that I am baptized with: but to sit on my right hand,"], ["a o le nofo i lo'u itu taumatau ma lo'u itu tauagavale,", "and on my left,"], ["e le o ia te au lea ona avatu,", "is not mine to give,"], ["a e tau lava o e ua saunia mo i latou lea mea e lo'u Tamā.", "but it shall be given to them for whom it is prepared of my Father."]]},
  {num:24,words:[["Ua faalogo ai le toasefulu,", "And when the ten heard it,"], ["ona tiga ai lea o latou loto i lea uso e toalua.", "they were moved with indignation against the two brethren."]]},
  {num:25,words:[["A ua valaau atu Iesu ia te i latou,", "But Jesus called them unto him,"], ["ona faapea atu lea o ia,", "and said,"], ["Ua outou iloa o alii o nuu ese ua aliitai i latou,", "Ye know that the princes of the Gentiles exercise dominion over them,"], ["o e ua sili foi ua pule ia te i latou;", "and they that are great exercise authority upon them."]]},
  {num:26,words:[["a e le faapea outou;", "But it shall not be so among you:"], ["a o sē fia sili ia te outou,", "but whosoever will be great among you,"], ["ia fai o ia ma a outou auauna;", "let him be your minister;"]]},
  {num:27,words:[["o sē fia muamua foi ia te outou,", "And whosoever will be chief among you,"], ["ia fai o ia ma a outou tautua.", "let him be your servant:"]]},
  {num:28,words:[["E pei o le Atalii o le tagata e lei sau ia ina ia auauna mai tagata ia te ia,", "Even as the Son of man came not to be ministered unto,"], ["a ia auauna atu ia,", "but to minister,"], ["ma foaiina atu lona ola e fai ma togiola e sui a'i tagata e toatele.", "and to give his life a ransom for many."]]},
  {num:29,words:[["Ua latou o atu nai Ieriko,", "And as they departed from Jericho,"], ["ona mulimuli mai ai lea ia te ia o le motu o tagata e toatele.", "a great multitude followed him."]]},
  {num:30,words:[["Faauta foi,", "And,"], ["ua nonofo i le au ala tagata tauaso e toalua,", "behold,"], ["ua la faalogo ua maliu ane Iesu,", "two blind men sitting by the way side,"], ["ona la alalaga mai ai lea,", "when they heard that Jesus passed by,"], ["ua faapea mai,", "cried out, saying,"], ["Le Alii e,", "Have mercy on us,"], ["le alo o Tavita,", "O Lord,"], ["ia e alofa mai ia te i maua.", "thou Son of David."]]},
  {num:31,words:[["Ona vavao ai lea e le motu o tagata ia te i laua,", "And the multitude rebuked them,"], ["ia la faalologo;", "because they should hold their peace:"], ["a ua atili ai ona alalaga o i laua,", "but they cried the more,"], ["ua faapea mai,", "saying,"], ["Le Alii e,", "Have mercy on us,"], ["le alo o Tavita,", "O Lord,"], ["ia e alofa mai ia te i maua.", "thou Son of David."]]},
  {num:32,words:[["Ona tu ai lea o Iesu,", "And Jesus stood still,"], ["ua valaau atu ia te i laua,", "and called them,"], ["ona faapea atu lea o ia,", "and said,"], ["Se a se mea lua te mananao i ai ou te faia mo oulua?", "What will ye that I shall do unto you?"]]},
  {num:33,words:[["Ona la fai mai ai lea ia te ia,", "They say unto him,"], ["Le Alii e,", "Lord,"], ["ia pupula o maua mata.", "that our eyes may be opened."]]},
  {num:34,words:[["Ona mutimuti vale ai lea o le alofa o Iesu,", "So Jesus had compassion on them,"], ["ua pa'i atu i o la mata;", "and touched their eyes:"], ["ona vaai loa ai lea o la mata,", "and immediately their eyes received sight,"], ["ona la mulimuli mai ai lea ia te ia.", "and they followed him."]]},
];
renderVerseSet(mat_ch_20_Verses, 'mat-ch20-verses');

var mat_ch_21_Verses = [
  {num:1,words:[["Ua latalata i latou i Ierusalema,", "And when they drew nigh unto Jerusalem,"], ["ua oo i Petefake i le mauga o Olive,", "and were come to Bethphage, unto the mount of Olives,"], ["ona aauina atu ai lea e Iesu ona soo e toalua,", "then sent Jesus two disciples,"]]},
  {num:2,words:[["ua faapea atu ia te i laua,", "Saying unto them,"], ["Lua te o atu i le aai ua lumanai oulua,", "Go into the village over against you,"], ["ona iloa atu loa lea e oulua o le asini ua nonoa,", "and straightway ye shall find an ass tied,"], ["o lana tama foi ua faatasi ma ia;", "and a colt with her:"], ["lua te tatalaina,", "loose them,"], ["i le ta'ita'i mai ai ia te au.", "and bring them unto me."]]},
  {num:3,words:[["Afai foi e fai ane se tasi se upu ia te oulua,", "And if any man say ought unto you,"], ["ia oulua fai atu,", "ye shall say,"], ["E manao i ai le Alii;", "The Lord hath need of them;"], ["ona tuu loa mai ai lea e ia.", "and straightway he will send them."]]},
  {num:4,words:[["Ua oo nei mea uma,", "All this was done,"], ["ina ia taunuu ai le upu a le perofeta,", "that it might be fulfilled which was spoken by the prophet,"], ["ua faapea mai,", "saying,"]]},
  {num:5,words:[["Ia outou fai atu i le tama fafine a Siona,", "Tell ye the daughter of Sion,"], ["faauta,", "Behold,"], ["o loo afio mai ia te oe lou Tupu,", "thy King cometh unto thee,"], ["ua agamalu o ia,", "meek,"], ["o loo tietie i le asini,", "and sitting upon an ass,"], ["o le tamai asini foi.", "and a colt the foal of an ass."]]},
  {num:6,words:[["Ona o ai lea o ia soo,", "And the disciples went,"], ["ua faia foi e i laua pei ona fetalai atu ai o Iesu ia te i laua.", "and did as Jesus commanded them,"]]},
  {num:7,words:[["Ua la ta'ita'iina mai foi le asini ma le tamai asini ,", "And brought the ass,"], ["ua faaee i ai o latou ofu,", "and the colt, and put on them their clothes,"], ["ma faatietie ai o ia.", "and they set him thereon."]]},
  {num:8,words:[["O le toatele o le motu o tagata ua fofola o latou ofu i le ala;", "And a very great multitude spread their garments in the way; others cut down branches from the trees,"], ["o isi foi ua latou sala i lālā o laau ma folasia ai le ala.", "and strawed them in the way."]]},
  {num:9,words:[["O le motu o tagata ua muamua,", "And the multitudes that went before,"], ["ma e ua mulimuli,", "and that followed,"], ["ua alalaga i latou,", "cried, saying,"], ["ua faapea mai,", "Hosanna to the Son of David:"], ["Osana i le alo o Tavita;", "Blessed is he that cometh in the name of the Lord;"], ["ia manuia lē afio mai i le suafa o le Alii. Osana i mea e aupito i luga.", "Hosanna in the highest."]]},
  {num:10,words:[["Ua oo ia i Ierusalema,", "And when he was come into Jerusalem,"], ["ona vevesi ai lea o le aai uma,", "all the city was moved,"], ["ua faapea ane,", "saying,"], ["O ai ea lenei?", "Who is this?"]]},
  {num:11,words:[["Ona faapea atu ai lea o le motu o tagata,", "And the multitude said,"], ["O Iesu lenei le perofeta mai Nasareta i Kalilaia.", "This is Jesus the prophet of Nazareth of Galilee."]]},
  {num:12,words:[["Ua ulufale atu Iesu i le malumalu o le Atua,", "And Jesus went into the temple of God,"], ["ona ia tulia uma lea i fafo o e na fefaatauai i le malumalu,", "and cast out all them that sold and bought in the temple,"], ["ma na fuli i lalo laulau a e na faatau tupe,", "and overthrew the tables of the moneychangers,"], ["ma nofoa o e na faatau lupe.", "and the seats of them that sold doves,"]]},
  {num:13,words:[["Ua faapea atu o ia ia te i latou,", "And said unto them,"], ["Ua tusia,", "It is written,"], ["E ta'ua lo'u fale, o le fale tatalo;", "My house shall be called the house of prayer;"], ["a ua faia e outou ma ana o e fao mea.", "but ye have made it a den of thieves."]]},
  {num:14,words:[["Ona o mai ai lea ia te ia i le malumalu o e tauaso ma e pipili,", "And the blind and the lame came to him in the temple;"], ["ua na faamalolo ia te i latou.", "and he healed them."]]},
  {num:15,words:[["Ua iloa atu e le au faitaulaga sili ma le au tusiupu o vavega ua faia e ia,", "And when the chief priests and scribes saw the wonderful things that he did,"], ["o tama foi ua alalaga i le malumalu,", "and the children crying in the temple,"], ["ua faapea ane,", "and saying,"], ["Osana i le alo o Tavita;", "Hosanna to the Son of David;"], ["ona matuā tiga ai lea o i latou,", "they were sore displeased,"]]},
  {num:16,words:[["ona faapea mai ai lea o i latou ia te ia,", "And said unto him,"], ["Ua e lagona ea a latou upu? Ona fetalai atu ai lea o Iesu ia te i latou,", "Hearest thou what these say? And Jesus saith unto them,"], ["Ioe;", "Yea;"], ["tou te lei faitaulia lava ea,", "have ye never read,"], ["Ua e saunia le viiga mai gutu o tama meamea ma tama fesusui?", "Out of the mouth of babes and sucklings thou hast perfected praise?"]]},
  {num:17,words:[["Ona tuua lea o i latou e ia,", "And he left them,"], ["a e maliu atu i tua o le aai ua oo i Petania,", "and went out of the city into Bethany;"], ["ua nofo ai.", "and he lodged there."]]},
  {num:18,words:[["O le taeao ua foi atu ai o ia i le aai,", "Now in the morning as he returned into the city,"], ["ua fia taumafa.", "he hungered."]]},
  {num:19,words:[["Ua silafia e ia le mati e tasi i le auala,", "And when he saw a fig tree in the way,"], ["ua oo atu i ai,", "he came to it,"], ["a e leai se mea na maua ai,", "and found nothing thereon,"], ["ua na o lau;", "but leaves only,"], ["ona faapea atu ai lea o ia i ai,", "and said unto it,"], ["Aua ne'i toe tutupu ni ou fua e oo i le faavavau. Ona mago loa lea o le mati.", "Let no fruit grow on thee henceforward for ever. And presently the fig tree withered away."]]},
  {num:20,words:[["Ua iloa atu e le au soo,", "And when the disciples saw it,"], ["ona latou taufaiofo ai lea,", "they marvelled,"], ["ua faapea ane,", "saying,"], ["Ua faapea ona vave mago o le mati nei!", "How soon is the fig tree withered away!"]]},
  {num:21,words:[["A ua tali atu Iesu,", "Jesus answered and said unto them,"], ["ua faapea atu ia te i latou,", "Verily I say unto you,"], ["E moni, ou te fai atu ia te outou,", "If ye have faith,"], ["Afai ua ia te outou le faatuatua,", "and doubt not,"], ["ma outou le masalosalo,", "ye shall not only do this which is done to the fig tree,"], ["ona faia lea e outou e le na o le mea ua faia i le mati,", "but also if ye shall say unto this mountain,"], ["a e afai tou te fai atu i lenei mauga, Ia siitia oe,", "Be thou removed,"], ["ma lafoina i le sami,", "and be thou cast into the sea;"], ["ona faia lava lea.", "it shall be done."]]},
  {num:22,words:[["O mea uma foi tou te ole mai ai i le tatalo ua i ai le faatuatua,", "And all things, whatsoever ye shall ask in prayer,"], ["e maua lava e outou.", "believing, ye shall receive."]]},
  {num:23,words:[["Ua ulufale atu ia i le malumalu, ua a'oa'o,", "And when he was come into the temple,"], ["ona o mai ai lea ia te ia o faitaulaga sili,", "the chief priests and the elders of the people came unto him as he was teaching,"], ["ma toeaina o le nuu,", "and said,"], ["ua faapea mai, O le a ea le pule e te fai ai na mea? o ai foi na na tuuina atu ia te oe lenei pule?", "By what authority doest thou these things? and who gave thee this authority?"]]},
  {num:24,words:[["Ona tali atu lea o Iesu,", "And Jesus answered and said unto them,"], ["ua faapea atu ia te i latou,", "I also will ask you one thing,"], ["Ou te fesili atu foi a'u ia te outou se upu e tasi; afai tou te ta'u mai lea ia te au,", "which if ye tell me,"], ["ona ou ta'uina atu lea le pule ou te fai ai nei mea.", "I in like wise will tell you by what authority I do these things."]]},
  {num:25,words:[["Se papatisoga ea a Ioane maifea? mai le lagi ea,", "The baptism of John,"], ["pe mai tagata? Ona latou felafolafoai ai lea,", "whence was it? from heaven,"], ["ua faapea ane,", "or of men? And they reasoned with themselves,"], ["Afai tatou te fai atu,", "saying, If we shall say,"], ["Mai le lagi;", "From heaven;"], ["ona fai mai ai lea o ia ia te i tatou,", "he will say unto us,"], ["Se a foi le mea tou te lei talitonu ai ia te ia?", "Why did ye not then believe him?"]]},
  {num:26,words:[["Afai foi tatou te fai atu,", "But if we shall say,"], ["Mai tagata;", "Of men;"], ["ua tatou fefefe i le motu o tagata; auā o la latou lea taofi uma ia Ioane,", "we fear the people;"], ["o le perofeta ia.", "for all hold John as a prophet."]]},
  {num:27,words:[["Ona latou tali mai ai lea ia Iesu,", "And they answered Jesus,"], ["ua faapea mai,", "and said,"], ["Matou te le iloa. Ona fetalai atu ai lea o ia ia te i latou,", "We cannot tell. And he said unto them,"], ["Ou te le ta'u atu foi ia te outou le pule ou te fai ai nei mea.", "Neither tell I you by what authority I do these things."]]},
  {num:28,words:[["Pe ni a fa outou? O le tasi tagata e toalua ona atalii;", "But what think ye? A certain man had two sons;"], ["ua alu atu ia i le ulumatua,", "and he came to the first,"], ["ua faapea atu, Sole,", "and said,"], ["ina alu ia i le asō,", "Son,"], ["se'i e galue i la'u tovine.", "go work to day in my vineyard."]]},
  {num:29,words:[["Ona tali mai ai lea o ia,", "He answered and said,"], ["ua faapea mai,", "I will not:"], ["Ou te musu; a e mulimuli ane ua salamo ia,", "but afterward he repented,"], ["ua alu.", "and went."]]},
  {num:30,words:[["Ona alu atu ai lea o ia i le tasi,", "And he came to the second,"], ["ua faapea foi lana upu ia te ia .", "and said likewise."], ["Ona tali mai ai lea o ia,", "And he answered and said,"], ["ua faapea mai,", "I go,"], ["Le alii e, ou te alu;", "sir:"], ["a ua le alu lava ia.", "and went not."]]},
  {num:31,words:[["O ai ea so laua na faia le loto o lo la tama? Ona latou faapea mai ai lea ia te ia,", "Whether of them twain did the will of his father? They say unto him,"], ["O le ulumatua.", "The first."], ["Ona faapea atu lea o Iesu ia te i latou,", "Jesus saith unto them,"], ["E moni, ou te fai atu ia te outou,", "Verily I say unto you,"], ["E muamua atu telona ma fafine talitane ia te outou i le malo o le Atua.", "That the publicans and the harlots go into the kingdom of God before you."]]},
  {num:32,words:[["Auā na sau Ioane ia te outou i le ala o le amiotonu,", "For John came unto you in the way of righteousness,"], ["a e tou te lei talitonu ia te ia;", "and ye believed him not:"], ["a ua talitonu ia te ia telona ma fafine talitane;", "but the publicans and the harlots believed him: and ye,"], ["ua outou iloa foi,", "when ye had seen it,"], ["a e lei mulimuli ona salamo outou,", "repented not afterward,"], ["ina ia talitonu ai ia te ia.", "that ye might believe him."]]},
  {num:33,words:[["Ia outou faalogo mai i le tasi faataoto. O le tasi matai na fai le tovine,", "Hear another parable:"], ["ua ia lotoāina i le āi,", "There was a certain householder, which planted a vineyard,"], ["ua eli ai le soligāvine,", "and hedged it round about,"], ["ua faia foi le 'olo,", "and digged a winepress in it,"], ["ua tuuina atu e ia i e galulue i vine,", "and built a tower, and let it out to husbandmen,"], ["ona alu malaga ai lea o ia i le nuu ese.", "and went into a far country:"]]},
  {num:34,words:[["Ua latalata ona po e matua ai le fuata,", "And when the time of the fruit drew near,"], ["ona aauina atu ai lea e ia o ana auauna i e galulue i vine,", "he sent his servants to the husbandmen,"], ["ia maua ona fua.", "that they might receive the fruits of it."]]},
  {num:35,words:[["Ona pupue ai lea o e galulue i vine i ana auauna,", "And the husbandmen took his servants,"], ["ua latou sasa i le tasi,", "and beat one,"], ["ma fasioti le isi,", "and killed another,"], ["ma fetogi le tasi i maa.", "and stoned another."]]},
  {num:36,words:[["Ona toe aauina atu ai lea e ia o isi auauna e sili ona toatele i e na muamua;", "Again, he sent other servants more than the first:"], ["a ua faapea lava a latou amio ia te i latou.", "and they did unto them likewise."]]},
  {num:37,words:[["A e mulimuli ane ua auina atu ai e ia o lona atalii ia te i latou,", "But last of all he sent unto them his son,"], ["ua faapea ane,", "saying,"], ["Latou te ava mai i lo'u atalii.", "They will reverence my son."]]},
  {num:38,words:[["A o ia tagata galulue i vine,", "But when the husbandmen saw the son,"], ["ua iloa atu lona atalii,", "they said among themselves,"], ["ona latou fetautalatalai ai lea, O le suli lenei;", "This is the heir;"], ["o mai ia,", "come,"], ["tatou te fasiotia o ia,", "let us kill him,"], ["a e fai mo i tatou lona fanua.", "and let us seize on his inheritance."]]},
  {num:39,words:[["Ona latou pue ai lea ia te ia,", "And they caught him,"], ["ua lafo ia te ia i tua o le tovine,", "and cast him out of the vineyard,"], ["ona latou fasiotia ai lea.", "and slew him."]]},
  {num:40,words:[["O lenei, pe a sau le alii e ona le tovine,", "When the lord therefore of the vineyard cometh,"], ["se a se mea na te faia i na tagata galulue i vine?", "what will he do unto those husbandmen?"]]},
  {num:41,words:[["Ona latou fai mai ai lea ia te ia,", "They say unto him,"], ["E matuā faaumatia e ia na tagata amio leaga;", "He will miserably destroy those wicked men,"], ["ona tuuina atu ai lea e ia o le tovine i nisi tagata galulue i vine,", "and will let out his vineyard unto other husbandmen,"], ["latou te avatu ia te ia ona fua i ona tausaga.", "which shall render him the fruits in their seasons."]]},
  {num:42,words:[["Ua fetalai atu Iesu ia te i latou,", "Jesus saith unto them,"], ["Tou te lei faitaulia lava ea i Tusi,", "Did ye never read in the scriptures,"], ["O le maa na lafoaiina e tufuga fai fale,", "The stone which the builders rejected,"], ["ua fai lea ma tulimanu aupitoaluga;", "the same is become the head of the corner:"], ["o le mea lea na faia e le Alii,", "this is the Lord's doing,"], ["tatou te ofo ai pe a vaavaai atu i ai?", "and it is marvellous in our eyes?"]]},
  {num:43,words:[["O le mea lea ou te fai atu ai ia te outou,", "Therefore say I unto you,"], ["E aveesea le malo o le Atua ia te outou,", "The kingdom of God shall be taken from you,"], ["a e tuuina atu i se nuu e au mai ai ona fua.", "and given to a nation bringing forth the fruits thereof."]]},
  {num:44,words:[["O sē paū foi i luga o lea maa,", "And whosoever shall fall on this stone shall be broken:"], ["e gāugau ai o ia; a o se tasi e paū ifo i ai le maa ,", "but on whomsoever it shall fall,"], ["e nutipalaina ai o ia.", "it will grind him to powder."]]},
  {num:45,words:[["Ua faalogo faitaulaga sili ma faresaio i ana faataoto, ona latou iloa ai lea,", "And when the chief priests and Pharisees had heard his parables,"], ["o i latou lava ia na ia fetalai mai ai.", "they perceived that he spake of them."]]},
  {num:46,words:[["Ona latou fia pue ai lea ia te ia,", "But when they sought to lay hands on him,"], ["a ua latou fefefe i le motu o tagata; auā o la latou taofi,", "they feared the multitude,"], ["o le perofeta o ia.", "because they took him for a prophet."]]},
];
renderVerseSet(mat_ch_21_Verses, 'mat-ch21-verses');

var mat_ch_22_Verses = [
  {num:1,words:[["Ona toe sauni ai lea e Iesu o faataoto,", "And Jesus answered and spake unto them again by parables,"], ["ua faapea atu ia te i latou,", "and said,"]]},
  {num:2,words:[["E tusa le malo o le lagi ma le tasi tupu ua na faia le tausamaaga o lona atalii;", "The kingdom of heaven is like unto a certain king, which made a marriage for his son,"]]},
  {num:3,words:[["ua aauina atu e ia ana auauna e fai atu i e na tala'iina ia o mai i le tausamaaga;", "And sent forth his servants to call them that were bidden to the wedding:"], ["a ua latou le mafafai ina o mai.", "and they would not come."]]},
  {num:4,words:[["Ua toe aauina atu e ia nisi auauna,", "Again,"], ["ua faapea atu,", "he sent forth other servants,"], ["Ia outou fai atu i e na tala'iina,", "saying,"], ["Faauta,", "Tell them which are bidden,"], ["ua ou saunia mea e taumafa,", "Behold, I have prepared my dinner:"], ["ua fafasi a'u povi ma a'u mea pepeti,", "my oxen and my fatlings are killed,"], ["ua saunia foi mea uma;", "and all things are ready:"], ["ina o mai ia i le tausamaaga.", "come unto the marriage."]]},
  {num:5,words:[["A ua latou faatāla ese mai,", "But they made light of it,"], ["ua taitasi ma alu,", "and went their ways,"], ["o le tasi i lona fanua,", "one to his farm,"], ["ma le tasi i lana faatau.", "another to his merchandise:"]]},
  {num:6,words:[["A o isi,", "And the remnant took his servants,"], ["ua latou pupue i ana auauna,", "and entreated them spitefully,"], ["ua faaleaga ma fasiotia.", "and slew them."]]},
  {num:7,words:[["Ua faalogo ai le tupu,", "But when the king heard thereof,"], ["ona matuā ita ai lea o ia;", "he was wroth:"], ["ua aauina atu e ia ana 'au,", "and he sent forth his armies,"], ["ua faaumatia na tagata fasi tagata,", "and destroyed those murderers,"], ["ma susunu la latou aai.", "and burned up their city."]]},
  {num:8,words:[["Ona fai atu ai lea o ia i ana auauna,", "Then saith he to his servants,"], ["Ua saunia lava le tausamaaga,", "The wedding is ready,"], ["a ua le aoga e na tala'iina.", "but they which were bidden were not worthy."]]},
  {num:9,words:[["O lenei,", "Go ye therefore into the highways,"], ["ia outou o atu i ala tele, o i latou uma tou te iloa ai,", "and as many as ye shall find,"], ["tou te tala'i i ai le tausamaaga.", "bid to the marriage."]]},
  {num:10,words:[["Ona o atu ai lea o ia auauna i ala,", "So those servants went out into the highways,"], ["ua latou faapotopoto uma e na latou iloa,", "and gathered together all as many as they found,"], ["o e leaga atoa ma e lelei;", "both bad and good:"], ["ona tumu ai lea o le mea na fai ai le tausamaaga i e na taooto e aai ai.", "and the wedding was furnished with guests."]]},
  {num:11,words:[["Ona ulufale atu ai lea o le tupu e vaavaai atu i e na taooto e aai ua iloa atu ai e ia o le tasi tagata ua le ofu i le ofu o le tausamaaga.", "And when the king came in to see the guests, he saw there a man which had not on a wedding garment:"]]},
  {num:12,words:[["Ona fai atu ai lea o ia ia te ia,", "And he saith unto him,"], ["Sole,", "Friend,"], ["pe faapefea ona e ulufale mai iinei ua le ia te oe le ofu o le tausamaaga? Ona le gagana ai lea o ia.", "how camest thou in hither not having a wedding garment? And he was speechless."]]},
  {num:13,words:[["Ona fai atu ai lea o le tupu i auauna,", "Then said the king to the servants,"], ["Ia outou fusifusia ona vae ma ona lima,", "Bind him hand and foot,"], ["ma ave o ia,", "and take him away,"], ["ma lafo i le pouliuli i fafo,", "and cast him into outer darkness;"], ["e i ai le taufaitagiane ma le lilivau o nifo.", "there shall be weeping and gnashing of teeth."]]},
  {num:14,words:[["Auā e toatele e ua tala'iina a e toaitiiti e ua filifilia.", "For many are called, but few are chosen."]]},
  {num:15,words:[["Ona o ane ai lea o le au faresaio,", "Then went the Pharisees,"], ["ma taupulepule pe faapefea ona latou mailei ia te ia i ana upu.", "and took counsel how they might entangle him in his talk."]]},
  {num:16,words:[["Ona latou aauina mai ai lea ia te ia o latou soo faatsi ma le au Herotiano,", "And they sent out unto him their disciples with the Herodians,"], ["ua faapea mai,", "saying,"], ["Le a'oa'o e,", "Master,"], ["ua matou iloa o oe le faamaoni,", "we know that thou art true,"], ["ua e a'oa'o foi i le ala o le Atua ma le faamaoni,", "and teachest the way of God in truth,"], ["e te le mata'u foi i se tasi;", "neither carest thou for any man:"], ["auā e lei faailogaina e oe se tagata.", "for thou regardest not the person of men."]]},
  {num:17,words:[["O lenei,", "Tell us therefore,"], ["ia e ta'u mai ia te i matou,", "What thinkest thou? Is it lawful to give tribute unto Caesar,"], ["pe se a lau taofi? pe sa ea ona avatu o taulaga ia Kaisara pe leai?", "or not?"]]},
  {num:18,words:[["A ua silafia e Iesu o latou loto leaga,", "But Jesus perceived their wickedness,"], ["ua faapea atu,", "and said,"], ["O outou tagata pepelo,", "Why tempt ye me,"], ["se a le mea ua outou tofotofo mai ai ia te au?", "ye hypocrites?"]]},
  {num:19,words:[["Faaali mai ia ia te au se tupe o le taulaga. Ona latou avane ai lea ia te ia o se tenari.", "Shew me the tribute money. And they brought unto him a penny."]]},
  {num:20,words:[["Ona fetalai atu lea o ia ia te i latou,", "And he saith unto them,"], ["O ai ea e ona lenei faatagata ma lenei tusi?", "Whose is this image and superscription?"]]},
  {num:21,words:[["Ua latou fai mai ia te ia,", "They say unto him,"], ["E o Kaisara.", "Caesar's."], ["Ona fetalai atu ai lea o ia ia te i latou, O lenei,", "Then saith he unto them,"], ["o mea a Kaisara,", "Render therefore unto Caesar the things which are Caesar's;"], ["ia outou avatu ia Kaisara; a o mea a le Atua ia avatu ia i le Atua.", "and unto God the things that are God's."]]},
  {num:22,words:[["Ua latou faalogo ai,", "When they had heard these words,"], ["ona latou taufaiofo ai lea;", "they marvelled,"], ["ua latou tuua ia,", "and left him,"], ["a e o ese.", "and went their way."]]},
  {num:23,words:[["O lea aso ua o mai ai ia te ia satukaio,", "The same day came to him the Sadducees,"], ["o e taofi,", "which say that there is no resurrection,"], ["e leai se toe tu;", "and asked him,"]]},
  {num:24,words:[["ua latou fesili mai ia te ia,", "Saying,"], ["ua faapea mai,", "Master,"], ["Le a'oa'o e,", "Moses said,"], ["ua fai mai Mose,", "If a man die,"], ["Afai e oti se tasi e leai sana fanau,", "having no children,"], ["ia fai lana avā ma avā a lona uso,", "his brother shall marry his wife,"], ["ia tupu ai se gafa mo lona uso.", "and raise up seed unto his brother."]]},
  {num:25,words:[["Sa ia te i matou le au uso e toafitu;", "Now there were with us seven brethren:"], ["na fai avā le ulumatua,", "and the first, when he had married a wife,"], ["ua oti foi o ia;", "deceased,"], ["e leai foi sana fanau,", "and, having no issue,"], ["o lea ua tuuina atu ai lana avā mā lona uso.", "left his wife unto his brother:"]]},
  {num:26,words:[["Na faapea foi o lona lua,", "Likewise the second also,"], ["ma lona toatolu,", "and the third,"], ["ua oo lava i le toafitu.", "unto the seventh."]]},
  {num:27,words:[["A e muliai oti foi le fafine.", "And last of all the woman died also."]]},
  {num:28,words:[["O lenei, a oo i le toe tu, o ai so latou o le toafitu e fai māna le avā? auā na fai avā uma ai.", "Therefore in the resurrection whose wife shall she be of the seven? for they all had her."]]},
  {num:29,words:[["Ona tali atu ai lea o Iesu,", "Jesus answered and said unto them,"], ["ua faapea atu ia te i latou,", "Ye do err,"], ["Ua outou sese lava, ina ua outou le iloa upu o Tusi,", "not knowing the scriptures,"], ["ma le mana o le Atua.", "nor the power of God."]]},
  {num:30,words:[["Auā a oo i le toe tu latou te le fai avā,", "For in the resurrection they neither marry,"], ["pe nofo tane,", "nor are given in marriage,"], ["a e latou te pei o agelu a le Atua o i le lagi.", "but are as the angels of God in heaven."]]},
  {num:31,words:[["A o le toe tutū mai o e ua oti,", "But as touching the resurrection of the dead,"], ["tou te lei faitau ai ea le afioga a le Atua ia te outou,", "have ye not read that which was spoken unto you by God,"], ["ua faapea mai,", "saying,"]]},
  {num:32,words:[["O a'u nei o le Atua o Aperaamo,", "I am the God of Abraham,"], ["o le Atua foi o Isaako,", "and the God of Isaac,"], ["o le Atua foi o Iakopo? o le Atua e le se Atua ia o e ua oti,", "and the God of Jacob? God is not the God of the dead,"], ["a o e ola.", "but of the living."]]},
  {num:33,words:[["Ua faalogo ai le motu o tagata,", "And when the multitude heard this,"], ["ona latou taufaiofo ai lea i lana mataupu.", "they were astonished at his doctrine."]]},
  {num:34,words:[["Ua faalogo le au faresaio ua le mautali ia te ia le au satukaio,", "But when the Pharisees had heard that he had put the Sadducees to silence,"], ["ona latou faapotopoto mai ai lea i lea mea,", "they were gathered together."]]},
  {num:35,words:[["ona fesili faatofotofo mai ai lea ia te ia o so latou,", "Then one of them, which was a lawyer,"], ["o le a'oa'o tulafono,", "asked him a question,"], ["ua faapea mai,", "tempting him, and saying,"]]},
  {num:36,words:[["Le a'oa'o e,", "Master,"], ["o le fea poloaiga o i le tulafono ua sili.?", "which is the great commandment in the law?"]]},
  {num:37,words:[["Ona fetalai atu ai lea o Iesu ia te ia,", "Jesus said unto him,"], ["E te alofa atu i le Alii lou Atua ma lou loto atoa,", "Thou shalt love the Lord thy God with all thy heart,"], ["ma lou agaga atoa,", "and with all thy soul,"], ["ma lou manatu atoa.", "and with all thy mind."]]},
  {num:38,words:[["O le poloaiga muamua lena ma le sili.", "This is the first and great commandment."]]},
  {num:39,words:[["E faapena foi lona lua, E te alofa atu i lē lua te tuaoi,", "And the second is like unto it,"], ["ia pei o oe lava ia te oe.", "Thou shalt love thy neighbour as thyself."]]},
  {num:40,words:[["O nā poloaiga e lua ua autu ai le tulafono uma ma le au perofeta.", "On these two commandments hang all the law and the prophets."]]},
  {num:41,words:[["Ua faapotopoto le au faresaio,", "While the Pharisees were gathered together,"], ["ona fesili atu ai lea o Iesu ia te i latou,", "Jesus asked them,"]]},
  {num:42,words:[["ua faapea atu,", "Saying,"], ["Se a la outou taofi i le Keriso? se atalii ea ia o ai? Ona latou fai mai ai lea ia te ia,", "What think ye of Christ? whose son is he? They say unto him,"], ["O le alo o Tavita.", "The Son of David."]]},
  {num:43,words:[["Ona fetalai atu ai lea o ia ia te i latou, O lenei,", "He saith unto them,"], ["pe faapefea ona ta'ua e Tavita e le Agaga,", "How then doth David in spirit call him Lord,"], ["o ia o lona Alii, ua faapea mai,", "saying,"]]},
  {num:44,words:[["Ua fetalai ane le Alii i lo'u Alii,", "The LORD said unto my Lord,"], ["Ia e nofo i lo'u itu taumatau,", "Sit thou on my right hand,"], ["seia ou faia e ua fai oe mo latou fili ma mea e tu ai ou vae.", "till I make thine enemies thy footstool?"]]},
  {num:45,words:[["O lenei, afai ua ta'ua o ia e Tavita,", "If David then call him Lord,"], ["o le Alii, pe faapefea ona fai o ia mona atalii?", "how is he his son?"]]},
  {num:46,words:[["A e leai se tasi ua na mafaia ona tali mai se upu ia te ia;", "And no man was able to answer him a word,"], ["talu lea aso e le toe faamalosi ona fesili mai se tasi ia te ia i se mea.", "neither durst any man from that day forth ask him any more questions."]]},
];
renderVerseSet(mat_ch_22_Verses, 'mat-ch22-verses');

var mat_ch_23_Verses = [
  {num:1,words:[["Ona fetalai atu ai lea o Iesu i le motu o tagata ma ona soo,", "Then spake Jesus to the multitude,"], ["ua faapea atu,", "and to his disciples,"]]},
  {num:2,words:[["Ua tietie le au tusiupu ma le au faresaio i le nofoa o Mose;", "Saying, The scribes and the Pharisees sit in Moses' seat:"]]},
  {num:3,words:[["o lea ia outou anaana ai ma ia outou faia mea uma latou te fai atu ai ia te outou e anaana i ai;", "All therefore whatsoever they bid you observe,"], ["a e aua tou te faaa'oa'o i a latou amio;", "that observe and do;"], ["auā ua latou fai atu,", "but do not ye after their works: for they say,"], ["a e latou te le faia.", "and do not."]]},
  {num:4,words:[["Auā ua latou saisai avega mamafa ma le avegata,", "For they bind heavy burdens and grievous to be borne,"], ["ma latou faaee i ua o tagata;", "and lay them on men's shoulders;"], ["a e latou te le mafafai ina faagaoioi ai i so latou tamatamai lima.", "but they themselves will not move them with one of their fingers."]]},
  {num:5,words:[["Ua latou fai a latou galuega uma,", "But all their works they do for to be seen of men:"], ["ina ia iloa ai e tagata; ua latou faalautele i a latou filateri,", "they make broad their phylacteries,"], ["ma faatele i tuupao o latou ofu.", "and enlarge the borders of their garments,"]]},
  {num:6,words:[["Ua latou fiafia foi i le mea sili e taoto ai i faigaai,", "And love the uppermost rooms at feasts,"], ["ma nofoa sili i sunako,", "and the chief seats in the synagogues,"]]},
  {num:7,words:[["ma ia alofaina i latou i malae,", "And greetings in the markets,"], ["ia ta'ua foi i latou e tagata,", "and to be called of men,"], ["Rapi e,", "Rabbi,"], ["rapi e.", "Rabbi."]]},
  {num:8,words:[["A o outou,", "But be not ye called Rabbi:"], ["aua ne'i ta'ua outou o rapi;", "for one is your Master,"], ["auā e toatasi la outou a'oa'o, o le Keriso lea;", "even Christ;"], ["a o outou uma o le au uso outou.", "and all ye are brethren."]]},
  {num:9,words:[["Aua foi ne'i tou ta'ua se tasi i le lalolagi o lo outou tamā;", "And call no man your father upon the earth:"], ["auā e toatasi lo outou Tamā,", "for one is your Father,"], ["o i le lagi ia.", "which is in heaven."]]},
  {num:10,words:[["Aua foi ne'i ta'ua outou o a'oa'o;", "Neither be ye called masters:"], ["auā e toatasi la outou a'oa'o,", "for one is your Master,"], ["o le Keriso lea.", "even Christ."]]},
  {num:11,words:[["A o lē sili ia te outou e fai lea ma a outou auauna.", "But he that is greatest among you shall be your servant."]]},
  {num:12,words:[["O sē faamaualuga o ia ia te ia, e faamaulaloina lea;", "And whosoever shall exalt himself shall be abased;"], ["a o sē faamaulalo o ia ia te ia, e faamaualugaina lea.", "and he that shall humble himself shall be exalted."]]},
  {num:13,words:[["Oi talofa ia te outou tusiupu ma faresaio,", "But woe unto you,"], ["tagata pepelo! auā ua outou pupuni le malo o le lagi i tagata;", "scribes and Pharisees,"], ["auā tou te le ulu atu i ai outou,", "hypocrites! for ye shut up the kingdom of heaven against men: for ye neither go in yourselves,"], ["ua outou vavao foi i e a ulu atu i ai.", "neither suffer ye them that are entering to go in."]]},
  {num:14,words:[["Oi talofa ia te outou tusiupu ma faresaio,", "Woe unto you,"], ["tagata pepelo! auā ua outou faauma fale o fafine ua oti a latou tane,", "scribes and Pharisees,"], ["ua faaleleva foi a outou tatalo e fai ma ufiufi;", "hypocrites! for ye devour widows' houses, and for a pretence make long prayer:"], ["o le mea lea e atili ai lava ona faasalaina outou.", "therefore ye shall receive the greater damnation."]]},
  {num:15,words:[["Oi talofa ia te outou tusiupu ma faresaio,", "Woe unto you,"], ["tagata pepelo! auā ua soo le sami ma le laueleele ia te outou ina ia lotu mai o se tasi;", "scribes and Pharisees,"], ["pe a maua foi o ia,", "hypocrites! for ye compass sea and land to make one proselyte, and when he is made,"], ["ona outou faia lea o ia ma tagata o Kēna ua sili ona leaga ia te outou.", "ye make him twofold more the child of hell than yourselves."]]},
  {num:16,words:[["Oi talofa ia te outou ta'ita'i tauaso! o e fai mai,", "Woe unto you,"], ["Ai sē tauto i le malumalu,", "ye blind guides, which say,"], ["ua leai lea;", "Whosoever shall swear by the temple,"], ["a o sē tauto i le auro o le malumalu,", "it is nothing; but whosoever shall swear by the gold of the temple,"], ["ua mau lea.", "he is a debtor!"]]},
  {num:17,words:[["Tagata vālea e ma le tauaso;", "Ye fools and blind:"], ["auā o le fea ua sili,", "for whether is greater,"], ["o le auro ea,", "the gold,"], ["po o le malumalu ua paia ai le auro?", "or the temple that sanctifieth the gold?"]]},
  {num:18,words:[["I le ma lea,", "And,"], ["Ai sē tauto i le fata faitaulaga,", "Whosoever shall swear by the altar,"], ["ua leai lea;", "it is nothing;"], ["a o sē tauto i le taulaga ua i ona luga,", "but whosoever sweareth by the gift that is upon it,"], ["ua mau lea.", "he is guilty."]]},
  {num:19,words:[["Tagata vālea e ma le tauaso;", "Ye fools and blind:"], ["auā o le fea ua sili,", "for whether is greater,"], ["o le taulaga ea,", "the gift,"], ["po o le fata faitaulaga ua paia ai le taulaga?", "or the altar that sanctifieth the gift?"]]},
  {num:20,words:[["O lenei,", "Whoso therefore shall swear by the altar,"], ["o lē tauto i le fata faitaulaga, ua ia tauto i ai,", "sweareth by it,"], ["ma mea uma ua i ona luga;", "and by all things thereon."]]},
  {num:21,words:[["o lē tauto foi i le malumalu,", "And whoso shall swear by the temple,"], ["ua ia tauto i ai,", "sweareth by it,"], ["ma loo afio ai.", "and by him that dwelleth therein."]]},
  {num:22,words:[["O lē tauto foi i le lagi,", "And he that shall swear by heaven,"], ["ua ia tauto i le nofoālii o le Atua,", "sweareth by the throne of God,"], ["ma loo tietie ai.", "and by him that sitteth thereon."]]},
  {num:23,words:[["Oi talofa ia te outou tusiupu ma faresaio,", "Woe unto you,"], ["tagata pepelo! ua outou avatu mea e sefulu a'i o le mili,", "scribes and Pharisees,"], ["ma le aneto,", "hypocrites! for ye pay tithe of mint and anise and cummin,"], ["ma le kumina,", "and have omitted the weightier matters of the law,"], ["a ua tuu e outou o mea silisili o i le tulafono, o le amiotonu,", "judgment,"], ["ma le alofa,", "mercy,"], ["ma le faamaoni;", "and faith:"], ["e tatau pe ana faia nei mea,", "these ought ye to have done,"], ["a e aua foi le tuu na mea.", "and not to leave the other undone."]]},
  {num:24,words:[["O outou ta'ita'i tauaso,", "Ye blind guides,"], ["ua outou faapilia le namu,", "which strain at a gnat,"], ["a ua outou folo atoa le kamela.", "and swallow a camel."]]},
  {num:25,words:[["Oi talofa ia te outou tusiupu ma faresaio,", "Woe unto you,"], ["tagata pepelo! ua outou faamamā i le tua o le ipu ma le tanoa,", "scribes and Pharisees, hypocrites! for ye make clean the outside of the cup and of the platter,"], ["a o totonu ua tutumu i mea ua faoa ma le amio leaga.", "but within they are full of extortion and excess."]]},
  {num:26,words:[["O oe na le faresaio tauaso,", "Thou blind Pharisee,"], ["ia e muai faamamā i totonu o le ipu ma le tanoa,", "cleanse first that which is within the cup and platter,"], ["ina ia mamā atoa ma le tua.", "that the outside of them may be clean also."]]},
  {num:27,words:[["Oi talofa ia te outou tusiupu ma faresaio,", "Woe unto you,"], ["tagata pepelo! auā e tutusa outou ma tuugamau ua faasinasinaina,", "scribes and Pharisees,"], ["o loo matagofie i fafo,", "hypocrites! for ye are like unto whited sepulchres, which indeed appear beautiful outward,"], ["a o totonu ua tutumu i ivi o tagata oti,", "but are within full of dead men's bones,"], ["ma mea leaga uma.", "and of all uncleanness."]]},
  {num:28,words:[["E faapea foi outou, o fafo ua mataamiotonu i luma o tagata,", "Even so ye also outwardly appear righteous unto men,"], ["a o totonu, ua tutumu outou i le pepelo ma le amioletonu.", "but within ye are full of hypocrisy and iniquity."]]},
  {num:29,words:[["Oi talofa ia te outou tusiupu ma faresaio,", "Woe unto you,"], ["tagata pepelo! auā ua outou ati ae tuugamau o perofeta,", "scribes and Pharisees, hypocrites! because ye build the tombs of the prophets,"], ["ua outou teuteu foi loa o tagata amiotonu,", "and garnish the sepulchres of the righteous,"]]},
  {num:30,words:[["ma outou faapea ane,", "And say,"], ["Ana matou i ai i ia ona po o matou tamā,", "If we had been in the days of our fathers,"], ["po ua matou le 'au faatasi ma i latou i le fāsiga o perofeta", "we would not have been partakers with them in the blood of the prophets."]]},
  {num:31,words:[["O lea, ua molia ai outou e outou,", "Wherefore ye be witnesses unto yourselves,"], ["o fanau outou a e na fasiotia perofeta.", "that ye are the children of them which killed the prophets."]]},
  {num:32,words:[["O outou foi, ia outou faatumuina le fua a o outou tamā.", "Fill ye up then the measure of your fathers."]]},
  {num:33,words:[["O outou gata,", "Ye serpents,"], ["o fanau a gata feai,", "ye generation of vipers,"], ["pe faapefea ona outou sosola i le faasala i Kēna?", "how can ye escape the damnation of hell?"]]},
  {num:34,words:[["Faauta mai,", "Wherefore,"], ["o le mea lea ou te aauina atu ai ia te outou o perofeta,", "behold,"], ["ma tagata popoto,", "I send unto you prophets,"], ["ma tusiupu;", "and wise men,"], ["o isi o i latou tou te fāsiotia ma faasatauroina;", "and scribes:"], ["a o isi,", "and some of them ye shall kill and crucify;"], ["tou te sasaina i o outou sunako,", "and some of them shall ye scourge in your synagogues,"], ["ma tulituliloa ia te i latou i lea aai ma lea aai;", "and persecute them from city to city:"]]},
  {num:35,words:[["ina ia oo ia te outou le toto uma o e amiotonu ua faamaligiina i le lalolagi,", "That upon you may come all the righteous blood shed upon the earth,"], ["e afua i le toto o Apelu le tagata amiotonu, e oo i le toto o Sakaria le atalii o Parakaio,", "from the blood of righteous Abel unto the blood of Zacharias son of Barachias,"], ["na outou fasiotia i le va o le malumalu ma le fata faitaulaga.", "whom ye slew between the temple and the altar."]]},
  {num:36,words:[["E moni, ou te fai atu ia te outou,", "Verily I say unto you,"], ["e oo mai nei mea uma i luga o lenei tupulaga.", "All these things shall come upon this generation."]]},
  {num:37,words:[["Ierusalema e,", "O Jerusalem,"], ["Ierusalema e,", "Jerusalem,"], ["o lē fasiotia perofeta,", "thou that killest the prophets, and stonest them which are sent unto thee,"], ["ma fetogi i maa i e ua aauina atu ia te oe;", "how often would I have gathered thy children together,"], ["ua tele lava o'u manao e faapotopoto i lau fanau,", "even as a hen gathereth her chickens under her wings,"], ["e pei o le moa ona ofaofatai i lana toloai i lalo i ona apaau a e lei mafafai outou.", "and ye would not!"]]},
  {num:38,words:[["Faauta, ua tuua lo outou fale,", "Behold,"], ["e faatafunaina.", "your house is left unto you desolate."]]},
  {num:39,words:[["Auā ou te fai atu ia te outou,", "For I say unto you,"], ["tou te le toe iloa mai a'u,", "Ye shall not see me henceforth,"], ["seia outou fai mai,", "till ye shall say,"], ["Ia manuia lē maliu mai i le suafa o le Alii.", "Blessed is he that cometh in the name of the Lord."]]},
];
renderVerseSet(mat_ch_23_Verses, 'mat-ch23-verses');

var mat_ch_24_Verses = [
  {num:1,words:[["Ona ulufafo lea o Iesu,", "And Jesus went out,"], ["ua maliu ese i le malumalu;", "and departed from the temple:"], ["ona o mai ai lea o ona soo ia te ia e faasino ia te ia i fale o le malumalu.", "and his disciples came to him for to shew him the buildings of the temple."]]},
  {num:2,words:[["A ua fetalai atu Iesu ia te i latou,", "And Jesus said unto them,"], ["Ua outou le iloa ea nei mea uma? E moni,", "See ye not all these things? verily I say unto you,"], ["ou te fai atu ia te outou, e le toe ai se maa i luga o le tasi maa,", "There shall not be left here one stone upon another,"], ["a e uma ona sŏloia i lalo.", "that shall not be thrown down."]]},
  {num:3,words:[["Ua nofo o ia i le mauga o Olive,", "And as he sat upon the mount of Olives,"], ["ona o mai ai lea o le au soo ia te ia ua na o i latou,", "the disciples came unto him privately,"], ["ua faapea mai,", "saying, Tell us,"], ["Ia e fetalai mai ia te i matou pe oo afea ia mea? pe se a foi le faailoga o lou maliu mai,", "when shall these things be? and what shall be the sign of thy coming,"], ["ma le gataaga o le lalolagi?", "and of the end of the world?"]]},
  {num:4,words:[["Ona tali atu ai lea o Iesu, ua faapea atu ia te i latou,", "And Jesus answered and said unto them,"], ["Ia outou, ne'i faaseseina outou e se tasi.", "Take heed that no man deceive you."]]},
  {num:5,words:[["Auā e toatele e o mai i lo'u igoa,", "For many shall come in my name,"], ["ua faapea ane,", "saying,"], ["O a'u nei o le Keriso;", "I am Christ;"], ["latou te faaseseina foi tagata e toatele.", "and shall deceive many."]]},
  {num:6,words:[["E faalogo outou i taua ma tala o taua;", "And ye shall hear of wars and rumours of wars:"], ["ia outou,", "see that ye be not troubled:"], ["ne'i tou atuatuvale; auā e ao ona taunuu o nei mea uma,", "for all these things must come to pass,"], ["a e lei oo i le gataaga.", "but the end is not yet."]]},
  {num:7,words:[["Auā e sii le taua e le tasi nuu i le tasi nuu,", "For nation shall rise against nation,"], ["ma le tasi malo i le tasi malo;", "and kingdom against kingdom:"], ["ona oo mai ai lea o oge,", "and there shall be famines, and pestilences,"], ["ma faamai,", "and earthquakes,"], ["ma mafuie i lea mea ma lea mea.", "in divers places."]]},
  {num:8,words:[["O na mea uma o le amataga ia o puapuaga.", "All these are the beginning of sorrows."]]},
  {num:9,words:[["Ona latou tuuina atu ai lea o outou i le puapuaga,", "Then shall they deliver you up to be afflicted,"], ["ma latou fasiotia outou,", "and shall kill you:"], ["e inosia foi outou e nuu uma ona o lo'u igoa.", "and ye shall be hated of all nations for my name's sake."]]},
  {num:10,words:[["O ona po ia e tausuai ai tagata e toatele,", "And then shall many be offended,"], ["e faalata le tasi i le tasi,", "and shall betray one another,"], ["ma feitagai i latou.", "and shall hate one another."]]},
  {num:11,words:[["E tutū mai foi perofeta pepelo e toatele,", "And many false prophets shall rise,"], ["latou te faasese foi i tagata e toatele.", "and shall deceive many."]]},
  {num:12,words:[["E maalili foi loto o tagata e toatele,", "And because iniquity shall abound,"], ["ona ua tupu tele o le amio leaga.", "the love of many shall wax cold."]]},
  {num:13,words:[["A o lē tumau seia oo i le gataaga,", "But he that shall endure unto the end,"], ["e faaolaina lea.", "the same shall be saved."]]},
  {num:14,words:[["E tala'iina atu foi lenei tala lelei o le malo i le atu laulau uma, e fai ma molimau i nuu uma;", "And this gospel of the kingdom shall be preached in all the world for a witness unto all nations;"], ["ona oo mai ai lea o le gataaga.", "and then shall the end come."]]},
  {num:15,words:[["Pe a iloa foi e outou le mea e inosia e faatafunaina a'i,", "When ye therefore shall see the abomination of desolation,"], ["na fai mai ai e le perofeta o Tanielu,", "spoken of by Daniel the prophet,"], ["ua tu i le mea paia,", "stand in the holy place, (whoso readeth,"], ["(ina mafaufau ia o lē faitau;", "let him understand:"], [")", ")"]]},
  {num:16,words:[["o e o i Iutaia i ia ona po, ia latou sosola i mauga;", "Then let them which be in Judaea flee into the mountains:"]]},
  {num:17,words:[["o le ua i luga o le fale, aua ne'i alu ifo ia e ave se mea ai lona fale;", "Let him which is on the housetop not come down to take any thing out of his house:"]]},
  {num:18,words:[["o le ua i le vao foi, aua ne'i foi atu e ave ona ofu.", "Neither let him which is in the field return back to take his clothes."]]},
  {num:19,words:[["Oi talofa foi i fafine totō,", "And woe unto them that are with child,"], ["ma ē failele i ia ona po.", "and to them that give suck in those days!"]]},
  {num:20,words:[["A ia outou tatalo ina ne'i outou sosola i le tausaga maalili,", "But pray ye that your flight be not in the winter,"], ["po o le sapati.", "neither on the sabbath day:"]]},
  {num:21,words:[["Auā o ia ona po e oo ai le puapuaga tele,", "For then shall be great tribulation,"], ["e leai sona tusa talu le amataga o le lalolagi,", "such as was not since the beginning of the world to this time,"], ["ua oo lava i ona po nei;", "no,"], ["e le toe faapea foi amuli.", "nor ever shall be."]]},
  {num:22,words:[["A le faapuupuuina foi ia aso,", "And except those days should be shortened,"], ["e le faaolaina se tasi;", "there should no flesh be saved:"], ["a e faapuupuuina ia aso ona o e ua filifilia.", "but for the elect's sake those days shall be shortened."]]},
  {num:23,words:[["Afai e fai ane se tasi ia te outou i ia ona po,", "Then if any man shall say unto you,"], ["Faauta,", "Lo,"], ["o iinei le Keriso,", "here is Christ,"], ["po o iila;", "or there;"], ["aua tou te faalogo i ai.", "believe it not."]]},
  {num:24,words:[["Auā e tutū mai Keriso pepelo,", "For there shall arise false Christs,"], ["ma perofeta pepelo,", "and false prophets,"], ["latou te faia foi faailoga tetele ma vavega,", "and shall shew great signs and wonders; insomuch that,"], ["ina ia faasese ai i e ua filifilia lava,", "if it were possible,"], ["pe afai e mafai ai.", "they shall deceive the very elect."]]},
  {num:25,words:[["Faauta,", "Behold,"], ["ua ou muai ta'uina atu ai ia te outou.", "I have told you before."]]},
  {num:26,words:[["O lea,", "Wherefore if they shall say unto you,"], ["afai latou te fai mai ai ia te outou,", "Behold,"], ["Faauta,", "he is in the desert;"], ["o i le vao ia; aua tou te o atu i ai;", "go not forth:"], ["faauta,", "behold,"], ["o i se afeafe ia;", "he is in the secret chambers;"], ["aua tou te faalogo i ai .", "believe it not."]]},
  {num:27,words:[["Auā e pei ona emo mai o le uila i sasae,", "For as the lightning cometh out of the east,"], ["ma malamalama atu i sisifo;", "and shineth even unto the west;"], ["e faapea foi ona sau o le Atalii o le tagata.", "so shall also the coming of the Son of man be."]]},
  {num:28,words:[["Auā o le mea ua i ai le tagata oti,", "For wheresoever the carcase is,"], ["e aofaga i ai aeto.", "there will the eagles be gathered together."]]},
  {num:29,words:[["A mavae atu le puapuaga o ia ona aso,", "Immediately after the tribulation of those days shall the sun be darkened,"], ["ona faapogisaina loa lea o le la,", "and the moon shall not give her light,"], ["e le susulu mai foi le masina, e pauu foi fetu mai le lagi,", "and the stars shall fall from heaven,"], ["e luluina foi 'au a le lagi.", "and the powers of the heavens shall be shaken:"]]},
  {num:30,words:[["Ona iloa ai lea i le lagi o le faailoga o le Atalii o le tagata;", "And then shall appear the sign of the Son of man in heaven:"], ["ona taufaitagitu'i ai lea o itu aiga uma o le lalolagi;", "and then shall all the tribes of the earth mourn,"], ["latou te iloa atu foi le Atalii o le tagata ua sau i ao o le lagi ma le mana ma le mamalu tele.", "and they shall see the Son of man coming in the clouds of heaven with power and great glory."]]},
  {num:31,words:[["E aauina atu foi e ia o ana agelu ma le leo tele o le pu,", "And he shall send his angels with a great sound of a trumpet,"], ["latou te faapotopoto foi i e ua filifilia e ia mai matāmatagi e fa, e amata i le tasi tulu'iga o le lagi,", "and they shall gather together his elect from the four winds,"], ["e oo i le tasi tulu'iga.", "from one end of heaven to the other."]]},
  {num:32,words:[["Ia outou mataulia le faataoto i le mati;", "Now learn a parable of the fig tree;"], ["pe a faatoa tutupu ona tatupu,", "When his branch is yet tender,"], ["ma matala mai ona lau,", "and putteth forth leaves,"], ["tou te iloa ai ua latalata le tausaga vevela.", "ye know that summer is nigh:"]]},
  {num:33,words:[["E faapea foi outou,", "So likewise ye,"], ["pe a outou iloa ia mea uma,", "when ye shall see all these things,"], ["tou te iloa ai, ua latalata ia,", "know that it is near,"], ["ua i faitotoa lava.", "even at the doors."]]},
  {num:34,words:[["E moni,", "Verily I say unto you,"], ["ou te fai atu ia te outou, E le mavae atu lava lenei tupulaga,", "This generation shall not pass,"], ["seia oo mai nei mea uma.", "till all these things be fulfilled."]]},
  {num:35,words:[["E mavae atu le lagi ma le lalolagi,", "Heaven and earth shall pass away,"], ["a o a'u upu e le mavae atu lava ia.", "but my words shall not pass away."]]},
  {num:36,words:[["A o lea aso ma lea itu aso e le iloa e se tasi,", "But of that day and hour knoweth no man,"], ["e le iloa lava e agelu i le lagi,", "no, not the angels of heaven,"], ["ua na o lo'u Tamā lava.", "but my Father only."]]},
  {num:37,words:[["A e pei o ona po o Noa,", "But as the days of Noe were,"], ["e faapea foi pe a sau le Atalii o le tagata.", "so shall also the coming of the Son of man be."]]},
  {num:38,words:[["Auā e pei ona faia i ona po a o lei oo le lolo,", "For as in the days that were before the flood they were eating and drinking,"], ["ua latou aai ma inu, ua latou fai avā foi ma faaavaga,", "marrying and giving in marriage,"], ["ua oo lava i le aso na ulu atu ai Noa i le vaa,", "until the day that Noe entered into the ark,"]]},
  {num:39,words:[["na le iloa foi e i latou ina seia oo le lolo,", "And knew not until the flood came,"], ["ma aveesea i latou uma;", "and took them all away;"], ["e faapea foi pe a sau le Atalii o le tagata.", "so shall also the coming of the Son of man be."]]},
  {num:40,words:[["O ia ona po e i ai i le vao o tagata e toalua,", "Then shall two be in the field;"], ["e avea le tasi,", "the one shall be taken,"], ["a e tuua le tasi.", "and the other left."]]},
  {num:41,words:[["E olo faatasi fafine e toalua i le mea e olo a'i saito,", "Two women shall be grinding at the mill;"], ["e avea le tasi,", "the one shall be taken,"], ["a e tuua le tasi.", "and the other left."]]},
  {num:42,words:[["O lea, ia outou mataala ai;", "Watch therefore:"], ["auā tou te le iloa po o le fea itu aso e sau ai lo outou Alii.", "for ye know not what hour your Lord doth come."]]},
  {num:43,words:[["Ia outou iloa lenei mea,", "But know this,"], ["ana iloa e le matai o le aiga po o le fea itu po e sau ai le gaoi,", "that if the goodman of the house had known in what watch the thief would come,"], ["po ua na leoleoina,", "he would have watched,"], ["a e le tuua e ia lona fale ia elia.", "and would not have suffered his house to be broken up."]]},
  {num:44,words:[["O le mea lea ia outou nofo sauni ai;", "Therefore be ye also ready:"], ["auā o le itu aso tou te le manatunatu ai e sau ai le Atalii o le tagata.", "for in such an hour as ye think not the Son of man cometh."]]},
  {num:45,words:[["O ai foi le auauna faamaoni ma le mafaufau,", "Who then is a faithful and wise servant,"], ["ua tofia e lona alii e pule i ana auauna,", "whom his lord hath made ruler over his household,"], ["ia avatu a latou mea e 'ai i ona itu aso?", "to give them meat in due season?"]]},
  {num:46,words:[["Amuia lea auauna,", "Blessed is that servant,"], ["pe a sau lona alii e maua o ia o loo faapea ona fai.", "whom his lord when he cometh shall find so doing."]]},
  {num:47,words:[["E moni, ou te fai atu ia te outou,", "Verily I say unto you,"], ["e tofia o ia e pule i ana mea uma.", "That he shall make him ruler over all his goods."]]},
  {num:48,words:[["A e afai e fai ifo lea auauna leaga i lona loto,", "But and if that evil servant shall say in his heart,"], ["E faatuai mai lo'u alii;", "My lord delayeth his coming;"]]},
  {num:49,words:[["ona fasi ai lea o ia i ona uso a auauna,", "And shall begin to smite his fellowservants,"], ["ua aai foi ma inu faatasi ma e inu ia onā;", "and to eat and drink with the drunken;"]]},
  {num:50,words:[["e sau lava le alii o lea auauna i le aso e le faatalitali atu ai o ia, o le itu aso foi e le iloa ai e ia,", "The lord of that servant shall come in a day when he looketh not for him,"], ["ona matuā faasala lea ia te ia,", "and in an hour that he is not aware of,"]]},
  {num:51,words:[["ma avatu ia te ia lona tofi faatasi ma tagata pepelo;", "And shall cut him asunder, and appoint him his portion with the hypocrites:"], ["e i ai le taufaitagiaue ma le lilivau o nifo.", "there shall be weeping and gnashing of teeth."]]},
];
renderVerseSet(mat_ch_24_Verses, 'mat-ch24-verses');

var mat_ch_25_Verses = [
  {num:1,words:[["O ia ona po e tusa ai le malo o le lagi ma taupou e toasefulu,", "Then shall the kingdom of heaven be likened unto ten virgins,"], ["o e na ave a latou lamepa,", "which took their lamps,"], ["ma latou o atu e faafetaiai i le faatoafaiavā.", "and went forth to meet the bridegroom."]]},
  {num:2,words:[["Ua popoto le toalima o i latou,", "And five of them were wise,"], ["a e vālea le toalima.", "and five were foolish."]]},
  {num:3,words:[["O e vālea ua ave a latou lamepa,", "They that were foolish took their lamps,"], ["a e lei avea ma ni suāuu.", "and took no oil with them:"]]},
  {num:4,words:[["A o e popoto ua ave ni suāuu i a latou fagu faatasi ma a latou lamepa.", "But the wise took oil in their vessels with their lamps."]]},
  {num:5,words:[["Ua tuai mai le faatoafaiavā, ona taufaitulemomoe ai lea o i latou uma,", "While the bridegroom tarried,"], ["ua momoe lava.", "they all slumbered and slept."]]},
  {num:6,words:[["A ua oo i le tulua o po,", "And at midnight there was a cry made,"], ["ona sau ai lea o lē alaga,", "Behold,"], ["Faauta, ua sau le faatoafaiavā;", "the bridegroom cometh;"], ["ina o ia outou e faafetaiai ia te ia.", "go ye out to meet him."]]},
  {num:7,words:[["Ona tutū ai lea o ia taupou uma lava,", "Then all those virgins arose,"], ["ma teuteu a latou lamepa.", "and trimmed their lamps."]]},
  {num:8,words:[["Ona fai atu ai lea o e vālea i e popoto,", "And the foolish said unto the wise,"], ["Au mai ni a outou suāuu mā matou;", "Give us of your oil;"], ["auā o le a mamate a matou lamepa.", "for our lamps are gone out."]]},
  {num:9,words:[["A ua tali mai o e popoto,", "But the wise answered, saying,"], ["ua faapea mai,", "Not so;"], ["Ne'i le lava ia i matou ma outou;", "lest there be not enough for us and you:"], ["a e lelei ona outou o i e faatau ma faatau mai ai ni a outou.", "but go ye rather to them that sell, and buy for yourselves."]]},
  {num:10,words:[["Ua latou o e faatau,", "And while they went to buy,"], ["ona sau ai lea o le faatoafaiavā;", "the bridegroom came;"], ["o e ua saunia foi ua latou ulufale atu faatasi ma ia i le tausamaaga,", "and they that were ready went in with him to the marriage:"], ["ona pupuni ai lea o le faitotoa.", "and the door was shut."]]},
  {num:11,words:[["E mulimuli ane,", "Afterward came also the other virgins,"], ["ona o mai ai lea o isi taupou,", "saying,"], ["ua faapea mai, Le Alii e,", "Lord,"], ["le alii e,", "Lord,"], ["ia e tatala atu le puipui mo i matou.", "open to us."]]},
  {num:12,words:[["A ua tali atu o ia, ua faapea atu,", "But he answered and said,"], ["E moni,", "Verily I say unto you,"], ["ou te fai atu ia te outou, ou te le iloa outou.", "I know you not."]]},
  {num:13,words:[["O lea, ia outou mataala ai,", "Watch therefore,"], ["auā tou te le iloa le aso po o le itu aso e sau ai le Atalii o le tagata.", "for ye know neither the day nor the hour wherein the Son of man cometh."]]},
  {num:14,words:[["E faapei o le tagata foi na alu malaga,", "For the kingdom of heaven is as a man travelling into a far country,"], ["ua valaau i ana auauna,", "who called his own servants,"], ["ona tuuina atu ai lea e ia o ana mea ia te i latou.", "and delivered unto them his goods."]]},
  {num:15,words:[["Ua avatu e ia taleni e lima i le tasi,", "And unto one he gave five talents,"], ["a e lua a le tasi,", "to another two,"], ["a e tasi i le tasi;", "and to another one;"], ["ua faatatau i le mea ua mafai ai e le tagata;", "to every man according to his several ability;"], ["ona alu loa lea o ia i lana malaga.", "and straightway took his journey."]]},
  {num:16,words:[["Ona alu ai lea o le na i ai taleni e lima na faatau atu ai,", "Then he that had received the five talents went and traded with the same,"], ["ua maua ai foi isi taleni e lima.", "and made them other five talents."]]},
  {num:17,words:[["Ua faapea foi o le na i ai taleni e lua,", "And likewise he that had received two,"], ["ua maua ai foi e ia le tasi lua.", "he also gained other two."]]},
  {num:18,words:[["A o le na i ai le tasi, ua alu ma eli i le eleele,", "But he that had received one went and digged in the earth,"], ["ua nā ai ario a lona alii.", "and hid his lord's money."]]},
  {num:19,words:[["Ua mavae po e tele, ona sau ai lea o le alii o ia auauna,", "After a long time the lord of those servants cometh,"], ["ua faamasino i ana mea ua ia te i latou.", "and reckoneth with them."]]},
  {num:20,words:[["Ona sau ai lea o le ua i ai taleni e lima ua au mai isi taleni e lima,", "And so he that had received five talents came and brought other five talents,"], ["ua faapea mai,", "saying,"], ["Le alii e,", "Lord,"], ["na e tuuina mai ia te au taleni e lima;", "thou deliveredst unto me five talents:"], ["faauta,", "behold,"], ["ua ou maua ai isi taleni e lima.", "I have gained beside them five talents more."]]},
  {num:21,words:[["Ona fai atu ai lea o lona alii ia te ia,", "His lord said unto him,"], ["Ua lelei ia,", "Well done,"], ["le auauna lelei e, ma le faamaoni,", "thou good and faithful servant:"], ["ua e faamaoni i nai mea itiiti,", "thou hast been faithful over a few things,"], ["ou te tofia oe e pule i mea e tele;", "I will make thee ruler over many things:"], ["ina ulufale mai ia i le fiafia o lou alii.", "enter thou into the joy of thy lord."]]},
  {num:22,words:[["Ua sau foi le ua i ai taleni e lua,", "He also that had received two talents came and said,"], ["ua faapea mai,", "Lord,"], ["Le Alii e, na e tuuina mai ia te au taleni e lua;", "thou deliveredst unto me two talents:"], ["faauta,", "behold,"], ["ua ou maua ai isi taleni e lua.", "I have gained two other talents beside them."]]},
  {num:23,words:[["Ona fai atu ai lea o lona alii ia te ia,", "His lord said unto him,"], ["Ua lelei ia,", "Well done,"], ["le auauna lelei e, ma le faamaoni,", "good and faithful servant;"], ["ua e faamaoni i nai mea itiiti,", "thou hast been faithful over a few things,"], ["ou te tofia oe e pule i mea e tele;", "I will make thee ruler over many things:"], ["ina ulufale mai ia i le fiafia o lou alii.", "enter thou into the joy of thy lord."]]},
  {num:24,words:[["Ua sau foi le ua i ai le taleni e tasi,", "Then he which had received the one talent came and said,"], ["ua faapea mai,", "Lord,"], ["Le alii e, na ou iloa o oe o le tagata faigata,", "I knew thee that thou art an hard man,"], ["ua e selesele i le mea e te lei luluina ai saito,", "reaping where thou hast not sown,"], ["ua e faapotopoto foi i le mea e te lei faataapeapeina ai mea;", "and gathering where thou hast not strawed:"]]},
  {num:25,words:[["ona ou fefe ai lea,", "And I was afraid,"], ["ua ou alu ma ou nā lau taleni i le eleele;", "and went and hid thy talent in the earth:"], ["faauta,", "lo,"], ["o lau mea lea.", "there thou hast that is thine."]]},
  {num:26,words:[["Ona tali atu ai lea o lona alii, ua faapea atu ia te ia,", "His lord answered and said unto him,"], ["Le auauna leaga e,", "Thou wicked and slothful servant,"], ["ma le paie,", "thou knewest that I reap where I sowed not,"], ["ua e iloa ou te selesele i le mea na ou le luluina ai saito, ou te faapotopoto foi i le mea na ou le faataapeapeina ai mea;", "and gather where I have not strawed:"]]},
  {num:27,words:[["o lea, e tatau ai pe ana e tuuina atu la'u ario i e faatau tupe,", "Thou oughtest therefore to have put my money to the exchangers,"], ["po ua ou sau, ona ou maua ai lea o la'u mea ma lona taui.", "and then at my coming I should have received mine own with usury."]]},
  {num:28,words:[["O lenei, ia outou fao le taleni nai ia te ia,", "Take therefore the talent from him,"], ["ma avatu i le ua i ai taleni e sefulu.", "and give it unto him which hath ten talents."]]},
  {num:29,words:[["Auā o se ua i ai ni mea,", "For unto every one that hath shall be given,"], ["e foaiina atu ia te ia e atili tele ai ana mea; a o le ua le i ai ni mea,", "and he shall have abundance:"], ["e faoa le mea ua i ai.", "but from him that hath not shall be taken away even that which he hath."]]},
  {num:30,words:[["Ia outou tulia foi le auauna le aoga i le pouliuli i fafo,", "And cast ye the unprofitable servant into outer darkness:"], ["e i ai le taufaitagiaue ma le lilivau o nifo.", "there shall be weeping and gnashing of teeth."]]},
  {num:31,words:[["Pe a sau le Atalii o le tagata i lona mamalu,", "When the Son of man shall come in his glory,"], ["ma le au agelu paia uma faatasi ma ia,", "and all the holy angels with him,"], ["ona tietie ai lea o ia i lona nofoālii mamalu;", "then shall he sit upon the throne of his glory:"]]},
  {num:32,words:[["e faapotopotoina foi i ona luma o nuu uma lava;", "And before him shall be gathered all nations:"], ["ona tuueseeseina lea o i latou e ia,", "and he shall separate them one from another,"], ["e pei o le leoleo mamoe ona tuueseeseina o mamoe ma 'oti;", "as a shepherd divideth his sheep from the goats:"]]},
  {num:33,words:[["ona tuu ai lea e ia o mamoe i lona itu taumatau,", "And he shall set the sheep on his right hand,"], ["a o 'oti i lona itu tauagavale.", "but the goats on the left."]]},
  {num:34,words:[["Ona fai atu ai lea o le Tupu i e o i lona itu taumatau,", "Then shall the King say unto them on his right hand,"], ["O mai ia,", "Come,"], ["o outou ua faamanuiaina e lo'u Tamā,", "ye blessed of my Father,"], ["ia fai mo outou tofi le malo ua saunia mo outou a o lei faavaeina le lalolagi;", "inherit the kingdom prepared for you from the foundation of the world:"]]},
  {num:35,words:[["auā na ou fia 'ai,", "For I was an hungred,"], ["ona outou avane ai lea ni mea ou te 'ai ai;", "and ye gave me meat:"], ["na ou fia inu,", "I was thirsty,"], ["ona outou avane ai lea ni vai ou te inu ai;", "and ye gave me drink:"], ["sa fai a'u ma tagata ese,", "I was a stranger,"], ["ona outou talia lea o a'u;", "and ye took me in:"]]},
  {num:36,words:[["na ou le lavalavā,", "Naked,"], ["ona outou faaofuina lea o a'u;", "and ye clothed me:"], ["na ou ma'i,", "I was sick,"], ["ona outou asiasia mai lea o a'u;", "and ye visited me:"], ["na ou i le fale puipui,", "I was in prison,"], ["ona outou o ane ai lea ia te au.", "and ye came unto me."]]},
  {num:37,words:[["Ona tali mai ai lea ia te ia o e amiotonu,", "Then shall the righteous answer him,"], ["e faapea mai,", "saying,"], ["Le Alii e,", "Lord,"], ["o anafea na matou iloa ai oe ua fia 'ai,", "when saw we thee an hungred,"], ["ma matou fagaina oe? po o fia inu,", "and fed thee? or thirsty,"], ["ma matou avane e te inu ai?", "and gave thee drink?"]]},
  {num:38,words:[["O anafea foi na matou iloa ai oe o le tagata ese,", "When saw we thee a stranger,"], ["ma matou talia oe? po o le le lavalavā,", "and took thee in? or naked,"], ["ma matou faaofuina oe?", "and clothed thee?"]]},
  {num:39,words:[["O anafea foi na matou iloa ai oe ua ma'i,", "Or when saw we thee sick,"], ["po o i le fale puipui,", "or in prison,"], ["ma matou o atu ai ia te oe?", "and came unto thee?"]]},
  {num:40,words:[["Ona tali atu ai lea o le Tupu, e faapea atu ia te i latou,", "And the King shall answer and say unto them,"], ["E moni,", "Verily I say unto you,"], ["ou te fai atu ia te outou,", "Inasmuch as ye have done it unto one of the least of these my brethren,"], ["auā na faia e outou i le tasi o e aupito itiiti o o'u uso nei, o a'u lea na outou faia i ai.", "ye have done it unto me."]]},
  {num:41,words:[["Ona fai atu foi lea o ia i e o i lona itu tauagavale,", "Then shall he say also unto them on the left hand,"], ["O outou ua faafanoina,", "Depart from me,"], ["o ese atu ia ia te au i le afi e faavavau,", "ye cursed, into everlasting fire,"], ["ua saunia mo le tiapolo ma ana agelu.", "prepared for the devil and his angels:"]]},
  {num:42,words:[["Auā na ou fia 'ai,", "For I was an hungred,"], ["a e tou te lei avane ni mea ou te 'ai ai;", "and ye gave me no meat:"], ["na ou fia inu,", "I was thirsty,"], ["a e tou te lei avane ni vai ou te inu ai;", "and ye gave me no drink:"]]},
  {num:43,words:[["sa fai a'u ma tagata ese,", "I was a stranger,"], ["a e lei talia a'u e outou;", "and ye took me not in:"], ["na ou le lavalavā,", "naked,"], ["a e tou te lei faaofuina a'u;", "and ye clothed me not:"], ["na ou ma'i,", "sick,"], ["na a'u i le fale puipui foi,", "and in prison,"], ["a e tou te lei asiasia a'u.", "and ye visited me not."]]},
  {num:44,words:[["Ona tali mai ai lea o i latou foi ia te ia,", "Then shall they also answer him,"], ["e faapea mai,", "saying,"], ["Le Alii e,", "Lord,"], ["o anafea na matou iloa ai oe ua fia 'ai,", "when saw we thee an hungred,"], ["pe fia inu,", "or athirst,"], ["po o se tagata ese,", "or a stranger,"], ["pe le lavalavā,", "or naked,"], ["po o ma'i,", "or sick,"], ["po o i le fale puipui,", "or in prison,"], ["ma matou lei auauna atu ia te oe?", "and did not minister unto thee?"]]},
  {num:45,words:[["Ona tali atu ai lea o ia ia te i latou,", "Then shall he answer them,"], ["e faapea atu,", "saying,"], ["E moni, ou te fai atu ia te outou,", "Verily I say unto you,"], ["auā na outou le faia i le tasi o e aupito itiiti o i latou nei,", "Inasmuch as ye did it not to one of the least of these,"], ["o a'u lea ua outou le faia i ai.", "ye did it not to me."]]},
  {num:46,words:[["Ona o atu ai lea o i latou nā i le sala e faavavau;", "And these shall go away into everlasting punishment:"], ["a o e amiotonu e o atu i le ola e faavavau.", "but the righteous into life eternal."]]},
];
renderVerseSet(mat_ch_25_Verses, 'mat-ch25-verses');

var mat_ch_26_Verses = [
  {num:1,words:[["Ua faaiu e Iesu o ia upu uma,", "And it came to pass, when Jesus had finished all these sayings,"], ["ona fetalai atu ai lea o ia i ona soo,", "he said unto his disciples,"]]},
  {num:2,words:[["Ua outou iloa a mavae aso e lua ona fai ai lea o le paseka,", "Ye know that after two days is the feast of the passover,"], ["e tuuina atu ai le Atalii o le tagata ina ia faasatauroina.", "and the Son of man is betrayed to be crucified."]]},
  {num:3,words:[["O ona po ia ua faapotopoto ai le au faitaulaga sili,", "Then assembled together the chief priests,"], ["ma le au tusiupu,", "and the scribes,"], ["ma toeaina o le nuu i le maota o le faitaulaga sili,", "and the elders of the people, unto the palace of the high priest,"], ["e igoa ia Kaiafa;", "who was called Caiaphas,"]]},
  {num:4,words:[["ua latou taupulepule i se mailei e mafai ai ona pue,", "And consulted that they might take Jesus by subtilty,"], ["ma fasioti ia Iesu.", "and kill him."]]},
  {num:5,words:[["A ua latou faapea ane,", "But they said,"], ["Aua le faia i le tausamiga,", "Not on the feast day,"], ["ina ne'i faanunununu ai le nuu.", "lest there be an uproar among the people."]]},
  {num:6,words:[["Sa i Petania Iesu i le fale o Simona le lepela,", "Now when Jesus was in Bethany, in the house of Simon the leper,"]]},
  {num:7,words:[["ona sau ai lea ia te ia o le fafine ma le fagu alapasa ua i ai le suāuu manogi tau tele,", "There came unto him a woman having an alabaster box of very precious ointment, and poured it on his head,"], ["ona liligi ai lea e ia i lona ao a o taoto ia e taumafa.", "as he sat at meat."]]},
  {num:8,words:[["Ua iloa e ona soo,", "But when his disciples saw it,"], ["ona tiga ai lea o latou loto,", "they had indignation,"], ["ua latou faapea ane,", "saying,"], ["Se a le mea ua faamāumau ai lena mea?", "To what purpose is this waste?"]]},
  {num:9,words:[["auā ana faatauina lena suāuu manogi po ua tele sona tau,", "For this ointment might have been sold for much,"], ["e foaiina atu ai i e matitiva.", "and given to the poor."]]},
  {num:10,words:[["A ua silafia e Iesu,", "When Jesus understood it,"], ["ona faapea atu ai lea o ia ia te i latou,", "he said unto them,"], ["Se a le mea ua outou faalavelave ai i le fafine? auā o le mea lelei ua na faia ia te au nei.", "Why trouble ye the woman? for she hath wrought a good work upon me."]]},
  {num:11,words:[["Auā tou te nonofo pea ma e matitiva; a o a'u nei,", "For ye have the poor always with you;"], ["tatou te le nonofo pea ma a'u.", "but me ye have not always."]]},
  {num:12,words:[["Auā ua liligi e ia lenei suāuu manogi i lo'u tino e fai ma faataimuaga o lo'u tanuga.", "For in that she hath poured this ointment on my body, she did it for my burial."]]},
  {num:13,words:[["E moni,", "Verily I say unto you,"], ["ou te fai atu ia te outou,", "Wheresoever this gospel shall be preached in the whole world,"], ["o nuu uma i le lalolagi e tala'iina atu i ai lenei tala lelei,", "there shall also this,"], ["e ta'ua ai le mea ua faia e lenei fafine,", "that this woman hath done,"], ["e faamanatu a'i ia te ia.", "be told for a memorial of her."]]},
  {num:14,words:[["Ona alu ai lea o le tasi o le toasefulu ma le toalua,", "Then one of the twelve,"], ["e igoa ia Iuta le Sekara,", "called Judas Iscariot,"], ["i le au faitaulaga sili,", "went unto the chief priests,"]]},
  {num:15,words:[["ua faapea atu,", "And said unto them,"], ["Se a le mea tou te au mai ma'u,", "What will ye give me,"], ["ou te faalataina ai o ia ia te outou? Ona latou avane ai lea ia te ia o tupe e tolugafulu.", "and I will deliver him unto you? And they covenanted with him for thirty pieces of silver."]]},
  {num:16,words:[["Talu ai lea aso ua lamalama e ia se itu aso e faigofie ai ona faalataina o ia.", "And from that time he sought opportunity to betray him."]]},
  {num:17,words:[["O le muai aso o areto e le faafefeteina ua o mai ai le au soo ia Iesu,", "Now the first day of the feast of unleavened bread the disciples came to Jesus,"], ["ua faapea mai ia te ia,", "saying unto him,"], ["Po o fea le mea e te finagalo i ai matou te saunia e te taumafa ai le paseka?", "Where wilt thou that we prepare for thee to eat the passover?"]]},
  {num:18,words:[["Ona faapea atu ai lea o ia,", "And he said,"], ["Ina o atu ia i le aai i le tasi tagata,", "Go into the city to such a man,"], ["ma fai atu ia te ia,", "and say unto him,"], ["Ua fai mai le a'oa'o,", "The Master saith,"], ["ua latalata o'u aso;", "My time is at hand;"], ["matou te fai ai le paseka ma o'u soo i lou fale.", "I will keep the passover at thy house with my disciples."]]},
  {num:19,words:[["Ona faia lea e ona soo e pei ona fetalai atu ai Iesu,", "And the disciples did as Jesus had appointed them;"], ["ua saunia foi le paseka.", "and they made ready the passover."]]},
  {num:20,words:[["Ua oo i le afiafi,", "Now when the even was come,"], ["ona taoto ai lea o ia e taumafa faatasi ma le toasefulu ma le toalua.", "he sat down with the twelve."]]},
  {num:21,words:[["O loo latou aai,", "And as they did eat,"], ["ona fetalai atu ai lea o ia,", "he said,"], ["E moni ou te fai atu ia te outou,", "Verily I say unto you,"], ["e faalataina a'u e so outou.", "that one of you shall betray me."]]},
  {num:22,words:[["Ona latou matuā tiga ai lea,", "And they were exceeding sorrowful,"], ["ua latou taitasi ma fai mai ia te ia,", "and began every one of them to say unto him,"], ["Le Alii e,", "Lord,"], ["o a'u ea?", "is it I?"]]},
  {num:23,words:[["Ona tali atu ai lea o ia,", "And he answered and said,"], ["ua faapea atu, O lē fufui faatasi lona lima ma lo'u i le tanoa,", "He that dippeth his hand with me in the dish,"], ["o ia lea na te faalataina a'u.", "the same shall betray me."]]},
  {num:24,words:[["E alu lava le Atalii o le tagata e pei ona tusia ia te ia;", "The Son of man goeth as it is written of him:"], ["a o le tagata na te faalataina le Atalii o le tagata oi talofa ia te ia! e lelei i lea tagata pe ana le fanau mai o ia.", "but woe unto that man by whom the Son of man is betrayed! it had been good for that man if he had not been born."]]},
  {num:25,words:[["Ona tali mai ai lea o Iuta le na faalataina ia,", "Then Judas,"], ["ua faapea mai,", "which betrayed him,"], ["Rapi e,", "answered and said, Master,"], ["o a'u ea? Ua fetalai atu o ia ia te ia,", "is it I? He said unto him,"], ["O lena lava.", "Thou hast said."]]},
  {num:26,words:[["O loo latou aai,", "And as they were eating,"], ["a e tago Iesu i le areto,", "Jesus took bread,"], ["ua faafetai,", "and blessed it,"], ["ona tofitofi ai lea,", "and brake it,"], ["ma avatu i le au soo,", "and gave it to the disciples,"], ["ua faapea atu,", "and said,"], ["Ina tago ia,", "Take,"], ["ina aai;", "eat;"], ["o lo'u tino lenei.", "this is my body."]]},
  {num:27,words:[["Ua tago foi o ia i le ipu,", "And he took the cup,"], ["ua faafetai,", "and gave thanks,"], ["ona avatu ai lea e ia ia te i latou,", "and gave it to them,"], ["ua faapea atu,", "saying,"], ["Ina inu ia outou uma i ai;", "Drink ye all of it;"]]},
  {num:28,words:[["auā o lo'u toto lenei, o le toto o le feagaiga fou,", "For this is my blood of the new testament,"], ["ua faamaligiina mo tagata e toatele e faamagalo a'i agasala.", "which is shed for many for the remission of sins."]]},
  {num:29,words:[["Ou te fai atu foi ia te outou,", "But I say unto you,"], ["ou te le toe inu lava i lenei fua o le vine,", "I will not drink henceforth of this fruit of the vine,"], ["seia oo i lea aso ou te inu ai le uaina fou faatasi ma outou i le malo o lo'u Tamā.", "until that day when I drink it new with you in my Father's kingdom."]]},
  {num:30,words:[["Ua uma ona fai o a latou pese,", "And when they had sung an hymn,"], ["ona latou o atu ai lea i le mauga o Olive.", "they went out into the mount of Olives."]]},
  {num:31,words:[["Ona fetalai atu ai lea o Iesu ia te i latou,", "Then saith Jesus unto them,"], ["E tausuai outou uma ona o a'u i lenei lava po;", "All ye shall be offended because of me this night:"], ["auā ua tusia,", "for it is written,"], ["Ou te taia le leoleo mamoe,", "I will smite the shepherd,"], ["ona taapeape ai lea o le lafu mamoe.", "and the sheep of the flock shall be scattered abroad."]]},
  {num:32,words:[["A e a mavae lo'u toe tu,", "But after I am risen again,"], ["ona ou muamua atu ai lea ia te outou i Kalilaia.", "I will go before you into Galilee."]]},
  {num:33,words:[["Ona tali mai ai lea o Peteru,", "Peter answered and said unto him,"], ["ua faapea mai ia te ia, E ui lava ina tausuai o tagata uma ona o oe,", "Though all men shall be offended because of thee,"], ["ou te le tausuai lava a'u.", "yet will I never be offended."]]},
  {num:34,words:[["Ona fetalai atu ai lea o Iesu ia te ia,", "Jesus said unto him,"], ["E moni,", "Verily I say unto thee,"], ["ou te fai atu ia te oe, o lenei lava po,", "That this night,"], ["a o lei vivini moa,", "before the cock crow,"], ["e te faafiti faatolu mai ai ia te au.", "thou shalt deny me thrice."]]},
  {num:35,words:[["Ona fai mai ai lea o Peteru ia te ia,", "Peter said unto him,"], ["E ui ina tā oti lava faatasi ma oe,", "Though I should die with thee,"], ["ou te le faafiti lava ia te oe. Ua faapea foi ona fai mai o le au soo uma lava.", "yet will I not deny thee. Likewise also said all the disciples."]]},
  {num:36,words:[["Ona oo ai lea o Iesu faatasi ma i latou i le fanua ua igoa ia Ketesemane;", "Then cometh Jesus with them unto a place called Gethsemane,"], ["ua faapea atu foi o ia i le au soo,", "and saith unto the disciples,"], ["Ia outou nonofo iinei,", "Sit ye here,"], ["seia ou alu atu iilā ou te tatalo.", "while I go and pray yonder."]]},
  {num:37,words:[["Ua o ane o ia ma Peteru ma atalii o Sepetaio e toalua,", "And he took with him Peter and the two sons of Zebedee,"], ["ona tiga lea o ia ma atuatuvale.", "and began to be sorrowful and very heavy."]]},
  {num:38,words:[["Ona fetalai atu ai lea o ia ia te i latou,", "Then saith he unto them,"], ["Ua matuā tiga lo'u loto e oo i le oti;", "My soul is exceeding sorrowful,"], ["ia outou nonofo pea iinei,", "even unto death: tarry ye here,"], ["ma ia tatou mataala faatasi ma a'u.", "and watch with me."]]},
  {num:39,words:[["Ua maliu faaitiiti atu i luma,", "And he went a little further,"], ["ona faapaū fao ai lea o ia ma tatalo,", "and fell on his face,"], ["ua faapea atu,", "and prayed,"], ["Lo'u Tamā e,", "saying,"], ["afai e mafai,", "O my Father, if it be possible,"], ["ia ave ese lenei ipu ia te au;", "let this cup pass from me:"], ["a e aua le faia lo'u loto,", "nevertheless not as I will,"], ["a o lou finagalo .", "but as thou wilt."]]},
  {num:40,words:[["Ona maliu ane lea o ia i ona soo,", "And he cometh unto the disciples,"], ["ua maua i latou o momoe,", "and findeth them asleep,"], ["ona fetalai atu ai lea o ia ia Peteru,", "and saith unto Peter, What,"], ["Pe faapena ea ona outou le lavā ona tatou mataala faatasi ma a'u i le itu po e tasi?", "could ye not watch with me one hour?"]]},
  {num:41,words:[["Ia outou mataala ma tatalo,", "Watch and pray,"], ["ina ne'i oo mai le faaosoosoga ia te outou;", "that ye enter not into temptation:"], ["ua manao i ai le loto,", "the spirit indeed is willing,"], ["a o le tino ua vaivai.", "but the flesh is weak."]]},
  {num:42,words:[["Ua toe maliu ane ia o le atu lua lea,", "He went away again the second time,"], ["ua tatalo,", "and prayed,"], ["ua faapea atu,", "saying, O my Father,"], ["Lo'u Tamā e,", "if this cup may not pass away from me,"], ["a le mafai ona ave ese o lenei ipu ia te au seia ou inu ai,", "except I drink it,"], ["ia faia lou finagalo.", "thy will be done."]]},
  {num:43,words:[["Ona maliu ane ai lea o ia ua maua i latou ua toe momoe;", "And he came and found them asleep again:"], ["auā ua maaa o latou laumata.", "for their eyes were heavy."]]},
  {num:44,words:[["Ona tuua lea o i latou e ia,", "And he left them,"], ["ua toe maliu ane,", "and went away again,"], ["ua tatalo o le atu tolu lea,", "and prayed the third time,"], ["ua fetalai atu i le upu lava e tasi.", "saying the same words."]]},
  {num:45,words:[["Ona maliu ane ai lea o ia i ona soo,", "Then cometh he to his disciples,"], ["ua faapea atu ia te i latou,", "and saith unto them,"], ["Ina momoe pea ia,", "Sleep on now, and take your rest:"], ["ma malolo;", "behold,"], ["faauta,", "the hour is at hand,"], ["ua latalata le itu po e faalataina ai le Atalii o le tagata i lima o tagata agasala.", "and the Son of man is betrayed into the hands of sinners."]]},
  {num:46,words:[["Ina tutū ia,", "Rise,"], ["tatou o;", "let us be going:"], ["faauta,", "behold,"], ["ua latalata mai o ia na te faalataina a'u", "he is at hand that doth betray me."]]},
  {num:47,words:[["Faauta,", "And while he yet spake,"], ["o loo fetalai o ia,", "lo,"], ["a sau Iuta,", "Judas,"], ["o le tasi o le toasefulu ma le toalua,", "one of the twelve,"], ["ua faatasi mai foi ma ia le motu o tagata e toatele,", "came,"], ["mai le au faitaulaga sili ma toeaina o le nuu,", "and with him a great multitude with swords and staves,"], ["ua ia te i latou o pelu ma uatogi.", "from the chief priests and elders of the people."]]},
  {num:48,words:[["Na tuuina atu foi e le na faalataina o ia le faailoga ia te i latou,", "Now he that betrayed him gave them a sign,"], ["ua faapea atu,", "saying,"], ["O lē ou te sogi atu i ai,", "Whomsoever I shall kiss,"], ["o ia lea;", "that same is he:"], ["ia outou pue ia te ia.", "hold him fast."]]},
  {num:49,words:[["Ona sau loa lea o ia ia Iesu,", "And forthwith he came to Jesus,"], ["ua faapea mai,", "and said,"], ["Rapi e,", "Hail,"], ["si o'u alofa;", "master;"], ["ona sogi ai lea o ia ia te ia.", "and kissed him."]]},
  {num:50,words:[["Ona fetalai atu ai lea o Iesu ia te ia,", "And Jesus said unto him,"], ["Sole,", "Friend,"], ["se a le mea ua e sau ai? Ona latou o mai ai lea,", "wherefore art thou come? Then came they,"], ["ua tago atu o latou lima ia Iesu,", "and laid hands on Jesus,"], ["ua latou pue ia te ia.", "and took him."]]},
  {num:51,words:[["Faauta foi,", "And,"], ["o le tasi o e na ia Iesu,", "behold,"], ["ua tago ia i lana pelu,", "one of them which were with Jesus stretched out his hand,"], ["ua se'i,", "and drew his sword,"], ["ona ia taia lea o le auauna a le faitaulaga sili,", "and struck a servant of the high priest's,"], ["ua tipiesea lona taliga.", "and smote off his ear."]]},
  {num:52,words:[["Ona fetalai atu lea o Iesu ia te ia,", "Then said Jesus unto him,"], ["Ina toe sulu ia o lau pelu i lona faamoega; auā o i latou uma o e tago i le pelu,", "Put up again thy sword into his place:"], ["e oti i latou i le pelu.", "for all they that take the sword shall perish with the sword."]]},
  {num:53,words:[["Fa te oe ea ou te le mafaia ona aioi atu nei i lo'u Tamā,", "Thinkest thou that I cannot now pray to my Father,"], ["ona aauina mai ai lea e ia ia te au o agelu e sili ona toatele i lekeona e sefulu ma le lua?", "and he shall presently give me more than twelve legions of angels?"]]},
  {num:54,words:[["Ona faapefea lea ona taunuu o Tusi,", "But how then shall the scriptures be fulfilled,"], ["e tatau ona oo ia mea?", "that thus it must be?"]]},
  {num:55,words:[["O lea itu po ua fetalai atu ai Iesu i le motu o tagata, Ua outou o mai ea ma pelu ma uatogi e pue mai ai ia te au,", "In that same hour said Jesus to the multitudes,"], ["peiseai o se fao mea? sa tatou nonofo ma outou i le malumalu,", "Are ye come out as against a thief with swords and staves for to take me? I sat daily with you teaching in the temple,"], ["ma ou a'oa'o atu ai i aso fai soo, a e tou te lei pueina ai a'u.", "and ye laid no hold on me."]]},
  {num:56,words:[["A ua oo ia mea uma ina ia taunuu ai Tusi a le au perofeta.", "But all this was done, that the scriptures of the prophets might be fulfilled."], ["Ona tuua ai lea o ia e le au soo uma,", "Then all the disciples forsook him,"], ["a e sosola i latou.", "and fled."]]},
  {num:57,words:[["O e na pue ia Iesu ua latou ta'ita'i ia te ia ia Kaiafa le faitaulaga sili,", "And they that had laid hold on Jesus led him away to Caiaphas the high priest,"], ["na faapotopoto ai le au tusiupu ma toeaina.", "where the scribes and the elders were assembled."]]},
  {num:58,words:[["A ua mulimuli mamao mai Peteru ia te ia,", "But Peter followed him afar off unto the high priest's palace,"], ["ua oo i le maota o le faitaulaga sili,", "and went in,"], ["ua ulufale atu i ai, ua nofo foi o ia faatasi ma auauna,", "and sat with the servants,"], ["ia iloa ona iu.", "to see the end."]]},
  {num:59,words:[["A o le au faitaulaga sili,", "Now the chief priests,"], ["ma toeaina,", "and elders,"], ["ma le taupulega uma,", "and all the council,"], ["ua latou saili ni e molimau pepelo ia Iesu,", "sought false witness against Jesus,"], ["ina ia latou fasioti ia te ia;", "to put him to death;"]]},
  {num:60,words:[["a e lei maua;", "But found none:"], ["e ui lava ina o mai molimau pepelo e toatele,", "yea,"], ["a e lei maua lava. E mulimuli ane ua o mai molimau pepelo e toalua,", "though many false witnesses came,"], ["ua faapea mai,", "yet found they none. At the last came two false witnesses,"]]},
  {num:61,words:[["Na fai mai lenei tagata ,", "And said,"], ["Ou te mafaia ona lepeti o le malumalu o le Atua,", "This fellow said, I am able to destroy the temple of God,"], ["ma ou toe faia i aso e tolu.", "and to build it in three days."]]},
  {num:62,words:[["Ona tu ai lea i luga o le faitaulaga sili,", "And the high priest arose,"], ["ua faapea mai ia te ia,", "and said unto him,"], ["E leai ea sau tali? Pe se a le mau a nei tagata ia te oe?", "Answerest thou nothing? what is it which these witness against thee?"]]},
  {num:63,words:[["A ua le fetalai Iesu.", "But Jesus held his peace."], ["Ona fai mai ai lea o le faitaulaga sili,", "And the high priest answered and said unto him,"], ["ua faapea mai ia te ia,", "I adjure thee by the living God,"], ["Ou te fai atu ia te oe ia te tauto mai ia te i matou i le suafa o le Atua soifua, po o oe le Keriso,", "that thou tell us whether thou be the Christ,"], ["o le Alo o le Atua.", "the Son of God."]]},
  {num:64,words:[["Ona fetalai atu ai lea o Iesu ia te ia,", "Jesus saith unto him,"], ["O lea lava;", "Thou hast said:"], ["ou te fai atu foi ia te outou,", "nevertheless I say unto you,"], ["E mulimuli ane tou te iloa ai le Atalii o le tagata e nofo i le itu taumatau o le e ona le mana,", "Hereafter shall ye see the Son of man sitting on the right hand of power,"], ["e sau foi o ia i ao o le lagi.", "and coming in the clouds of heaven."]]},
  {num:65,words:[["Ona saeia ai lea e le faitaulaga sili ona lava ofu,", "Then the high priest rent his clothes,"], ["ua faapea ane,", "saying,"], ["Ua upu leaga o ia i le Atua se a se toe aoga o molimau ia te i tatou? faauta,", "He hath spoken blasphemy; what further need have we of witnesses? behold,"], ["ua outou faalogo nei i ana upu leaga i le Atua .", "now ye have heard his blasphemy."]]},
  {num:66,words:[["Pe ni a fa outou? Ona latou tali mai ai lea,", "What think ye? They answered and said,"], ["ua faapea mai. E tatau ona oti o ia.", "He is guilty of death."]]},
  {num:67,words:[["Ona latou taufaifeanu ai lea i ona fofoga,", "Then did they spit in his face,"], ["ua taufaitu'i foi ia te ia;", "and buffeted him;"], ["ua taufaipo atu foi isi,", "and others smote him with the palms of their hands,"]]},
  {num:68,words:[["ua faapea mai,", "Saying,"], ["Keriso e,", "Prophesy unto us,"], ["ina iite mai ia te i matou,", "thou Christ,"], ["po o ai na na fasia oe?", "Who is he that smote thee?"]]},
  {num:69,words:[["A o Peteru sa nofo o ia i fafo i le maota;", "Now Peter sat without in the palace:"], ["ona alu atu ai lea o le tasi auauna teine ia te ia,", "and a damsel came unto him,"], ["ua faapea atu, O oe foi,", "saying,"], ["sa oulua faatasi ma Iesu le Kalilaia.", "Thou also wast with Jesus of Galilee."]]},
  {num:70,words:[["Ona faafiti lea o ia i o latou luma atoa,", "But he denied before them all,"], ["ua faapea ane,", "saying,"], ["Ou te le iloa le mea e te fai mai ai na.", "I know not what thou sayest."]]},
  {num:71,words:[["Ua ulufafo ia i le faapaologa,", "And when he was gone out into the porch,"], ["ona iloa mai ai lea o ia e le tasi auauna teine ,", "another maid saw him,"], ["ua na fai atu i e ua i ai,", "and said unto them that were there,"], ["O lenei tagata foi sa la faatasi ma Iesu le Nasareta.", "This fellow was also with Jesus of Nazareth."]]},
  {num:72,words:[["Ona toe faafiti ai lea o ia ma le augani,", "And again he denied with an oath,"], ["Ou te lei iloa lea tagata.", "I do not know the man."]]},
  {num:73,words:[["Ua toe itiiti, ona o ane ai lea o e na tutū mai,", "And after a while came unto him they that stood by,"], ["ua faapea mai ia Peteru,", "and said to Peter,"], ["E moni,", "Surely thou also art one of them;"], ["o oe lava lo latou; auā ua iloa oe i lau gagana.", "for thy speech bewrayeth thee."]]},
  {num:74,words:[["Ona augani ai lea o ia ma tauto,", "Then began he to curse and to swear,"], ["ua faapea atu ,", "saying,"], ["Ou te le iloa lava lea tagata. Ona vivini loa lea o moa.", "I know not the man. And immediately the cock crew."]]},
  {num:75,words:[["Ona manatua lea e Peteru o le upu na fetalai atu ai Iesu ia te ia,", "And Peter remembered the word of Jesus, which said unto him,"], ["E le vivini moa seia e faafiti faatolu mai ia te au.", "Before the cock crow, thou shalt deny me thrice."], ["Ona ulufafo ai lea o ia,", "And he went out,"], ["ua tagi lotulotu.", "and wept bitterly."]]},
];
renderVerseSet(mat_ch_26_Verses, 'mat-ch26-verses');

var mat_ch_27_Verses = [
  {num:1,words:[["Ua ao,", "When the morning was come,"], ["ona taupulepule ai lea o le au faitaulaga sili uma ma toeaina o le nuu ia Iesu ina ia fasioti ia te ia;", "all the chief priests and elders of the people took counsel against Jesus to put him to death:"]]},
  {num:2,words:[["ua latou noanoa ia te ia,", "And when they had bound him,"], ["ona latou ta'ita'i ai lea ia te ia,", "they led him away,"], ["ma tuu atu ai ia Ponotio Pilato le alii.", "and delivered him to Pontius Pilate the governor."]]},
  {num:3,words:[["Ua iloa e Iuta,", "Then Judas,"], ["o le na faalataina o ia,", "which had betrayed him,"], ["ua faasalaina o ia, ona salamo ai lea o ia,", "when he saw that he was condemned,"], ["ua toe ave tupe e tolugafulu i le au faitaulaga sili ma toeaina,", "repented himself,"], ["ua faapea atu,", "and brought again the thirty pieces of silver to the chief priests and elders,"]]},
  {num:4,words:[["Ua ou agasala,", "Saying,"], ["ina ua ou faalata le ua le sala. A ua latou faapea mai,", "I have sinned in that I have betrayed the innocent blood. And they said,"], ["Sa matou mea ea lena? faitalia lava oe.", "What is that to us? see thou to that."]]},
  {num:5,words:[["Ona lafo ai lea e ia o tupe i le malumalu,", "And he cast down the pieces of silver in the temple,"], ["ua alu ese;", "and departed,"], ["ona alu ai lea o ia ua noa o ia e ia.", "and went and hanged himself."]]},
  {num:6,words:[["Ona tago ai lea o le au faitaulaga sili i tupe,", "And the chief priests took the silver pieces,"], ["ua faapea ane,", "and said,"], ["E sa ona tuu ia mea i le mea e teu ai oloa,", "It is not lawful for to put them into the treasury,"], ["auā o le tau o le toto.", "because it is the price of blood."]]},
  {num:7,words:[["Ua latou filifili,", "And they took counsel,"], ["ona faatau a'i lea o le fanua o le fai ipu omea,", "and bought with them the potter's field,"], ["e tatanu ai tagata ese.", "to bury strangers in."]]},
  {num:8,words:[["O le mea lea ua igoa ai lea fanua,", "Wherefore that field was called,"], ["O le fanua o le toto,", "The field of blood,"], ["ua oo lava i nei ona po.", "unto this day."]]},
  {num:9,words:[["Ona taunuu ai lea o le upu a le perofeta o Ieremia,", "Then was fulfilled that which was spoken by Jeremy the prophet,"], ["ua faapea mai,", "saying,"], ["Ua latou tago i tupe e tolugafulu,", "And they took the thirty pieces of silver,"], ["o le tau lea o le na faatatauina,", "the price of him that was valued,"], ["na faatatauina e nisi o le fanauga a Isaraelu;", "whom they of the children of Israel did value;"]]},
  {num:10,words:[["ona latou faatau a'i lea o le fanua o le fai ipu omea,", "And gave them for the potter's field,"], ["e pei ona fetalai mai ai ia te au o le Alii.", "as the Lord appointed me."]]},
  {num:11,words:[["Ua tu Iesu i luma o le alii;", "And Jesus stood before the governor:"], ["ona fesili mai ai lea o le alii ia te ia,", "and the governor asked him,"], ["ua faapea mai,", "saying,"], ["O oe ea o le tupu o tagata Iutaia? Ona fetalai atu ai lea o Iesu ia te ia,", "Art thou the King of the Jews? And Jesus said unto him,"], ["O lea lava.", "Thou sayest."]]},
  {num:12,words:[["Ua momoli ia te ia e le au faitaulaga sili ma toeaina,", "And when he was accused of the chief priests and elders,"], ["a ua leai sana tali.", "he answered nothing."]]},
  {num:13,words:[["Ona fai mai ai lea o Pilato ia te ia,", "Then said Pilate unto him,"], ["Ua e le faalogo ea i le tele o mea ua latou molimau mai ai ia te oe?", "Hearest thou not how many things they witness against thee?"]]},
  {num:14,words:[["A ua le tali atu ia ia te ia i se upu e tasi;", "And he answered him to never a word;"], ["ona matuā ofo ai lea o le alii.", "insomuch that the governor marvelled greatly."]]},
  {num:15,words:[["Ua masani le alii e tatala atu i lea tausamiga ma lea tausamiga i le motu o tagata se tasi tagata ua noanoatia,", "Now at that feast the governor was wont to release unto the people a prisoner,"], ["o le ua latou loto i ai.", "whom they would."]]},
  {num:16,words:[["O ona po ia sa i ai ia te i latou le tagata ua noanoatia ua logologoa,", "And they had then a notable prisoner,"], ["e igoa ia Parapa.", "called Barabbas."]]},
  {num:17,words:[["O lea na fai atu ai Pilato ia te i latou,", "Therefore when they were gathered together,"], ["ina ua potopoto i latou,", "Pilate said unto them, Whom will ye that I release unto you? Barabbas,"], ["Po o ai tou te loto i ai ou te tatalaina atu ia te outou? o Parapa ea? po o Iesu le ua igoa ia Keriso?", "or Jesus which is called Christ?"]]},
  {num:18,words:[["Auā ua na iloa o le mataua na latou tuuina atu ai o ia.", "For he knew that for envy they had delivered him."]]},
  {num:19,words:[["Ua tietie o ia i le nofoa faamasino,", "When he was set down on the judgment seat,"], ["ona sau ai lea o le feau mai lana avā,", "his wife sent unto him,"], ["ua faapea mai,", "saying,"], ["Ne'i e mao i lea tagata amiotonu;", "Have thou nothing to do with that just man:"], ["auā na ou matuā tigaina analeila i le miti ia te ia.", "for I have suffered many things this day in a dream because of him."]]},
  {num:20,words:[["A ua faaoso e le au faitaulaga sili ma toeaina i le motu o tagata ia latou fai atu, o Parapa,", "But the chief priests and elders persuaded the multitude that they should ask Barabbas,"], ["a ia fasiotia Iesu.", "and destroy Jesus."]]},
  {num:21,words:[["Ona fai atu ai lea o le alii,", "The governor answered and said unto them,"], ["ua faapea atu ia te i latou, O ai so laua tou te loto i ai ou te tatalaina atu ia te outou? Ona latou fai mai ai lea,", "Whether of the twain will ye that I release unto you? They said,"], ["O Parapa.", "Barabbas."]]},
  {num:22,words:[["Ona fai atu ai lea o Pilato ia te i latou,", "Pilate saith unto them,"], ["Se a foi le mea ou te faia ia Iesu o le ua igoa ia Keriso? Ona fai mai ai lea o i latou uma ia te ia,", "What shall I do then with Jesus which is called Christ? They all say unto him,"], ["Ia faasatauroina ia.", "Let him be crucified."]]},
  {num:23,words:[["A ua fai atu le alii,", "And the governor said,"], ["Pe se a foi se leaga ua ia faia? A ua atili ai ona alalaga i latou,", "Why,"], ["ua faapea mai,", "what evil hath he done? But they cried out the more, saying,"], ["Ia faasatauroina ia.", "Let him be crucified."]]},
  {num:24,words:[["Ua iloa e Pilato,", "When Pilate saw that he could prevail nothing,"], ["ua le aoga lana upu ,", "but that rather a tumult was made,"], ["a e atili ai le vāvaō,", "he took water,"], ["ona tago ai lea o ia i le vai, ua fafano ai ona lima i luma o le motu o tagata,", "and washed his hands before the multitude,"], ["ua faapea atu,", "saying,"], ["Ou te mamā a'u i le toto o lenei tagata amiotonu;", "I am innocent of the blood of this just person:"], ["faitalia lava outou.", "see ye to it."]]},
  {num:25,words:[["Ona tali mai ai lea o le nuu uma,", "Then answered all the people,"], ["ua faapea mai,", "and said,"], ["Ia i luga ia i matou,", "His blood be on us,"], ["ma a matou fanau lona toto.", "and on our children."]]},
  {num:26,words:[["Ona tatalaina atu ai lea e ia o Parapa ia te i latou,", "Then released he Barabbas unto them:"], ["a ua sasaina e ia o Iesu,", "and when he had scourged Jesus,"], ["ma tuuina atu o ia ia faasatauroina.", "he delivered him to be crucified."]]},
  {num:27,words:[["Ua ta'ita'iina Iesu e le 'au a le alii i le maota o le alii,", "Then the soldiers of the governor took Jesus into the common hall,"], ["ona latou faapotopotoina ai lea ia te ia o le 'au uma.", "and gathered unto him the whole band of soldiers."]]},
  {num:28,words:[["Ua latou toeseina ona ofu,", "And they stripped him,"], ["ona latou faaofuina ai lea o ia i le ofu mūmū.", "and put on him a scarlet robe."]]},
  {num:29,words:[["Ua latou taataai foi laau tuitui ua fai a'i le pale,", "And when they had platted a crown of thorns,"], ["ona latou faaee ai lea i lona ao,", "they put it upon his head,"], ["ua tuu foi le u i lona aao taumatau;", "and a reed in his right hand:"], ["ona latou tootuli ai lea i ona luma,", "and they bowed the knee before him,"], ["ua faatauemu mai ia te ia,", "and mocked him,"], ["ua faapea mai,", "saying,"], ["Talofa,", "Hail,"], ["le tupu o tagata Iutaia!", "King of the Jews!"]]},
  {num:30,words:[["Ua feanu i latou ia te ia,", "And they spit upon him,"], ["ona latou tago ai lea i le u,", "and took the reed,"], ["ma ta i lona ao.", "and smote him on the head."]]},
  {num:31,words:[["Ua uma ona latou faatauemu mai ia te ia,", "And after that they had mocked him,"], ["ona latou tatala ese lea o le ofu,", "they took the robe off from him,"], ["ma faaofu ia te ia i ona lava ofu;", "and put his own raiment on him,"], ["ona latou ta'ita'i atu ai lea ia te ia ia faasatauroina.", "and led him away to crucify him."]]},
  {num:32,words:[["Ua latou o atu,", "And as they came out,"], ["ona iloa ai lea e i latou o le tagata Kurene,", "they found a man of Cyrene,"], ["e igoa ia Simona,", "Simon by name:"], ["ua latou faatauanau ia te ia ia ave lona satauro.", "him they compelled to bear his cross."]]},
  {num:33,words:[["Ua latou oo atu i le mea ua igoa ia Kolokota,", "And when they were come unto a place called Golgotha,"], ["o lona uiga,", "that is to say,"], ["O le mea o i ai le ulupoo;", "a place of a skull,"]]},
  {num:34,words:[["ona latou avatu lea ia te ia le vineta ua fefiloi ma le laau oona,", "They gave him vinegar to drink mingled with gall:"], ["ia inu ai; ua tofotofo e ia,", "and when he had tasted thereof,"], ["a ua le mafai ona inu ai.", "he would not drink."]]},
  {num:35,words:[["Ua latou faasatauro ia te ia,", "And they crucified him,"], ["ona tufatufa ai lea e i latou o ona ofu,", "and parted his garments,"], ["ua latou fai ai le vili;", "casting lots:"], ["ina ia taunuu ai le upu a le perofeta,", "that it might be fulfilled which was spoken by the prophet,"], ["Ua latou tufatufaina o'u ofu mo i latou,", "They parted my garments among them,"], ["ua latou faia foi le vili i lo'u ofu tino.", "and upon my vesture did they cast lots."]]},
  {num:36,words:[["Ua latou nonofo i lea mea ua leoleo ia te ia.", "And sitting down they watched him there;"]]},
  {num:37,words:[["Ua latou tuu foi i luga ae o lona ao le tusi i le mea na molia ai o ia, O IESU LENEI,", "And set up over his head his accusation written,"], ["O LE TUPU O TAGATA IUTAIA.", "THIS IS JESUS THE KING OF THE JEWS."]]},
  {num:38,words:[["Ona latou faasatauro lea faatasi ma ia tagata fao mea e toalua,", "Then were there two thieves crucified with him,"], ["o le tasi i le itu taumatau,", "one on the right hand,"], ["ma le tasi i le itu tauagavale.", "and another on the left."]]},
  {num:39,words:[["Ua upu leaga ia te ia o e na ui ane,", "And they that passed by reviled him,"], ["ma lialiai o latou ulu,", "wagging their heads,"]]},
  {num:40,words:[["ua faapea mai,", "And saying,"], ["O oe na,", "Thou that destroyest the temple,"], ["o lē lepeti i le malumalu, ma toe faia i aso e tolu,", "and buildest it in three days,"], ["ina faaola ia oe ia te oe.", "save thyself."], ["Afai o oe le Alo o le Atua,", "If thou be the Son of God,"], ["ina alu ifo ia i le satauro.", "come down from the cross."]]},
  {num:41,words:[["Ua faapea foi ona faatauemu o le au faitaulaga sili,", "Likewise also the chief priests mocking him,"], ["ma le au tusiupu, ma toeaina,", "with the scribes and elders,"], ["ua faapea ane,", "said,"]]},
  {num:42,words:[["Na ia faaolaina isi tagata,", "He saved others;"], ["e le mafaia e ia ona faaola ia te ia. Afai o le Tupu o Isaraelu o ia,", "himself he cannot save. If he be the King of Israel,"], ["ina alu ifo nei lava o ia i le satauro,", "let him now come down from the cross,"], ["ona tatou talitonu ai lea ia te ia.", "and we will believe him."]]},
  {num:43,words:[["Na faatuatua ia i le Atua,", "He trusted in God;"], ["ina laveai mai nei o ia ia te ia,", "let him deliver him now,"], ["afai e finagalo o ia ia te ia;", "if he will have him:"], ["auā na ia fai mai,", "for he said,"], ["O a'u o le Atalii o le Atua.", "I am the Son of God."]]},
  {num:44,words:[["Ua faapea foi ona upu leaga ia te ia o tagata fao mea ua faasatauroina ma ia.", "The thieves also, which were crucified with him, cast the same in his teeth."]]},
  {num:45,words:[["Ua fua mai i le itu aso e ono, ua pogisa uma ai le nuu, ua oo lava i le itu aso e iva.", "Now from the sixth hour there was darkness over all the land unto the ninth hour."]]},
  {num:46,words:[["Ua lata i le itu aso e iva,", "And about the ninth hour Jesus cried with a loud voice,"], ["ona alaga ai lea o Iesu ma le leo tele,", "saying,"], ["ua faapea atu,", "Eli,"], ["Eli,", "Eli,"], ["Eli, lama sapatani? o lona uiga lenei,", "lama sabachthani? that is to say,"], ["Lo'u Atua e,", "My God,"], ["lo'u Atua e,", "my God,"], ["se a le mea ua e tuulafoai mai ai a'u?", "why hast thou forsaken me?"]]},
  {num:47,words:[["Ua faalogo ai nisi o e na tutū mai,", "Some of them that stood there,"], ["ona latou faapea atu ai lea,", "when they heard that, said,"], ["Ua valaau atu lenei tagata ia Elia.", "This man calleth for Elias."]]},
  {num:48,words:[["Ona momo'e loa ai lea o so latou,", "And straightway one of them ran,"], ["ua tago i le omomi,", "and took a spunge,"], ["ua fufui ai i le vineta,", "and filled it with vinegar,"], ["ma tuu i luga i le pito laau,", "and put it on a reed,"], ["ua faainu ia te ia.", "and gave him to drink."]]},
  {num:49,words:[["A ua faapea ane i latou uma,", "The rest said,"], ["Tuu ai pea ia,", "Let be,"], ["se'i tatou iloa pe sau Elia na te faaolaina o ia.", "let us see whether Elias will come to save him."]]},
  {num:50,words:[["Ua toe alaga Iesu ma le leo tele,", "Jesus, when he had cried again with a loud voice,"], ["ona tuuina atu ai lea e ia o lona agaga.", "yielded up the ghost."]]},
  {num:51,words:[["Faauta foi,", "And,"], ["ua saeluaina le ie puipui o le malumalu,", "behold,"], ["ua amata ifo i luga, ua oo i lalo;", "the veil of the temple was rent in twain from the top to the bottom;"], ["ua luluina foi le eleele,", "and the earth did quake,"], ["ua mavaevae foi papa;", "and the rocks rent;"]]},
  {num:52,words:[["ua avanoa foi tuugamau,", "And the graves were opened;"], ["ua toe tutū mai foi tino o tagata paia e toatele na momoe,", "and many bodies of the saints which slept arose,"]]},
  {num:53,words:[["na mavae foi lona toe tu mai,", "And came out of the graves after his resurrection,"], ["ona latou o mai ai lea nai tuugamau, ma latou o atu i le aai paia,", "and went into the holy city,"], ["ua iloa i latou e tagata e toatele.", "and appeared unto many."]]},
  {num:54,words:[["O le ta'ita'i foi o le toaselau,", "Now when the centurion,"], ["ma e na leoleo ia Iesu faatasi ma ia,", "and they that were with him,"], ["na latou iloa le mafuie ma mea na faia,", "watching Jesus,"], ["ona latou matuā matatau ai lea,", "saw the earthquake, and those things that were done,"], ["ua faapea ane,", "they feared greatly,"], ["E moni,", "saying,"], ["o le Alo lava lenei o le Atua.", "Truly this was the Son of God."]]},
  {num:55,words:[["Sa i ai foi fafine e toatele na vaavaai mamao mai,", "And many women were there beholding afar off,"], ["o i latou ia na mulimuli mai ia Iesu mai Kalilaia,", "which followed Jesus from Galilee,"], ["ma auauna mai ia te ia;", "ministering unto him:"]]},
  {num:56,words:[["sa i ai ia te i latou o Maria le Makatala,", "Among which was Mary Magdalene,"], ["ma Maria le tinā o Iakopo ma Iose,", "and Mary the mother of James and Joses,"], ["o le tinā foi o atalii o Sepetaio.", "and the mother of Zebedee's children."]]},
  {num:57,words:[["Ua oo i le afiafi,", "When the even was come,"], ["ona sau ai lea o le tasi tagata mauoa,", "there came a rich man of Arimathaea,"], ["o le Arimataia, e igoa ia Iosefa,", "named Joseph,"], ["o ia foi o le soo o Iesu;", "who also himself was Jesus' disciple:"]]},
  {num:58,words:[["ua alu atu o ia ia Pilato,", "He went to Pilate,"], ["ua faanoi atu ai i le tino o Iesu. Ona fai atu ai lea o Pilato ia tuu ane le tino.", "and begged the body of Jesus. Then Pilate commanded the body to be delivered."]]},
  {num:59,words:[["Ua ave e Iosefa le tino,", "And when Joseph had taken the body,"], ["ona aui ai lea i le ie lino e mamā.", "he wrapped it in a clean linen cloth,"]]},
  {num:60,words:[["Ua tuu ai i lona tuugamau fou na foa i le papa;", "And laid it in his own new tomb,"], ["ua fuli atu e ia le maa tele i le gutu o le tuugamau,", "which he had hewn out in the rock: and he rolled a great stone to the door of the sepulchre,"], ["ona alu ai lea o ia.", "and departed."]]},
  {num:61,words:[["Sa i ai Maria le Makatala,", "And there was Mary Magdalene,"], ["ma le isi Maria,", "and the other Mary,"], ["sa la nonofo feagai ma le tuugamau.", "sitting over against the sepulchre."]]},
  {num:62,words:[["O le taeao,", "Now the next day,"], ["o le aso lea e tuaoi ma le aso o le sauniga,", "that followed the day of the preparation,"], ["ua faapotopoto atu ai ia Pilato le au faitaulaga sili ma le au faresaio,", "the chief priests and Pharisees came together unto Pilate,"]]},
  {num:63,words:[["ua faapea atu,", "Saying,"], ["Le alii e,", "Sir,"], ["ua matou manatua, na fai mai lena tagata pepelo,", "we remember that that deceiver said,"], ["ina o ola mai o ia,", "while he was yet alive,"], ["A mavae aso e tolu ou te toe tu mai ai.", "After three days I will rise again."]]},
  {num:64,words:[["O lenei,", "Command therefore that the sepulchre be made sure until the third day,"], ["ia e fetalai ane, ia faamauina le tuugamau seia oo i le aso tolu,", "lest his disciples come by night,"], ["ina ne'i o atu ona soo i le po,", "and steal him away,"], ["ma gaoi ia te ia,", "and say unto the people,"], ["ma latou fai atu i le nuu, Ua toe tu mai ia nai e ua oti;", "He is risen from the dead:"], ["ona sili ai lea o le pepelo e mulimuli i le na muamua.", "so the last error shall be worse than the first."]]},
  {num:65,words:[["Ona fai ane ai lea o Pilato ia te i latou,", "Pilate said unto them,"], ["Ua ia te outou leoleo,", "Ye have a watch:"], ["ina o ia,", "go your way,"], ["faitalia lava outou ona faamau ai.", "make it as sure as ye can."]]},
  {num:66,words:[["Ona latou o ai lea,", "So they went,"], ["ua faamauina le tuugamau,", "and made the sepulchre sure,"], ["ua faamaufaailoga i le maa,", "sealing the stone,"], ["ma tuu ai tagata e leoleo.", "and setting a watch."]]},
];
renderVerseSet(mat_ch_27_Verses, 'mat-ch27-verses');

var mat_ch_28_Verses = [
  {num:1,words:[["Ua mavae le sapati,", "In the end of the sabbath,"], ["ua tafa ata o le uluai aso o le vaisapati, ona o atu ai lea o Maria le Makatala,", "as it began to dawn toward the first day of the week,"], ["ma le isi Maria e asiasi i le tuugamau.", "came Mary Magdalene and the other Mary to see the sepulchre."]]},
  {num:2,words:[["Faauta foi,", "And,"], ["ua to le mafuie tele;", "behold,"], ["auā na alu ifo le agelu a le Alii mai le lagi,", "there was a great earthquake:"], ["ua alu atu,", "for the angel of the Lord descended from heaven,"], ["ma fuli ese le maa i le gutu o le tuugamau ,", "and came and rolled back the stone from the door,"], ["ma tietie i ona luga.", "and sat upon it."]]},
  {num:3,words:[["E pei o le uila lona tino mai,", "His countenance was like lightning,"], ["ma ona ofu ua sinasina pei o le kiona;", "and his raiment white as snow:"]]},
  {num:4,words:[["ua tetemu foi i le matatau ia te ia o e na leoleo,", "And for fear of him the keepers did shake,"], ["ua liua i latou e pei o tagata oti.", "and became as dead men."]]},
  {num:5,words:[["Ona fai atu ai lea o le agelu i fafine,", "And the angel answered and said unto the women,"], ["ua faapea atu,", "Fear not ye:"], ["Aua lua te matatau oulua;", "for I know that ye seek Jesus,"], ["auā ua ou iloa ua oulua sailia mai Iesu na faasatauroina.", "which was crucified."]]},
  {num:6,words:[["E le o iinei o ia;", "He is not here:"], ["auā ua toe tu mai o ia,", "for he is risen,"], ["pei ona fetalai atu ai o ia. O mai,", "as he said. Come,"], ["ina matamata i le mea na tuu ai le Alii.", "see the place where the Lord lay."]]},
  {num:7,words:[["Ina o atu ia ia vave,", "And go quickly,"], ["lua te ta'u atu i ona soo,", "and tell his disciples that he is risen from the dead;"], ["ua toe tu mai o ia nai e ua oti;", "and,"], ["faauta foi,", "behold,"], ["e muamua atu ia ia te outou i Kalilaia;", "he goeth before you into Galilee;"], ["tou te iloa ai o ia i lea mea;", "there shall ye see him:"], ["faauta,", "lo,"], ["ua ou fai atu ia te oulua.", "I have told you."]]},
  {num:8,words:[["Ona la vave o ai lea nai le tuugamau ma le fefe ma le fiafia tele;", "And they departed quickly from the sepulchre with fear and great joy;"], ["ua la taufetuli e ta'u atu ai i ona soo.", "and did run to bring his disciples word."]]},
  {num:9,words:[["Ua la o e ta'u atu ai i ona soo,", "And as they went to tell his disciples,"], ["faauta foi,", "behold,"], ["ua fetaiai Iesu ma i laua,", "Jesus met them,"], ["ua faapea atu,", "saying,"], ["Si o'u alofa. Ona la o mai ai lea ua fetagofi i ona vae,", "All hail. And they came and held him by the feet,"], ["ma ifo mai ia te ia.", "and worshipped him."]]},
  {num:10,words:[["Ona fetalai atu ai lea o Iesu ia te i laua, Aua lua te matatau;", "Then said Jesus unto them,"], ["ina o atu ia,", "Be not afraid:"], ["lua te ta'u atu i o'u uso,", "go tell my brethren that they go into Galilee,"], ["ina ia latou o atu i Kalilaia, latou te iloa mai ai a'u.", "and there shall they see me."]]},
  {num:11,words:[["Ua la o;", "Now when they were going,"], ["faauta,", "behold,"], ["ua o atu i le aai nisi o e na leoleo,", "some of the watch came into the city,"], ["ua ta'u atu i le au faitaulaga sili mea uma ua faia.", "and shewed unto the chief priests all the things that were done."]]},
  {num:12,words:[["Ona latou faapotopoto ai lea faatasi ma toeaina,", "And when they were assembled with the elders,"], ["ua latou filifili,", "and had taken counsel,"], ["ona avatu ai lea o tupe e tele i le 'au,", "they gave large money unto the soldiers,"]]},
  {num:13,words:[["ua faapea atu,", "Saying,"], ["Ia outou ta'uta'u atu,", "Say ye,"], ["Na o mai ona soo i le po ua gaoi ia te ia,", "His disciples came by night,"], ["a o matou momoe.", "and stole him away while we slept."]]},
  {num:14,words:[["Afai e faalogo i ai le alii,", "And if this come to the governor's ears,"], ["matou te faaoleole atu ia te ia,", "we will persuade him,"], ["ma faasao ia te outou.", "and secure you."]]},
  {num:15,words:[["Ona latou talia lea o tupe,", "So they took the money,"], ["ma latou faia e pei ona a'oa'oina ai o i latou;", "and did as they were taught:"], ["ua salalau foi lea tala i tagata Iutaia ua oo mai lava i nei ona po.", "and this saying is commonly reported among the Jews until this day."]]},
  {num:16,words:[["Ona o atu ai lea o le au soo e toasefulu ma le toatasi i Kalilaia,", "Then the eleven disciples went away into Galilee,"], ["i le mauga na poloai atu ai Iesu ia te i latou.", "into a mountain where Jesus had appointed them."]]},
  {num:17,words:[["Ua latou iloa o ia,", "And when they saw him,"], ["ona latou ifo mai ai lea ia te ia;", "they worshipped him:"], ["a ua masalosalo nisi.", "but some doubted."]]},
  {num:18,words:[["Ona maliu ane ai lea o Iesu,", "And Jesus came and spake unto them,"], ["ua fetalai atu ia te i latou, ua faapea atu,", "saying,"], ["Ua tuuina mai ia te au le pule uma lava i le lagi ma le lalolagi.", "All power is given unto me in heaven and in earth."]]},
  {num:19,words:[["O lenei,", "Go ye therefore,"], ["ia outou o atu e fai nuu uma lava ma soo,", "and teach all nations,"], ["ma papatiso atu ia te i latou i le suafa o le Tamā,", "baptizing them in the name of the Father,"], ["ma le Atalii,", "and of the Son,"], ["ma le Agaga Paia;", "and of the Holy Ghost:"]]},
  {num:20,words:[["ia outou a'oa'o atu ia te i latou ia tausi i mea uma ua ou fai atu ai ia te outou;", "Teaching them to observe all things whatsoever I have commanded you:"], ["faauta foi,", "and,"], ["ou te ia te outou i aso uma lava,", "lo, I am with you alway,"], ["e oo lava i le gataaga o le lalolagi.", "even unto the end of the world."], ["Amene.", "Amen."]]},
];
renderVerseSet(mat_ch_28_Verses, 'mat-ch28-verses');

})();